interactionEffects.wgsl:
fn interactionEffect(coord: vec2f, regionMin: vec2f, regionMax: vec2f, time: f32, params: vec4f) -> vec4f {
  let c = (regionMin + regionMax) * 0.5;
  let ext = max(regionMax.x - regionMin.x, regionMax.y - regionMin.y) * 0.5 + 14.0;
  let dv = coord - c;
  let r = length(dv) / max(ext, 1.0);
  if (r > 1.6) { return vec4f(0.0); }
  let a = atan2(dv.y, dv.x);
  // rotating rays of the meeting
  let rays = pow(abs(sin(a * 7.0 + time * 1.7)), 6.0) * exp(-r * 2.2);
  // breathing corona, with a cool fringe just outside it
  let ring = exp(-abs(r - (0.55 + 0.15 * sin(time * 2.4))) * 9.0);
  let fringe = exp(-abs(r - (0.66 + 0.15 * sin(time * 2.4))) * 14.0);
  // an expanding pulse, reborn every couple of seconds
  let pu = fract(time * 0.55);
  let pulse = exp(-abs(r - pu * 1.4) * 12.0) * (1.0 - pu);
  let core = exp(-r * 4.5);
  var col = vec3f(0.0);
  col += vec3f(3.2, 2.2, 0.9) * rays;
  col += vec3f(2.6, 1.6, 0.5) * ring;
  col += vec3f(1.4, 2.0, 3.2) * fringe * 0.7;
  col += vec3f(3.0, 2.4, 1.2) * pulse;
  col += vec3f(4.0, 3.2, 1.8) * core;
  let inten = clamp(rays + ring + pulse + core, 0.0, 1.0);
  return vec4f(col, inten * 0.9);
}

stepHooks.code:
try {
  const wd = sim.worldData
  if (!wd.__lh3) wd.__lh3 = { t: 38, icx: -9, icz: 32, hold: 0, ba: 0, fire: 0, mh: 0, bt: 0, fireLock: 0 }
  const H = wd.__lh3
  const CYC = 150
  const mx = wd.mouse_x, my = wd.mouse_y, md = wd.mouse_down
  const hasM = typeof mx === 'number'

  // ── camera math (matches the shader: ro=(0,3.4,0), f=1.75, y=(py*0.72-0.14)) ──
  const proj = (x, y, z, isDir) => {
    const vy = isDir ? y : y - 3.4
    if (z < 0.12) return null
    const px = x / z * 1.75, py = (vy / z * 1.75 + 0.14) / 0.72
    return { px, py, gx: (px + 1) * 256, gy: (1 - py) * 256 }
  }
  const ray = (gx, gy) => {
    const px = (gx / 256) - 1, py = 1 - (gy / 256)
    return [px, py * 0.72 - 0.14, 1.75]
  }

  // ── hover + drag: the lighthouse is a thing you can pick up ──
  const bS = proj(H.icx, 0.8, H.icz)
  const tS = proj(H.icx, 13.8, H.icz)
  const fTower = sim.fields.get('lh_tower')
  let hover = false
  if (hasM && fTower) {
    const TT = fTower.transform
    hover = TT.x > 0 && Math.abs(mx - TT.x) < (fTower.w || 64) / 2 && Math.abs(my - TT.y) < (fTower.h || 120) / 2
  }
  if (md && (hover || H.hold)) H.hold = 1
  if (!md) H.hold = 0
  if (H.hold && hasM) {
    // drag on the sea plane — and while held, TIME DOES NOT MOVE
    const d = ray(mx, my)
    if (d[1] < -0.02) {
      const tp = (0.5 - 3.4) / d[1]
      H.icx = Math.max(-38, Math.min(38, d[0] * tp))
      H.icz = Math.max(16, Math.min(70, d[2] * tp))
    }
  }
  // ── the SLIDER is the clock: click & drag the bottom bar to move the sun ──
  if (!md) H.sliderDrag = 0
  else if (hasM && (H.sliderDrag || (!H.mh && my > 470))) {
    H.sliderDrag = 1
    const target = (Math.max(8, Math.min(504, mx)) - 8) / 496 * CYC
    H.t += (target - H.t) * Math.min(1, dt * 12)
  }

  const ph = ((H.t % CYC) + CYC) % CYC / CYC
  const az = 1.35 + ph * 6.28318
  const el = Math.sin(ph * 6.28318) * 0.72
  const wind = Math.max(0, Math.min(1, 0.35 + 0.30 * Math.sin(ph * 6.28318 - 1.2)))
  const beam = Math.max(0, Math.min(1, (0.06 - el) * 9))
  const mel = -el * 0.85
  const maz = az + Math.PI
  H.bt += dt
  const leg = Math.floor(H.bt / 55)
  const dirB = (leg % 2 === 0) ? 1 : -1
  const u2 = ((H.bt % 55) + 55) % 55 / 55
  const bx = dirB > 0 ? (-70 + u2 * 140) : (70 - u2 * 140)

  // ── the beam sweeps; geometry alone decides the fire ──
  H.ba += dt * 0.55
  const sd = [Math.cos(az) * Math.cos(el), Math.sin(el), Math.sin(az) * Math.cos(el)]
  const sunS = sd[2] > 0.05 ? proj(sd[0], sd[1], sd[2], true) : null
  const lampS = proj(H.icx, 12.55, H.icz)
  let crossD = 1e9, crX = -80, crY = -120
  if (sunS && lampS) {
    for (const sgn of [1, -1]) {
      const T = proj(H.icx + Math.cos(H.ba) * 45 * sgn, 12.55, H.icz + Math.sin(H.ba) * 45 * sgn)
      if (!T) continue
      const vx = T.gx - lampS.gx, vy = T.gy - lampS.gy
      const tt = Math.max(0, Math.min(1, ((sunS.gx - lampS.gx) * vx + (sunS.gy - lampS.gy) * vy) / Math.max(vx * vx + vy * vy, 1e-6)))
      const cx2 = lampS.gx + vx * tt, cy2 = lampS.gy + vy * tt
      const dd3 = Math.hypot(sunS.gx - cx2, sunS.gy - cy2)
      if (dd3 < crossD) { crossD = dd3; crX = cx2; crY = cy2 }
    }
  }
  const sunVisible = !!sunS && el > -0.15 && sunS.gx > 10 && sunS.gx < 502 && sunS.gy > 0 && sunS.gy < 350
  // ── citizens: The Sun, The Beam, The Tower are FIELDS — their bodies are
  //    the hit truth (rule 'ir_lightgrow' watches the same bodies) ──
  const fSun = sim.fields.get('lh_sun'), fBeam = sim.fields.get('lh_beam')
  if (fSun) { const T2 = fSun.transform; if (sunVisible && sunS) { T2.x = sunS.gx; T2.y = sunS.gy } else { T2.x = -80; T2.y = -80 } T2.vx = 0; T2.vy = 0 }
  if (fBeam) { const T3 = fBeam.transform; if (beam > 0.2 && crossD < 1e8) { T3.x = crX; T3.y = crY } else { T3.x = -80; T3.y = -120 } T3.vx = 0; T3.vy = 0 }
  if (fTower && bS && tS) {
    const T4 = fTower.transform
    T4.x = (bS.gx + tS.gx) / 2; T4.y = (bS.gy + tS.gy) / 2; T4.vx = 0; T4.vy = 0
    fTower.w = 64; fTower.h = Math.abs(bS.gy - tS.gy) + 32
  }
  // water → fire TRIGGERS when the fields overlap: the light grows into the burn
  // ── overlap in WORLD space: the beam's angle meets the sun's azimuth —
  //    projection-proof. The fields then physically meet for the flare. ──
  const wrapA = x => { let v = x % 6.28318; if (v > 3.14159) v -= 6.28318; if (v < -3.14159) v += 6.28318; return v }
  const dA = Math.min(Math.abs(wrapA(az - H.ba)), Math.abs(wrapA(az - H.ba - 3.14159)))
  const overlapped = beam > 0.2 && el > -0.12 && el < 0.30 && dA < 0.12
  H.dbgA = Math.round(dA * 57.3)
  // during the meeting, The Beam stands where The Sun stands — the engine's
  // interaction rule and the flare fire on real field overlap
  if (overlapped && fBeam && sunS) { fBeam.transform.x = sunS.gx; fBeam.transform.y = sunS.gy }
  // TEST SWITCH: a fresh click (not on the tower) toggles water <-> fire
  // directly, so the burn can be verified independent of hit detection
  if (md && !H.mh && !hover && !H.hold && my <= 470) H.fireLock = H.fireLock ? 0 : 1
  H.fire = (overlapped || H.fireLock) ? Math.min(1, H.fire + dt * 1.5) : Math.max(0, H.fire - dt * 0.6)

  // (the blaze-door to TIDERUNNER was removed with that world)
  H.mh = md ? 1 : 0

  // outline rect in the shader's p-space
  let ocx = 0, ocy = 0, ohh = 0
  if (bS && tS) { ocx = (bS.px + tS.px) / 2; ocy = (bS.py + tS.py) / 2; ohh = Math.abs(tS.py - bS.py) / 2 + 0.045 }

  wd.gpuUniforms = [az, el, ph, wind, beam, mel, maz, bx, dirB, H.ba % 6.28318, H.fire, H.icx, H.icz, (hover || H.hold) ? 1 : 0, ocx, ocy, ohh]
  wd.hud = [{ id: 'lh_t', type: 'text', x: '14px', y: '12px', color: '#c9b370', fontSize: '13px',
    text: 'LIGHTHOUSE — ' + (H.fire > 0.5 ? 'THE WATER BURNS' : H.hold ? 'carrying the lighthouse' : (beam > 0.5 ? 'the lamp is lit' : (el > 0.3 ? 'high day' : 'low light'))) + (beam > 0.2 ? ' · beam∠sun ' + H.dbgA + '°' + (overlapped ? ' · OVERLAP' : '') : '') + (H.fireLock ? ' · TEST FIRE' : '') }]
} catch (e) { /* keep the sim alive */ }

tv_set.wgsl:
fn ch_dream(q: vec2f, t: f32) -> vec3f {
  // CH 5 — the set dreams the worlds it has seen
  let drift = fbm3(q * 1.6 + vec2f(t * 0.05, -t * 0.03));
  var col = mix(vec3f(0.02, 0.03, 0.06), vec3f(0.10, 0.07, 0.16), drift);
  let s = vnoise(q * 3.0 + vec2f(sin(t * 0.2) * 2.0, t * 0.11));
  col += vec3f(0.25, 0.2, 0.5) * pow(s, 3.0);
  let mem = floor(t / 8.0) % 4.0;
  let ph = smoothstep(0.0, 0.15, fract(t / 8.0)) * smoothstep(1.0, 0.85, fract(t / 8.0));
  if (mem < 0.5) {          // a sun that was carried across a sky
    col += vec3f(2.0, 1.3, 0.4) * exp(-length(q - vec2f(sin(t * 0.13) * 0.4, -0.2)) * 5.0) * ph;
  } else if (mem < 1.5) {   // the hex lattice
    let hx = abs(fract(q.x * 4.0 + q.y * 2.0) - 0.5) * abs(fract(q.y * 4.6) - 0.5);
    col += vec3f(0.2, 0.9, 0.8) * smoothstep(0.22, 0.25, hx) * 0.35 * ph;
  } else if (mem < 2.5) {   // city windows in the rain
    let w = step(0.6, hash21(floor(q * vec2f(14.0, 10.0)) + floor(t * 0.5)));
    col += vec3f(1.4, 1.0, 0.5) * w * 0.3 * ph;
  } else {                  // a beam crossing a sun, water catching fire
    let ang = atan2(q.y + 0.3, q.x);
    col += vec3f(1.8, 1.6, 1.1) * exp(-abs(ang - sin(t * 0.3)) * 8.0) * exp(-length(q) * 1.2) * ph * 0.7;
    col += vec3f(2.2, 0.8, 0.2) * exp(-length(q - vec2f(cos(t * 0.3), -0.3 + sin(t * 0.3) * 0.2)) * 6.0) * ph;
  }
  return col;
}

// ── the channel words: each is a callable shader — signature (q: -1..1 screen, t) ──

fn ch_static(q: vec2f, t: f32) -> vec3f {
  let n = hash21(floor(q * vec2f(160.0, 120.0)) + floor(t * 60.0) * 7.3);
  var v = 0.25 + 0.75 * n;
  // rolling tear bar
  let bar = fract(q.y * 0.5 - t * 0.35);
  if (bar < 0.06) { v *= 0.45; }
  return vec3f(v);
}

fn ch_plasma(q: vec2f, t: f32) -> vec3f {
  var v = sin(q.x * 6.0 + t * 1.2);
  v += sin((q.y * 5.0 + t) * 0.8);
  v += sin((q.x + q.y) * 4.0 + t * 0.7);
  v += sin(length(q * 5.0) - t * 1.5);
  v *= 0.25;
  return vec3f(0.5 + 0.5 * sin(6.2831 * v), 0.5 + 0.5 * sin(6.2831 * v + 2.1), 0.5 + 0.5 * sin(6.2831 * v + 4.2));
}

fn ch_pong(q: vec2f, t: f32) -> vec3f {
  var col = vec3f(0.02, 0.03, 0.02);
  // net
  if (abs(q.x) < 0.012 && fract(q.y * 5.0) < 0.55) { col = vec3f(0.35); }
  // paddles (hook-simulated)
  if (abs(q.x + 0.85) < 0.03 && abs(q.y - uni(5)) < 0.16) { col = vec3f(1.4); }
  if (abs(q.x - 0.85) < 0.03 && abs(q.y - uni(6)) < 0.16) { col = vec3f(1.4); }
  // ball
  if (abs(q.x - uni(3)) < 0.035 && abs(q.y - uni(4)) < 0.045) { col = vec3f(1.8); }
  // score pips
  for (var i = 0; i < 5; i++) {
    if (f32(i) < uni(7) && length(q - vec2f(-0.5 + f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
    if (f32(i) < uni(8) && length(q - vec2f(0.5 - f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
  }
  return col;
}

fn ch_boids(q: vec2f, t: f32) -> vec3f {
  var col = mix(vec3f(0.03, 0.05, 0.10), vec3f(0.10, 0.14, 0.22), q.y * -0.5 + 0.5);
  // moon
  col += vec3f(0.5, 0.5, 0.42) * exp(-length(q - vec2f(0.55, -0.55)) * 9.0);
  // the flock (hook-simulated)
  for (var i = 0; i < 16; i++) {
    let b = vec2f(uni(10 + i * 2), uni(11 + i * 2));
    let d = length(q - b);
    if (d < 0.028) { col = vec3f(0.02); }                    // bird body
    col += vec3f(0.05, 0.05, 0.04) * exp(-d * 40.0);         // faint presence
  }
  return col;
}


fn sc_box(p: vec2f, c: vec2f, b: vec2f, r: f32) -> f32 {
  let d = abs(p - c) - b;
  return length(max(d, vec2f(0.0))) + min(max(d.x, d.y), 0.0) - r;
}

// CH 5 — SITCOM. The hook runs four little lives through behavior zones
// (couch, kitchen, window, door, center-stage); the tube just draws them.
fn ch_sitcom(q: vec2f, t: f32) -> vec3f {
  let FLOOR = 0.42;
  // the set: warm wall, wood floor
  var col = mix(vec3f(0.20, 0.14, 0.11), vec3f(0.13, 0.09, 0.08), q.y * 0.5 + 0.5);
  col *= 0.94 + 0.06 * sin(q.x * 40.0);
  if (q.y > FLOOR) {
    col = mix(vec3f(0.17, 0.11, 0.06), vec3f(0.10, 0.06, 0.04), (q.y - FLOOR) * 1.6);
    col *= 0.9 + 0.1 * sin(q.x * 24.0 + q.y * 60.0);
  }
  // window on the night
  let wd2 = sc_box(q, vec2f(-0.72, -0.28), vec2f(0.13, 0.17), 0.02);
  if (wd2 < 0.0) {
    col = vec3f(0.02, 0.03, 0.07);
    if (hash21(floor(q * 30.0)) > 0.992) { col += vec3f(0.6); }
    col += vec3f(0.35, 0.35, 0.30) * exp(-length(q - vec2f(-0.68, -0.38)) * 14.0);
    if (abs(q.x + 0.72) < 0.012 || abs(q.y + 0.28) < 0.012) { col = vec3f(0.24, 0.17, 0.12); }
  } else if (wd2 < 0.02) { col = vec3f(0.26, 0.19, 0.13); }
  // the door — uni(2) swings it open on a dark hallway
  let dOpen = uni(2);
  let dframe = sc_box(q, vec2f(0.86, 0.12), vec2f(0.11, 0.30), 0.01);
  if (dframe < 0.0) {
    col = vec3f(0.03, 0.025, 0.032);
    if (q.x > 0.75 + dOpen * 0.17) {
      col = vec3f(0.23, 0.15, 0.09) * (0.85 + 0.15 * sin(q.y * 30.0));
      if (length(q - vec2f(0.78 + dOpen * 0.17, 0.14)) < 0.012) { col = vec3f(0.55, 0.45, 0.25); }
    }
  } else if (dframe < 0.018) { col = vec3f(0.28, 0.20, 0.13); }
  // couch
  let cc = vec2f(-0.30, 0.32);
  if (sc_box(q, cc + vec2f(0.0, -0.10), vec2f(0.27, 0.09), 0.04) < 0.0) { col = vec3f(0.36, 0.11, 0.11); }
  if (sc_box(q, cc + vec2f(0.0, 0.05), vec2f(0.27, 0.06), 0.04) < 0.0) {
    col = vec3f(0.45, 0.14, 0.13);
    if (abs(q.x - cc.x) < 0.004) { col *= 0.8; }
  }
  if (sc_box(q, cc + vec2f(-0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0 ||
      sc_box(q, cc + vec2f(0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0) { col = vec3f(0.42, 0.13, 0.12); }
  // kitchen counter + mug
  if (sc_box(q, vec2f(0.52, 0.47), vec2f(0.14, 0.08), 0.01) < 0.0) { col = vec3f(0.20, 0.16, 0.12); }
  if (sc_box(q, vec2f(0.52, 0.385), vec2f(0.155, 0.014), 0.005) < 0.0) { col = vec3f(0.55, 0.50, 0.42); }
  if (sc_box(q, vec2f(0.47, 0.355), vec2f(0.012, 0.014), 0.004) < 0.0) { col = vec3f(0.75, 0.68, 0.60); }
  // lamp
  if (abs(q.x - 0.13) < 0.006 && q.y > -0.02 && q.y < FLOOR) { col = vec3f(0.1); }
  if (q.y > -0.11 && q.y < -0.02 && abs(q.x - 0.13) < 0.035 + (q.y + 0.11) * 0.45) { col = vec3f(0.85, 0.65, 0.35); }
  col += vec3f(0.5, 0.35, 0.15) * exp(-length((q - vec2f(0.13, 0.05)) * vec2f(1.0, 0.8)) * 3.2) * 0.35;

  // ── the cast (uni 42..61: x, pose, face, talk, row per character) ──
  for (var i = 0; i < 4; i++) {
    let ux = uni(42 + i * 5);
    let pose = uni(43 + i * 5);
    if (pose > 2.5) { continue; }
    let face = uni(44 + i * 5);
    let talk = uni(45 + i * 5);
    let row = uni(46 + i * 5);
    let fi = f32(i);
    var shirt = vec3f(0.75, 0.55, 0.15);
    var hair = vec3f(0.12, 0.09, 0.05);
    if (i == 1) { shirt = vec3f(0.15, 0.50, 0.50); hair = vec3f(0.35, 0.20, 0.08); }
    if (i == 2) { shirt = vec3f(0.55, 0.22, 0.10); hair = vec3f(0.08, 0.08, 0.08); }
    if (i == 3) { shirt = vec3f(0.35, 0.18, 0.42); hair = vec3f(0.50, 0.45, 0.40); }
    let hgt = 0.30 + fi * 0.014;
    let sitting = pose > 1.5;
    let walking = abs(pose - 1.0) < 0.25;
    let bob = select(0.0, abs(sin(t * 7.0 + fi * 2.0)) * 0.012, walking);
    let feetY = select(FLOOR + row, 0.40, sitting) - bob;
    let hipY = feetY - select(hgt * 0.42, 0.055, sitting);
    let torsoC = vec2f(ux, hipY - hgt * 0.19);
    let headC = vec2f(ux + face * 0.008, hipY - hgt * 0.36);
    if (sitting) {
      if (sc_box(q, vec2f(ux + face * 0.05, hipY + 0.05), vec2f(0.05, 0.015), 0.01) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    } else {
      let sw = select(0.0, sin(t * 9.0 + fi * 2.0) * 0.016, walking);
      if (sc_box(q, vec2f(ux - 0.014 + sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0 ||
          sc_box(q, vec2f(ux + 0.014 - sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    }
    if (sc_box(q, torsoC, vec2f(0.036, hgt * 0.20), 0.02) < 0.0) { col = shirt; }
    let hd = length(q - headC);
    if (hd < 0.036) { col = vec3f(0.85, 0.62, 0.45); }
    if (hd < 0.038 && q.y < headC.y - 0.010) { col = hair; }
    if (fract(t * 0.31 + fi * 0.37) > 0.06) {
      if (length(q - (headC + vec2f(face * 0.012 - 0.008, 0.004))) < 0.0035 ||
          length(q - (headC + vec2f(face * 0.012 + 0.008, 0.004))) < 0.0035) { col = vec3f(0.05, 0.05, 0.05); }
    }
    if (talk > 0.5) {
      let bc = headC + vec2f(face * 0.11, -0.105);
      let bd = sc_box(q, bc, vec2f(0.065, 0.030), 0.02);
      if (bd < 0.0) {
        col = vec3f(0.92, 0.92, 0.90);
        for (var k = 0; k < 3; k++) {
          if (fract(t * 0.9 + fi * 0.5) > f32(k) * 0.3 &&
              length(q - (bc + vec2f(-0.03 + f32(k) * 0.03, 0.0))) < 0.008) { col = vec3f(0.25, 0.25, 0.25); }
        }
      } else if (bd < 0.006 && bd >= 0.0) { col = vec3f(0.6, 0.6, 0.58); }
    }
  }
  // the laugh: warm audience light washing up from below
  col += vec3f(0.45, 0.32, 0.12) * uni(62) * (0.6 + 0.4 * sin(t * 18.0)) * (0.3 + 0.7 * smoothstep(0.0, 0.8, q.y));
  return col;
}

fn visual_tv_set(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = (uv + vec2f(1.0)) * 256.0;
  let t = time;

  // the room: dark, lit by the set
  var col = vec3f(0.012, 0.011, 0.015) * (1.0 + 0.35 * fbm3(p * 0.01));

  let C = vec2f(256.0, 238.0);
  let half = vec2f(172.0, 122.0);
  let dBez = sdRoundedBox(p - C, half + vec2f(22.0, 26.0), 14.0);
  let dScr = sdRoundedBox(p - C, half, 10.0);

  // glow spill on the room
  let flick = 0.94 + 0.06 * sin(t * 47.0) * sin(t * 31.0);
  col += vec3f(0.10, 0.12, 0.16) * flick * exp(-max(dBez, 0.0) * 0.02);

  // bezel: warm plastic with a highlight
  if (dBez < 0.0 && dScr >= 0.0) {
    col = mix(vec3f(0.10, 0.085, 0.07), vec3f(0.16, 0.14, 0.12), fbm3(p * 0.15) * 0.5);
    col *= 0.8 + 0.4 * smoothstep(20.0, -30.0, p.y - (C.y - half.y));
    // channel knob
    let kd = length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)));
    if (kd < 7.0) {
      col = vec3f(0.05);
      let ka = 6.2831 * uni(0) / 5.0 - 1.57;
      if (length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)) - vec2f(cos(ka), sin(ka)) * 4.0) < 1.6) { col = vec3f(0.7); }
    }
  }

  // the screen: barrel-distorted, phosphor, scanlines — a CRT calling a channel
  if (dScr < 0.0) {
    var q = (p - C) / half;                                   // -1..1
    q *= 1.0 + 0.10 * dot(q, q);                              // barrel
    if (abs(q.x) > 1.0 || abs(q.y) > 1.0) {
      col = vec3f(0.0);                                       // over-scan black
    } else {
      // ── THE CALL: channel word by number ──
      let ch = i32(uni(0) + 0.5);
      var scr: vec3f;
      if (ch == 0) { scr = ch_static(q, t); }
      else if (ch == 1) { scr = ch_plasma(q, t); }
      else if (ch == 2) { scr = ch_pong(q, t); }
      else if (ch == 3) { scr = ch_boids(q, t); }
      else { scr = ch_sitcom(q, t); }

      // switch burst: static bleeds over the program
      if (uni(1) > 0.01) { scr = mix(scr, ch_static(q, t * 3.0), min(uni(1) * 1.4, 1.0)); }

      // CRT dress: phosphor triads, scanlines, corner falloff, flicker
      let px = i32(p.x * 3.0) % 3;
      var mask = vec3f(0.85);
      if (px == 0) { mask = vec3f(1.25, 0.72, 0.72); }
      else if (px == 1) { mask = vec3f(0.72, 1.25, 0.72); }
      else { mask = vec3f(0.72, 0.72, 1.25); }
      scr *= mask;
      scr *= 0.82 + 0.18 * sin(p.y * 3.14159);                // scanlines
      scr *= flick;
      scr *= 1.0 - 0.45 * pow(length(q), 4.0);                // corner falloff
      col = scr * 1.35;                                       // HDR — bloom catches the tube
    }
  }

  // set shadow on the floor
  col *= 1.0 - 0.3 * smoothstep(30.0, 0.0, abs(p.y - (C.y + half.y + 40.0))) * smoothstep(half.x + 40.0, half.x - 20.0, abs(p.x - C.x));

  return vec4f(col, 1.0);
}

fb_world.wgsl:
fn fb_bg(p: vec2f, t: f32) -> vec3f {
  // the unlensed sky: nebula, dust, two starfield depths
  var c = vec3f(0.010, 0.008, 0.022);

  // nebula — indigo body, rose folds, gold filaments
  let q = p * 1.6 + vec2f(0.3, -0.2);
  let n1 = fbm(q + vec2f(t * 0.004, 0.0), 5);
  let n2 = fbm(q * 2.3 + vec2f(7.0, 3.0) - vec2f(0.0, t * 0.003), 4);
  c += vec3f(0.10, 0.05, 0.28) * smoothstep(0.35, 0.85, n1) * 1.1;
  c += vec3f(0.30, 0.08, 0.22) * smoothstep(0.55, 0.9, n1 * 0.6 + n2 * 0.6) * 0.9;
  c += vec3f(0.55, 0.38, 0.12) * pow(smoothstep(0.62, 0.95, n2), 2.0) * 0.8;
  // dark dust lane
  c *= 1.0 - 0.55 * smoothstep(0.55, 0.8, fbm(q * 1.3 + vec2f(21.0, 13.0), 4));

  // stars — two depths, hue-varied, twinkling
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (14.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let h2 = hash21(cell + 91.0);
    let fp = fract(sp) - 0.5 + (vec2f(h, h2) - 0.5) * 0.6;
    let star = step(0.982 - fl * 0.006, h) * smoothstep(0.24, 0.02, length(fp));
    let tw = 0.55 + 0.45 * sin(t * (0.6 + h * 1.6) + h * 40.0);
    let hue = mix(vec3f(0.75, 0.82, 1.05), vec3f(1.05, 0.85, 0.6), h2);
    c += hue * star * tw * (1.4 - fl * 0.5);
  }
  return c;
}

fn fb_mass(i: i32) -> vec3f { return vec3f(uni(9 + i * 3), uni(10 + i * 3), uni(11 + i * 3)); }

// total lens deflection: sample the sky at beta = theta - sum(m_i * d_i / r_i^2)
fn fb_beta(uv: vec2f, mScale: f32, t: f32) -> vec2f {
  var beta = uv;
  let nA = i32(uni(0));
  for (var i = 0; i < 9; i++) {
    if (i >= nA) { break; }
    let m = fb_mass(i);
    let d = uv - m.xy;
    let r2 = max(dot(d, d), 0.0004);
    beta -= d * (m.z * mScale) / r2;
  }
  // the cursor lens
  let md = uv - vec2f(uni(1), uni(2));
  let mr2 = max(dot(md, md), 0.0004);
  beta -= md * (uni(3) * mScale) / mr2;
  // gravitational ripple from the last anchor drop
  let rt = uni(6);
  if (rt < 4.0) {
    let ro = uv - vec2f(uni(7), uni(8));
    let rr = length(ro);
    let wave = sin((rr - rt * 0.9) * 26.0) * exp(-pow((rr - rt * 0.9) * 3.2, 2.0)) * exp(-rt * 1.1);
    beta += (ro / max(rr, 0.01)) * wave * 0.02;
  }
  return beta;
}

fn visual_fb_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let chroma = uni(5) * 0.22;

  // lensed sky, with dispersion: each color feels gravity slightly differently
  let bR = fb_beta(uv, 1.0 - chroma, t);
  let bG = fb_beta(uv, 1.0, t);
  let bB = fb_beta(uv, 1.0 + chroma, t);
  var col = vec3f(fb_bg(bR, t).r, fb_bg(bG, t).g, fb_bg(bB, t).b);

  // spacetime grid, drawn in SOURCE coordinates — lines funnel into the wells
  let g01 = uni(4);
  if (g01 > 0.01) {
    let gc = bG * 7.0;
    let gx = smoothstep(0.06, 0.0, abs(fract(gc.x) - 0.5) - 0.44);
    let gy = smoothstep(0.06, 0.0, abs(fract(gc.y) - 0.5) - 0.44);
    col += vec3f(0.10, 0.22, 0.28) * max(gx, gy) * g01 * 0.8;
  }

  // the masses themselves: dark cores wearing hot photon rings
  let nA = i32(uni(0));
  for (var i = 0; i < 10; i++) {
    var m: vec3f;
    var held = false;
    if (i < nA) { m = fb_mass(i); }
    else if (i == nA) { m = vec3f(uni(1), uni(2), uni(3)); held = true; }
    else { break; }
    if (m.z < 0.0005) { continue; }
    let r = length(uv - m.xy);
    let rs = sqrt(m.z) * 0.55;                 // event-horizon scale from the Einstein radius
    col = mix(col, vec3f(0.0), smoothstep(rs, rs * 0.55, r));
    var ringCol = vec3f(3.2, 2.1, 1.0);
    if (held) { ringCol = vec3f(1.2, 2.6, 3.2); }
    let flick = 0.85 + 0.15 * sin(t * 5.0 + f32(i) * 9.0 + r * 40.0);
    col += ringCol * exp(-pow((r - rs * 1.18) * (34.0 / max(rs, 0.02)) * rs, 2.0) * 3.0) * flick;
    // faint accretion shimmer just outside the ring
    let sh = exp(-pow((r - rs * 1.7) * 8.0 / max(rs, 0.05), 2.0));
    col += vec3f(0.5, 0.3, 0.15) * sh * (0.4 + 0.3 * sin(t * 1.3 + atan2(uv.y - m.y, uv.x - m.x + 1e-5) * 3.0 - t));
  }

  // NaN scrub — nothing poisoned may reach the bloom
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01, 0.01, 0.02); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

cf_world.wgsl:
fn cf_stars(p: vec2f, t: f32) -> vec3f {
  var c = vec3f(0.008, 0.007, 0.016);
  c += vec3f(0.05, 0.025, 0.09) * smoothstep(0.4, 0.9, fbm(p * 1.5 + vec2f(t * 0.004, 0.0), 4));
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (16.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let fp = fract(sp) - 0.5;
    let tw = 0.5 + 0.5 * sin(t * (0.5 + h * 1.4) + h * 40.0);
    c += vec3f(0.8, 0.75, 0.95) * step(0.985, h) * smoothstep(0.24, 0.03, length(fp)) * tw * (1.1 - fl * 0.4);
  }
  return c;
}

fn visual_cf_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mp = vec2f(uni(4), uni(5));     // cursor (uv coords)
  let cam = vec2f(uni(0), uni(1));
  let zm = uni(2);

  // ── the room: stars seen through curved space (your cursor is a lens) ──
  var p = uv;
  let md = uv - mp;
  let mr2 = max(dot(md, md), 0.002);
  p -= md * (0.010 / mr2) * smoothstep(0.9, 0.2, length(md));
  var col = cf_stars(p, t);

  // warm hearth-light from below — this is a cafe, not a void
  col += vec3f(0.10, 0.055, 0.02) * pow(max(0.0, uv.y + 0.2), 2.0) * (0.8 + 0.2 * sin(t * 0.7));

  // ── the bubble universe: live positions, pressure-ranked, explorable ──
  for (var i = 0; i < i32(uni(3) + 0.5); i++) {
    let sv = uni(8 + i * 3);
    let st = i32(floor(sv));
    let hue = fract(sv);
    let ctr = vec2f((uni(6 + i * 3) - cam.x) * zm / 256.0, (uni(7 + i * 3) - cam.y) * zm / 256.0);
    let d = length(uv - ctr);
    let R = 0.098 * zm;
    let hov = smoothstep(R * 1.9, R * 1.1, length(mp - ctr));
    let rr = R * (1.0 + hov * 0.12);
    if (d < rr) {
      let q = (uv - ctr) / rr;                     // -1..1 inside the disc
      var g = vec3f(0.0);
      if (st == 0) {
        // FABRIC — a lens wandering through stars
        var pp = q * 2.0;
        let lc = vec2f(sin(t * 0.6) * 0.5, cos(t * 0.47) * 0.4);
        let ld = pp - lc;
        pp -= ld * (0.16 / max(dot(ld, ld), 0.02));
        g = cf_stars(pp * 1.6, t) * 2.2;
        g += vec3f(0.5, 0.9, 1.1) * exp(-dot(ld, ld) * 14.0) * 0.4;
      } else if (st == 1) {
        // ORRERY — three worlds around a coal
        g = vec3f(0.02, 0.015, 0.03);
        g += vec3f(3.0, 1.7, 0.5) * exp(-dot(q, q) * 30.0);
        for (var k = 1; k <= 3; k++) {
          let fk = f32(k);
          let a = t * (0.9 - fk * 0.18) + fk * 2.1;
          let pp = q - vec2f(cos(a), sin(a)) * (0.22 + fk * 0.17);
          var pc = vec3f(0.45, 0.5, 0.65);
          if (k == 2) { pc = vec3f(0.2, 0.45, 0.8); }
          if (k == 3) { pc = vec3f(0.8, 0.5, 0.25); }
          g += pc * exp(-dot(pp, pp) * 260.0) * 1.6;
        }
      } else if (st == 2) {
        // GARNET — the crystal
        let qa = rotate(q, t * 0.4);
        let cd = abs(qa.x) * 0.866 + abs(qa.y) * 0.5;
        let inside = smoothstep(0.62, 0.58, max(cd, abs(qa.y)));
        let facet = 0.6 + 0.4 * sin(qa.x * 9.0 + qa.y * 7.0 + t * 0.8);
        g = mix(vec3f(0.02, 0.01, 0.02), vec3f(0.75, 0.18, 0.25) * facet, inside);
        g += vec3f(1.6, 0.9, 0.7) * pow(max(0.0, facet - 0.75) * 4.0, 2.0) * inside;
      } else if (st == 3) {
        // ONE DAY — a sky that keeps its whole day
        let ph = fract(t * 0.05);
        let el = sin(ph * 6.28318) * 0.8;
        let day = smoothstep(-0.2, 0.4, el);
        g = mix(vec3f(0.02, 0.02, 0.06), vec3f(0.25, 0.5, 0.8), day * (0.5 - q.y * 0.5));
        g = mix(g, vec3f(0.9, 0.4, 0.15), smoothstep(0.3, 0.0, abs(el)) * max(0.0, -q.y + 0.2) * 0.9);
        let sun = vec2f(cos(ph * 6.28318 - 1.57) * 0.6, -el * 0.55 + 0.1);
        g += vec3f(3.0, 2.0, 0.9) * exp(-dot(q - sun, q - sun) * 60.0) * max(day, 0.15);
        if (q.y > 0.25) { g = mix(g, g * vec3f(0.5, 0.6, 0.8), 0.6); }   // the sea below
      } else if (st == 4) {
        // SAIL — one boat, one sea
        g = mix(vec3f(0.35, 0.5, 0.65), vec3f(0.05, 0.14, 0.2), smoothstep(-0.1, 0.5, q.y));
        let w = sin(q.x * 9.0 + t * 1.4) * 0.05;
        g = mix(g, vec3f(0.03, 0.10, 0.14), smoothstep(w + 0.02, w - 0.02, -q.y + 0.1) * 0.0 + smoothstep(w - 0.02, w + 0.06, q.y - 0.05));
        let sail = max(max(-(q.x + 0.05) * 3.0, q.y + 0.15), (q.x * 0.9 + q.y * 0.8) - 0.28);
        g = mix(g, vec3f(1.0, 0.96, 0.88), smoothstep(0.02, -0.02, sail));
      } else if (st == 5) {
        // SOLSTICE — a sun you carry over a valley
        g = vec3f(0.03, 0.04, 0.09);
        let sp = vec2f(sin(t * 0.5) * 0.45, -0.3 + cos(t * 0.5) * 0.12);
        g += vec3f(3.2, 2.2, 0.9) * exp(-dot(q - sp, q - sp) * 40.0);
        let hill = q.y - (0.25 + 0.15 * sin(q.x * 3.0 + 1.0));
        let lit = max(0.0, 1.0 - length(q - sp) * 1.4);
        g = mix(g, mix(vec3f(0.03, 0.05, 0.02), vec3f(0.15, 0.3, 0.08), lit), smoothstep(-0.02, 0.02, hill));
      } else if (st == 6) {
        // TIDERUNNER — wind over water
        let band = sin(q.y * 14.0 - t * 1.1 + sin(q.x * 4.0) * 0.7);
        g = mix(vec3f(0.05, 0.13, 0.17), vec3f(0.12, 0.25, 0.3), 0.5 + 0.5 * band);
        g += vec3f(0.8, 0.85, 0.85) * pow(max(0.0, band - 0.8) * 5.0, 2.0) * 0.4;
        let bt = q - vec2f(sin(t * 0.4) * 0.4, 0.0);
        g += vec3f(0.9, 0.85, 0.75) * exp(-dot(bt, bt) * 300.0) * 1.2;
      } else if (st == 7) {
        // SIGNAL — a television waiting for a word
        let sn = hash21(floor(q * 24.0) + floor(t * 9.0));
        g = vec3f(sn * 0.5);
        g += vec3f(0.3, 1.0, 0.45) * exp(-dot(q, q) * 8.0) * (0.28 + 0.14 * sin(t * 2.0));
        g *= 0.82 + 0.18 * sin(q.y * 60.0 - t * 8.0);
      } else {
        // a young world — a banded seed-planet in its own hue
        let cA = 0.5 + 0.5 * cos(6.2831 * (hue + vec3f(0.0, 0.33, 0.67)));
        g = cA * (0.22 + 0.5 * fbm3(q * 3.0 + vec2f(t * 0.08, f32(i) * 3.7)));
        g += cA * 0.4 * smoothstep(0.6, 1.0, 1.0 - abs(q.y * 2.2 + 0.3 * sin(q.x * 3.0 + t * 0.4)));
        let mn = q - vec2f(cos(t * 0.5 + f32(i) * 1.9), sin(t * 0.5 + f32(i) * 1.9) * 0.6) * 0.78;
        g += vec3f(0.85) * exp(-dot(mn, mn) * 260.0);
        g *= 0.85 + 0.3 * (1.0 - length(q));
      }
      // glass edge + hover bloom
      let edge = smoothstep(1.0, 0.86, length(q));
      col = mix(col, g, edge);
      col += vec3f(1.2, 0.85, 0.4) * exp(-pow((length(q) - 0.97) * 9.0, 2.0)) * (0.25 + hov * 1.3);
    } else {
      // halo when hovered
      col += vec3f(1.0, 0.7, 0.3) * exp(-pow((d - rr) * 22.0, 2.0)) * hov * 0.8;
    }
  }

  // the cursor itself — a soft ember
  col += vec3f(1.4, 0.9, 0.4) * exp(-dot(uv - mp, uv - mp) * 900.0) * 0.8;

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

helios.wgsl:
const HL_HOR: f32 = 336.0;

fn hl_moonness(ph: f32) -> f32 { return 0.5 - 0.5 * cos(6.2831853 * ph); }

// sky + orb, callable so the lake can mirror it
fn hl_sky(p: vec2f, sun: vec2f, m: f32, t: f32, a: f32) -> vec3f {
  let up = clamp(1.0 - p.y / HL_HOR, 0.0, 1.0);
  // day palette → night palette
  let dayZen = vec3f(0.16, 0.34, 0.62);
  let dayHor = vec3f(0.95, 0.62, 0.32);
  let nightZen = vec3f(0.015, 0.020, 0.055);
  let nightHor = vec3f(0.05, 0.06, 0.13);
  var col = mix(mix(dayHor, dayZen, pow(up, 0.6)), mix(nightHor, nightZen, pow(up, 0.6)), m);

  // light breathes from wherever the orb is (screen-round despite the
  // vertical compression that fits the painting to wide viewports)
  let rel = vec2f(p.x - sun.x, (p.y - sun.y) / a);
  let d = length(rel);
  let warm = mix(vec3f(1.1, 0.7, 0.35), vec3f(0.55, 0.62, 0.80), m);
  col += warm * exp(-d * 0.012) * mix(0.5, 0.28, m);

  // the orb: gold sun ↔ silver moon with craters and a crescent bite
  let r = 26.0;
  if (d < r) {
    var oc = mix(vec3f(3.2, 2.4, 1.1), vec3f(1.6, 1.7, 1.9), m);
    // craters surface only as it becomes moon
    let cr = vnoise(rel * 0.22 + 7.0);
    oc *= 1.0 - m * 0.35 * smoothstep(0.45, 0.8, cr);
    // crescent: a dark disk slides across as moonness grows past half
    let bite = length(rel - vec2f(r * 0.85 * smoothstep(0.35, 1.0, m), -4.0));
    if (m > 0.35 && bite < r * 0.98) { oc *= 0.12; }
    col = oc;
  }
  col += warm * exp(-max(d - r, 0.0) * 0.05) * mix(0.9, 0.55, m);   // corona

  // stars belong to the moon
  if (m > 0.25) {
    let sp2 = p * 0.14;
    let cell = floor(sp2);
    let st = hash21(cell);
    if (st > 0.975 && p.y < HL_HOR - 10.0) {
      let d2 = length(fract(sp2) - 0.5);
      let tw = 0.5 + 0.5 * sin(t * 3.0 + st * 40.0);
      col += vec3f(0.9, 0.92, 1.0) * smoothstep(0.16, 0.02, d2) * tw * smoothstep(0.25, 0.6, m);
    }
  }
  return col;
}

fn hl_ridge(x: f32, seed: f32, amp: f32, base: f32) -> f32 {
  return base - amp * (fbm3(vec2f(x * 0.008 + seed, seed)) - 0.25);
}

fn visual_helios(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let asp = 1.0;   // contain-fit shows the whole painting
  let p = vec2f((uv.x + 1.0) * 256.0, (uv.y * asp + 1.0) * 256.0);
  let t = time;
  var sun = vec2f(uni(0), uni(1));
  if (sun.x < 1.0) { sun = vec2f(150.0, 120.0); }        // pre-hook default: morning
  let m = hl_moonness(uni(2));
  let gold = uni(4);

  var col: vec3f;
  let LAKE = 424.0;

  if (p.y < LAKE) {
    col = hl_sky(p, sun, m, t, asp);

    // three ridgelines, lit from wherever the orb hangs
    let warm = mix(vec3f(1.0, 0.75, 0.45), vec3f(0.5, 0.58, 0.75), m);
    let sunSide = clamp(1.0 - abs(p.x - sun.x) / 360.0, 0.0, 1.0);
    let r1 = hl_ridge(p.x, 3.0, 90.0, HL_HOR - 40.0);
    let r2 = hl_ridge(p.x, 11.0, 60.0, HL_HOR - 6.0);
    let r3 = hl_ridge(p.x, 27.0, 34.0, HL_HOR + 26.0);
    if (p.y > r3 && p.y < LAKE) {
      col = mix(vec3f(0.10, 0.16, 0.08), vec3f(0.012, 0.02, 0.03), m);
      col += warm * 0.35 * sunSide * smoothstep(r3 + 14.0, r3, p.y);  // lit brow
      col *= 0.9 + 0.2 * vnoise(p * 0.12);
    } else if (p.y > r2) {
