        let cc = vec3f(0.8, 1.7, 1.1);
        let fc = mix(cc * 0.7, cc * 1.4, pet);
        col = mix(col, fc, fm);
        col = mix(col, cc * 1.6, smoothstep(3.5, 1.0, pol2.x) * prog * budsOn);
        col += cc * exp(-pol2.x * 0.10) * prog * 0.22 * budsOn;
        alpha = max(alpha, fm);
      }
      // hover indicator: a slow-breathing ring names the door
      if (hovered) {
        let ring = smoothstep(2.2, 0.8, abs(length(lq) - (14.0 + sin(t * 2.2) * 1.5)));
        col += vec3f(0.8, 1.7, 1.1) * ring * 0.9;
        col += vec3f(0.8, 1.7, 1.1) * exp(-length(lq) * 0.09) * 0.25;
        alpha = max(alpha, ring * 0.8);
      }
    }
  }
  {
    let bp = vec2f(346.0, 178.0);
    let prog = uni(17);
    let hovered = abs(uni(20) - 4.0) < 0.5;
    let lq = p - bp;
    if (budsOn > 0.001) {
