        let bd = length(lq * vec2f(1.0, 0.85)) - 5.0;
        let bm = smoothstep(1.2, -1.2, bd) * budsOn;
        col = mix(col, vec3f(1.0, 0.62, 0.75), bm);
        alpha = max(alpha, bm);
      } else {
        // the bloom: petals unfurl with a slow twist — each chapter wears its color
        let pol2 = polar(lq);
        let th = pol2.y + (1.0 - prog) * 2.2 + 5.0;
        let pet = abs(sin(th * 3.0));
        let rad = 4.0 + prog * 16.0 * (0.35 + 0.65 * pet);
        let fm = smoothstep(1.5, -1.5, pol2.x - rad) * budsOn;
        let cc = vec3f(1.5, 0.7, 1.8);
        let fc = mix(cc * 0.7, cc * 1.4, pet);
        col = mix(col, fc, fm);
        col = mix(col, cc * 1.6, smoothstep(3.5, 1.0, pol2.x) * prog * budsOn);
        col += cc * exp(-pol2.x * 0.10) * prog * 0.22 * budsOn;
        alpha = max(alpha, fm);
      }
      // hover indicator: a slow-breathing ring names the door
      if (hovered) {
        let ring = smoothstep(2.2, 0.8, abs(length(lq) - (14.0 + sin(t * 2.2) * 1.5)));
        col += vec3f(1.5, 0.7, 1.8) * ring * 0.9;
        col += vec3f(1.5, 0.7, 1.8) * exp(-length(lq) * 0.09) * 0.25;
        alpha = max(alpha, ring * 0.8);
      }
    }
  }
  {
    let bp = vec2f(256.0, 118.0);
    let prog = uni(19);
    let hovered = abs(uni(20) - 6.0) < 0.5;
    let lq = p - bp;
    if (budsOn > 0.001) {
