        alpha = max(alpha, bm);
      } else {
        // the bloom: petals unfurl with a slow twist — each chapter wears its color
        let pol2 = polar(lq);
        let th = pol2.y + (1.0 - prog) * 2.2 + 6.0;
        let pet = abs(sin(th * 3.0));
        let rad = 4.0 + prog * 16.0 * (0.35 + 0.65 * pet);
        let fm = smoothstep(1.5, -1.5, pol2.x - rad) * budsOn;
        let cc = vec3f(0.7, 1.6, 1.9);
        let fc = mix(cc * 0.7, cc * 1.4, pet);
        col = mix(col, fc, fm);
        col = mix(col, cc * 1.6, smoothstep(3.5, 1.0, pol2.x) * prog * budsOn);
        col += cc * exp(-pol2.x * 0.10) * prog * 0.22 * budsOn;
        alpha = max(alpha, fm);
      }
      // hover indicator: a slow-breathing ring names the door
      if (hovered) {
        let ring = smoothstep(2.2, 0.8, abs(length(lq) - (14.0 + sin(t * 2.2) * 1.5)));
        col += vec3f(0.7, 1.6, 1.9) * ring * 0.9;
