try {
  const wd = sim.worldData
  const NB = 16
  if (!wd.__tv || wd.__tv.v !== 2) {
    wd.__tv = { v: 2, ch: 1, sw: 0, held: 0, sHeld: 0, ct: 0, door: 0, laugh: 0, lseq: 0, lq: 0,
      cast: [
        { x: -0.42, tx: -0.42, pose: 2, face: 1, talk: 0, row: 0.0, st: 'sit', t: 4, partner: -1, knocked: 0 },
        { x: 0.47, tx: 0.47, pose: 0, face: 1, talk: 0, row: 0.012, st: 'kitchen', t: 5, partner: -1, knocked: 0 },
        { x: 0.10, tx: 0.10, pose: 0, face: -1, talk: 0, row: -0.012, st: 'idle', t: 2, partner: -1, knocked: 0 },
        { x: 1.10, tx: 1.10, pose: 3, face: -1, talk: 0, row: 0.024, st: 'out', t: 7, partner: -1, knocked: 0 },
      ],
      pong: { bx: 0, by: 0, vx: 0.9, vy: 0.5, pa: 0, pb: 0, sa: 0, sb: 0 },
      boids: Array.from({ length: NB }, (_, i) => ({ x: Math.sin(i * 2.1) * 0.5, y: Math.cos(i * 1.7) * 0.5, vx: 0.2, vy: 0.1 })),
      tgt: { x: 0, y: 0, t: 0 } }
  }
  const G = wd.__tv
  const pdt = Math.min(dt, 0.05)

  // channel change: click anywhere or space
  const want = (wd.mouse_down && !G.held) || (wd.key_space && !G.sHeld)
  if (wd.mouse_down) G.held = 1; else G.held = 0
  if (wd.key_space) G.sHeld = 1; else G.sHeld = 0
  if (want) {
    G.ch = (G.ch + 1) % 5
    G.sw = 1
    wd.__play_sound = [
      { frequency: 1200, duration: 0.03, volume: 0.25, type: 'square' },
      { frequency: 90, duration: 0.15, volume: 0.2, type: 'sawtooth' },
    ]
  }
  G.sw = Math.max(0, G.sw - 2.2 * pdt)

  // ── ALGORITHM 1: Pong plays itself ──
  const P = G.pong
  P.bx += P.vx * pdt; P.by += P.vy * pdt
  if (P.by > 0.92 || P.by < -0.92) { P.vy = -P.vy; P.by = Math.sign(P.by) * 0.92 }
  const chase = (pad, ty) => pad + Math.max(-1.3 * pdt, Math.min(1.3 * pdt, ty - pad))
  P.pa = chase(P.pa, P.vx < 0 ? P.by : P.by * 0.3)
  P.pb = chase(P.pb, P.vx > 0 ? P.by : P.by * 0.3)
  if (P.bx < -0.82 && Math.abs(P.by - P.pa) < 0.19 && P.vx < 0) { P.vx = -P.vx * 1.04; P.vy += (P.by - P.pa) * 2.0; P.bx = -0.82 }
  if (P.bx > 0.82 && Math.abs(P.by - P.pb) < 0.19 && P.vx > 0) { P.vx = -P.vx * 1.04; P.vy += (P.by - P.pb) * 2.0; P.bx = 0.82 }
  if (Math.abs(P.bx) > 1.05) {
    if (P.bx > 0) P.sa = Math.min(5, P.sa + 1); else P.sb = Math.min(5, P.sb + 1)
    if (P.sa >= 5 || P.sb >= 5) { P.sa = 0; P.sb = 0 }
    P.bx = 0; P.by = 0; P.vx = Math.sign(-P.bx || (Math.random() < 0.5 ? 1 : -1)) * 0.9; P.vy = 0.5
    if (G.ch === 2) wd.__play_sound = { frequency: 220, duration: 0.12, volume: 0.25, type: 'square' }
  }
  const spd = Math.hypot(P.vx, P.vy)
  if (spd > 2.2) { P.vx *= 2.2 / spd; P.vy *= 2.2 / spd }

  // ── ALGORITHM 2: boids murmuration ──
  G.tgt.t -= pdt
  if (G.tgt.t <= 0) { G.tgt = { x: (Math.sin(Date.now ? 0 : 0) || Math.sin(G.sw * 7 + P.bx * 13)) * 0.6, y: Math.sin(P.by * 11 + G.ch * 3) * 0.5, t: 2.5 } }
  let cx = 0, cy = 0
  for (const b of G.boids) { cx += b.x; cy += b.y }
  cx /= NB; cy /= NB
  for (const b of G.boids) {
    // cohesion + target + separation + alignment-lite
    b.vx += ((cx - b.x) * 0.4 + (G.tgt.x - b.x) * 0.5) * pdt
    b.vy += ((cy - b.y) * 0.4 + (G.tgt.y - b.y) * 0.5) * pdt
    for (const o of G.boids) {
      if (o === b) continue
      const dx = b.x - o.x, dy = b.y - o.y
      const d2 = dx * dx + dy * dy
      if (d2 < 0.008 && d2 > 1e-6) { b.vx += dx / d2 * 0.0022 * pdt * 60; b.vy += dy / d2 * 0.0022 * pdt * 60 }
    }
    const sp = Math.hypot(b.vx, b.vy) || 1
    const want2 = 0.55
    b.vx *= 1 + (want2 - sp) / sp * 0.08
    b.vy *= 1 + (want2 - sp) / sp * 0.08
    b.x += b.vx * pdt; b.y += b.vy * pdt
    if (Math.abs(b.x) > 0.95) { b.vx -= Math.sign(b.x) * 1.5 * pdt }
    if (Math.abs(b.y) > 0.9) { b.vy -= Math.sign(b.y) * 1.5 * pdt }
  }

  // ── ALGORITHM 3: the sitcom — four lives moving through behavior zones ──
  G.ct += pdt
  G.laugh = Math.max(0, G.laugh - 1.1 * pdt)
  G.door = Math.max(0, G.door - 0.55 * pdt)
  if (G.lseq > 0) {
    G.lq -= pdt
    if (G.lq <= 0) {
      if (G.ch === 4) wd.__play_sound = { frequency: 280 + G.lseq * 55 + Math.random() * 40, duration: 0.07, volume: 0.22, type: 'square' }
      G.lq = 0.11; G.lseq--
    }
  }
  const SEATS = [-0.42, -0.20]
  const CAST = G.cast
  for (let i = 0; i < 4; i++) {
    const c = CAST[i]
    c.t -= pdt
    if (c.st === 'walk') {
      const dw = c.tx - c.x
      c.face = dw > 0 ? 1 : -1
      c.x += Math.sign(dw) * Math.min(Math.abs(dw), 0.16 * pdt)
      c.pose = 1
      c.talk = 0
      if (Math.abs(dw) < 0.006) {
        c.st = c.next; c.t = 2.5 + Math.random() * 4
        if (c.st === 'sit') { c.pose = 2; c.face = c.x < -0.31 ? 1 : -1 }
        else if (c.st === 'out') { c.pose = 3; G.door = 1; c.t = 6 + Math.random() * 12 }
        else { c.pose = 0 }
        if (c.st === 'chat') c.t = 5 + Math.random() * 5
        if (c.st === 'window') c.face = -1
        if (c.st === 'kitchen') c.face = 1
      }
      continue
    }
    if (c.st === 'chat') {
      const pr = CAST[c.partner]
      if (!pr || pr.st !== 'chat') { c.st = 'idle'; c.partner = -1; c.talk = 0; c.t = 2; continue }
      c.face = pr.x > c.x ? 1 : -1
      const tk = Math.floor(G.ct / 1.4) % 2
      c.talk = ((i < c.partner) ? tk === 0 : tk === 1) ? 1 : 0
      if (c.t <= 0 && i < c.partner) {
        // the punchline lands
        G.laugh = 1; G.lseq = 5; G.lq = 0
        pr.st = 'idle'; pr.talk = 0; pr.t = 2 + Math.random() * 3; pr.partner = -1
        c.st = 'idle'; c.talk = 0; c.t = 2 + Math.random() * 3; c.partner = -1
      }
      continue
    }
    if (c.st === 'out') {
      c.talk = 0
      if (c.t <= 0) {
        if (!c.knocked) {
          c.knocked = 1; c.t = 1.1
          if (G.ch === 4) wd.__play_sound = [{ frequency: 130, duration: 0.05, volume: 0.3, type: 'square' }, { frequency: 118, duration: 0.05, volume: 0.28, type: 'square' }]
          continue
        }
        c.knocked = 0; G.door = 1
        c.x = 0.84; c.st = 'walk'; c.pose = 1
        c.tx = -0.05 + Math.random() * 0.35; c.next = 'idle'
        if (G.ch === 4) wd.__play_sound = { frequency: 520, duration: 0.1, volume: 0.18, type: 'triangle' }
      }
      continue
    }
    // standing zones: when the timer runs out, pick the next scene beat
    c.talk = 0
    if (c.t <= 0) {
      const r = Math.random()
      if (r < 0.30) {
        let j = -1
        for (let k = 0; k < 4; k++) {
          const o = CAST[k]
          if (k !== i && o.partner < 0 && o.pose !== 3 && o.st !== 'walk' && o.st !== 'chat' && o.st !== 'out') { j = k; break }
        }
        if (j >= 0) {
          const o = CAST[j]
          const mx2 = Math.max(-0.55, Math.min(0.6, (c.x + o.x) / 2))
          c.partner = j; o.partner = i
          c.st = 'walk'; c.tx = mx2 - 0.055; c.next = 'chat'
          o.st = 'walk'; o.tx = mx2 + 0.055; o.next = 'chat'
          if (o.pose === 2) o.pose = 1
        } else { c.t = 2 }
      }
      else if (r < 0.50) { c.st = 'walk'; c.tx = SEATS[i % 2] + (Math.random() - 0.5) * 0.03; c.next = 'sit' }
      else if (r < 0.66) { c.st = 'walk'; c.tx = 0.44; c.next = 'kitchen' }
      else if (r < 0.80) { c.st = 'walk'; c.tx = -0.62; c.next = 'window' }
      else if (r < 0.88 && i === 3) { c.st = 'walk'; c.tx = 0.82; c.next = 'out' }
      else { c.st = 'walk'; c.tx = -0.15 + Math.random() * 0.45; c.next = 'idle' }
    }
  }

  const u = [G.ch, G.sw, G.door, P.bx, P.by, P.pa, P.pb, P.sa, P.sb, 0]
  for (const b of G.boids) u.push(b.x, b.y)
  for (const c of G.cast) u.push(c.x, c.pose, c.face, c.talk, c.row)
  u.push(G.laugh)
  wd.gpuUniforms = u
  wd.hud = [
    { id: 'tv_ch', type: 'text', x: '14px', y: '12px', text: 'CH ' + (G.ch + 1) + '  \u00b7  ' + ['STATIC', 'PLASMA', 'PONG', 'BOIDS', 'SITCOM'][G.ch], color: '#c9b370', fontSize: '13px' },
    { id: 'tv_hint', type: 'text', x: '14px', bottom: '12px', text: 'click / space: change channel', color: '#6f8f8a', fontSize: '12px' },
  ]
} catch (e) { /* keep the sim alive */ }

visualTypes.wgsl:
// ── the channel words: each is a callable shader — signature (q: -1..1 screen, t) ──

fn ch_static(q: vec2f, t: f32) -> vec3f {
  let n = hash21(floor(q * vec2f(160.0, 120.0)) + floor(t * 60.0) * 7.3);
  var v = 0.25 + 0.75 * n;
  // rolling tear bar
  let bar = fract(q.y * 0.5 - t * 0.35);
  if (bar < 0.06) { v *= 0.45; }
  return vec3f(v);
}

fn ch_plasma(q: vec2f, t: f32) -> vec3f {
  var v = sin(q.x * 6.0 + t * 1.2);
  v += sin((q.y * 5.0 + t) * 0.8);
  v += sin((q.x + q.y) * 4.0 + t * 0.7);
  v += sin(length(q * 5.0) - t * 1.5);
  v *= 0.25;
  return vec3f(0.5 + 0.5 * sin(6.2831 * v), 0.5 + 0.5 * sin(6.2831 * v + 2.1), 0.5 + 0.5 * sin(6.2831 * v + 4.2));
}

fn ch_pong(q: vec2f, t: f32) -> vec3f {
  var col = vec3f(0.02, 0.03, 0.02);
  // net
  if (abs(q.x) < 0.012 && fract(q.y * 5.0) < 0.55) { col = vec3f(0.35); }
  // paddles (hook-simulated)
  if (abs(q.x + 0.85) < 0.03 && abs(q.y - uni(5)) < 0.16) { col = vec3f(1.4); }
  if (abs(q.x - 0.85) < 0.03 && abs(q.y - uni(6)) < 0.16) { col = vec3f(1.4); }
  // ball
  if (abs(q.x - uni(3)) < 0.035 && abs(q.y - uni(4)) < 0.045) { col = vec3f(1.8); }
  // score pips
  for (var i = 0; i < 5; i++) {
    if (f32(i) < uni(7) && length(q - vec2f(-0.5 + f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
    if (f32(i) < uni(8) && length(q - vec2f(0.5 - f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
  }
  return col;
}

fn ch_boids(q: vec2f, t: f32) -> vec3f {
  var col = mix(vec3f(0.03, 0.05, 0.10), vec3f(0.10, 0.14, 0.22), q.y * -0.5 + 0.5);
  // moon
  col += vec3f(0.5, 0.5, 0.42) * exp(-length(q - vec2f(0.55, -0.55)) * 9.0);
  // the flock (hook-simulated)
  for (var i = 0; i < 16; i++) {
    let b = vec2f(uni(10 + i * 2), uni(11 + i * 2));
    let d = length(q - b);
    if (d < 0.028) { col = vec3f(0.02); }                    // bird body
    col += vec3f(0.05, 0.05, 0.04) * exp(-d * 40.0);         // faint presence
  }
  return col;
}


fn sc_box(p: vec2f, c: vec2f, b: vec2f, r: f32) -> f32 {
  let d = abs(p - c) - b;
  return length(max(d, vec2f(0.0))) + min(max(d.x, d.y), 0.0) - r;
}

// CH 5 — SITCOM. The hook runs four little lives through behavior zones
// (couch, kitchen, window, door, center-stage); the tube just draws them.
fn ch_sitcom(q: vec2f, t: f32) -> vec3f {
  let FLOOR = 0.42;
  // the set: warm wall, wood floor
  var col = mix(vec3f(0.20, 0.14, 0.11), vec3f(0.13, 0.09, 0.08), q.y * 0.5 + 0.5);
  col *= 0.94 + 0.06 * sin(q.x * 40.0);
  if (q.y > FLOOR) {
    col = mix(vec3f(0.17, 0.11, 0.06), vec3f(0.10, 0.06, 0.04), (q.y - FLOOR) * 1.6);
    col *= 0.9 + 0.1 * sin(q.x * 24.0 + q.y * 60.0);
  }
  // window on the night
  let wd2 = sc_box(q, vec2f(-0.72, -0.28), vec2f(0.13, 0.17), 0.02);
  if (wd2 < 0.0) {
    col = vec3f(0.02, 0.03, 0.07);
    if (hash21(floor(q * 30.0)) > 0.992) { col += vec3f(0.6); }
    col += vec3f(0.35, 0.35, 0.30) * exp(-length(q - vec2f(-0.68, -0.38)) * 14.0);
    if (abs(q.x + 0.72) < 0.012 || abs(q.y + 0.28) < 0.012) { col = vec3f(0.24, 0.17, 0.12); }
  } else if (wd2 < 0.02) { col = vec3f(0.26, 0.19, 0.13); }
  // the door — uni(2) swings it open on a dark hallway
  let dOpen = uni(2);
  let dframe = sc_box(q, vec2f(0.86, 0.12), vec2f(0.11, 0.30), 0.01);
  if (dframe < 0.0) {
    col = vec3f(0.03, 0.025, 0.032);
    if (q.x > 0.75 + dOpen * 0.17) {
      col = vec3f(0.23, 0.15, 0.09) * (0.85 + 0.15 * sin(q.y * 30.0));
      if (length(q - vec2f(0.78 + dOpen * 0.17, 0.14)) < 0.012) { col = vec3f(0.55, 0.45, 0.25); }
    }
  } else if (dframe < 0.018) { col = vec3f(0.28, 0.20, 0.13); }
  // couch
  let cc = vec2f(-0.30, 0.32);
  if (sc_box(q, cc + vec2f(0.0, -0.10), vec2f(0.27, 0.09), 0.04) < 0.0) { col = vec3f(0.36, 0.11, 0.11); }
  if (sc_box(q, cc + vec2f(0.0, 0.05), vec2f(0.27, 0.06), 0.04) < 0.0) {
    col = vec3f(0.45, 0.14, 0.13);
    if (abs(q.x - cc.x) < 0.004) { col *= 0.8; }
  }
  if (sc_box(q, cc + vec2f(-0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0 ||
      sc_box(q, cc + vec2f(0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0) { col = vec3f(0.42, 0.13, 0.12); }
  // kitchen counter + mug
  if (sc_box(q, vec2f(0.52, 0.47), vec2f(0.14, 0.08), 0.01) < 0.0) { col = vec3f(0.20, 0.16, 0.12); }
  if (sc_box(q, vec2f(0.52, 0.385), vec2f(0.155, 0.014), 0.005) < 0.0) { col = vec3f(0.55, 0.50, 0.42); }
  if (sc_box(q, vec2f(0.47, 0.355), vec2f(0.012, 0.014), 0.004) < 0.0) { col = vec3f(0.75, 0.68, 0.60); }
  // lamp
  if (abs(q.x - 0.13) < 0.006 && q.y > -0.02 && q.y < FLOOR) { col = vec3f(0.1); }
  if (q.y > -0.11 && q.y < -0.02 && abs(q.x - 0.13) < 0.035 + (q.y + 0.11) * 0.45) { col = vec3f(0.85, 0.65, 0.35); }
  col += vec3f(0.5, 0.35, 0.15) * exp(-length((q - vec2f(0.13, 0.05)) * vec2f(1.0, 0.8)) * 3.2) * 0.35;

  // ── the cast (uni 42..61: x, pose, face, talk, row per character) ──
  for (var i = 0; i < 4; i++) {
    let ux = uni(42 + i * 5);
    let pose = uni(43 + i * 5);
    if (pose > 2.5) { continue; }
    let face = uni(44 + i * 5);
    let talk = uni(45 + i * 5);
    let row = uni(46 + i * 5);
    let fi = f32(i);
    var shirt = vec3f(0.75, 0.55, 0.15);
    var hair = vec3f(0.12, 0.09, 0.05);
    if (i == 1) { shirt = vec3f(0.15, 0.50, 0.50); hair = vec3f(0.35, 0.20, 0.08); }
    if (i == 2) { shirt = vec3f(0.55, 0.22, 0.10); hair = vec3f(0.08, 0.08, 0.08); }
    if (i == 3) { shirt = vec3f(0.35, 0.18, 0.42); hair = vec3f(0.50, 0.45, 0.40); }
    let hgt = 0.30 + fi * 0.014;
    let sitting = pose > 1.5;
    let walking = abs(pose - 1.0) < 0.25;
    let bob = select(0.0, abs(sin(t * 7.0 + fi * 2.0)) * 0.012, walking);
    let feetY = select(FLOOR + row, 0.40, sitting) - bob;
    let hipY = feetY - select(hgt * 0.42, 0.055, sitting);
    let torsoC = vec2f(ux, hipY - hgt * 0.19);
    let headC = vec2f(ux + face * 0.008, hipY - hgt * 0.36);
    if (sitting) {
      if (sc_box(q, vec2f(ux + face * 0.05, hipY + 0.05), vec2f(0.05, 0.015), 0.01) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    } else {
      let sw = select(0.0, sin(t * 9.0 + fi * 2.0) * 0.016, walking);
      if (sc_box(q, vec2f(ux - 0.014 + sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0 ||
          sc_box(q, vec2f(ux + 0.014 - sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    }
    if (sc_box(q, torsoC, vec2f(0.036, hgt * 0.20), 0.02) < 0.0) { col = shirt; }
    let hd = length(q - headC);
    if (hd < 0.036) { col = vec3f(0.85, 0.62, 0.45); }
    if (hd < 0.038 && q.y < headC.y - 0.010) { col = hair; }
    if (fract(t * 0.31 + fi * 0.37) > 0.06) {
      if (length(q - (headC + vec2f(face * 0.012 - 0.008, 0.004))) < 0.0035 ||
          length(q - (headC + vec2f(face * 0.012 + 0.008, 0.004))) < 0.0035) { col = vec3f(0.05, 0.05, 0.05); }
    }
    if (talk > 0.5) {
      let bc = headC + vec2f(face * 0.11, -0.105);
      let bd = sc_box(q, bc, vec2f(0.065, 0.030), 0.02);
      if (bd < 0.0) {
        col = vec3f(0.92, 0.92, 0.90);
        for (var k = 0; k < 3; k++) {
          if (fract(t * 0.9 + fi * 0.5) > f32(k) * 0.3 &&
              length(q - (bc + vec2f(-0.03 + f32(k) * 0.03, 0.0))) < 0.008) { col = vec3f(0.25, 0.25, 0.25); }
        }
      } else if (bd < 0.006 && bd >= 0.0) { col = vec3f(0.6, 0.6, 0.58); }
    }
  }
  // the laugh: warm audience light washing up from below
  col += vec3f(0.45, 0.32, 0.12) * uni(62) * (0.6 + 0.4 * sin(t * 18.0)) * (0.3 + 0.7 * smoothstep(0.0, 0.8, q.y));
  return col;
}

fn visual_tv_set(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = (uv + vec2f(1.0)) * 256.0;
  let t = time;

  // the room: dark, lit by the set
  var col = vec3f(0.012, 0.011, 0.015) * (1.0 + 0.35 * fbm3(p * 0.01));

  let C = vec2f(256.0, 238.0);
  let half = vec2f(172.0, 122.0);
  let dBez = sdRoundedBox(p - C, half + vec2f(22.0, 26.0), 14.0);
  let dScr = sdRoundedBox(p - C, half, 10.0);

  // glow spill on the room
  let flick = 0.94 + 0.06 * sin(t * 47.0) * sin(t * 31.0);
  col += vec3f(0.10, 0.12, 0.16) * flick * exp(-max(dBez, 0.0) * 0.02);

  // bezel: warm plastic with a highlight
  if (dBez < 0.0 && dScr >= 0.0) {
    col = mix(vec3f(0.10, 0.085, 0.07), vec3f(0.16, 0.14, 0.12), fbm3(p * 0.15) * 0.5);
    col *= 0.8 + 0.4 * smoothstep(20.0, -30.0, p.y - (C.y - half.y));
    // channel knob
    let kd = length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)));
    if (kd < 7.0) {
      col = vec3f(0.05);
      let ka = 6.2831 * uni(0) / 5.0 - 1.57;
      if (length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)) - vec2f(cos(ka), sin(ka)) * 4.0) < 1.6) { col = vec3f(0.7); }
    }
  }

  // the screen: barrel-distorted, phosphor, scanlines — a CRT calling a channel
  if (dScr < 0.0) {
    var q = (p - C) / half;                                   // -1..1
    q *= 1.0 + 0.10 * dot(q, q);                              // barrel
    if (abs(q.x) > 1.0 || abs(q.y) > 1.0) {
      col = vec3f(0.0);                                       // over-scan black
    } else {
      // ── THE CALL: channel word by number ──
      let ch = i32(uni(0) + 0.5);
      var scr: vec3f;
      if (ch == 0) { scr = ch_static(q, t); }
      else if (ch == 1) { scr = ch_plasma(q, t); }
      else if (ch == 2) { scr = ch_pong(q, t); }
      else if (ch == 3) { scr = ch_boids(q, t); }
      else { scr = ch_sitcom(q, t); }

      // switch burst: static bleeds over the program
      if (uni(1) > 0.01) { scr = mix(scr, ch_static(q, t * 3.0), min(uni(1) * 1.4, 1.0)); }

      // CRT dress: phosphor triads, scanlines, corner falloff, flicker
      let px = i32(p.x * 3.0) % 3;
      var mask = vec3f(0.85);
      if (px == 0) { mask = vec3f(1.25, 0.72, 0.72); }
      else if (px == 1) { mask = vec3f(0.72, 1.25, 0.72); }
      else { mask = vec3f(0.72, 0.72, 1.25); }
      scr *= mask;
      scr *= 0.82 + 0.18 * sin(p.y * 3.14159);                // scanlines
      scr *= flick;
      scr *= 1.0 - 0.45 * pow(length(q), 4.0);                // corner falloff
      col = scr * 1.35;                                       // HDR — bloom catches the tube
    }
  }

  // set shadow on the floor
  col *= 1.0 - 0.3 * smoothstep(30.0, 0.0, abs(p.y - (C.y + half.y + 40.0))) * smoothstep(half.x + 40.0, half.x - 20.0, abs(p.x - C.x));

  return vec4f(col, 1.0);
}

stepHooks.code:
try {
  const wd = sim.worldData
  if (!wd.__sg || !wd.__sg.keys) {
    wd.__sg = { age: 0, word: '', committed: '', hinted: false, pulse: 0, keys: {},
      F: .0545, k: .062, A: 1, B: .62, C: .55,
      tF: .0545, tk: .062, tA: 1, tB: .62, tC: .55 }
  }
  const G = wd.__sg
  if (wd.__fresh) {
    // new session: reseed the tube, keep the saved tuning (F/k/palette survive)
    delete wd.__fresh
    G.age = 0; G.word = ''; G.pulse = 0; G.keys = {}; G.hinted = false
  }
  const dt2 = Math.min(dt, 0.05)
  G.age += dt2

  // words → coordinates in the reaction's parameter space + a palette.
  // Regimes are real Gray-Scott territories: these words GROW what they name.
  const REG = { mit: [.0367, .0649], coral: [.0545, .062], worms: [.046, .063],
    maze: [.029, .057], soli: [.03, .062], holes: [.039, .058],
    chaos: [.026, .051], waves: [.014, .045], dead: [.005, .075] }
  const PAL = { cyan: [.35, 1, 1.1], coral: [1, .5, .55], amber: [1, .62, .2],
    blue: [.35, .5, 1.2], red: [1, .35, .1], violet: [.8, .38, 1.15],
    green: [.35, 1, .3], gold: [1, .8, .25], ice: [.6, .85, 1.15],
    indigo: [.5, .38, 1.2], grey: [.5, .5, .55], rose: [1, .45, .8], white: [.9, .95, .95] }
  const LEX = {
    life: 'mit/green', cells: 'mit/cyan', cell: 'mit/cyan', mitosis: 'mit/cyan',
    divide: 'mit/cyan', birth: 'mit/rose', seed: 'mit/green', cradle: 'mit/cyan',
    love: 'mit/rose', blood: 'mit/red', heart: 'mit/rose', pulse: 'mit/red',
    coral: 'coral/coral', reef: 'coral/coral', garden: 'coral/green', moss: 'coral/green',
    grow: 'coral/green', bloom: 'coral/rose', flower: 'coral/rose', forest: 'coral/green',
    tree: 'coral/green', home: 'coral/amber', reality: 'coral/white',
    light: 'coral/gold', dawn: 'coral/gold', sun: 'coral/gold', gold: 'coral/gold',
    worm: 'worms/amber', worms: 'worms/amber', snake: 'worms/amber', roots: 'worms/amber',
    veins: 'worms/red', ember: 'worms/red', river: 'worms/blue',
    maze: 'maze/violet', labyrinth: 'maze/violet', mind: 'maze/violet', brain: 'maze/violet',
    thought: 'maze/violet', dream: 'maze/violet', ghost: 'maze/ice', spirit: 'maze/ice',
    memory: 'maze/indigo', signal: 'maze/green',
    star: 'soli/ice', stars: 'soli/ice', dust: 'soli/ice', rain: 'soli/blue',
    snow: 'soli/white', night: 'soli/indigo', moon: 'soli/ice', dark: 'soli/indigo',
    storm: 'chaos/red', chaos: 'chaos/red', fire: 'chaos/red', burn: 'chaos/amber',
    war: 'chaos/red', anger: 'chaos/red', lightning: 'chaos/ice',
    ocean: 'waves/blue', sea: 'waves/blue', wave: 'waves/blue', waves: 'waves/blue',
    tide: 'waves/blue', water: 'waves/blue', wind: 'waves/ice',
    calm: 'holes/indigo', still: 'holes/indigo', peace: 'holes/ice', sleep: 'holes/indigo',
    quiet: 'holes/grey', shelter: 'holes/amber',
    death: 'dead/grey', void: 'dead/grey', end: 'dead/grey', silence: 'dead/grey', nothing: 'dead/grey',
  }
  const caption = (text, kind) => {
    if (typeof window !== 'undefined')
      window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text, kind } }))
  }
  // real semantics: word vectors (the Cradle's GloVe space) load once and any
  // word projects onto anchor concepts by cosine similarity — semantic
  // NEIGHBORS get neighboring physics without ever being written down
  if (typeof window !== 'undefined' && !window.__ccSemantic && !window.__ccSemLoading) {
    window.__ccSemLoading = 1
    fetch('/semantic-50d.json').then(r => r.json()).then(d => { window.__ccSemantic = d }).catch(() => {})
  }
  const ANCHORS = ['life', 'coral', 'worm', 'maze', 'star', 'storm', 'ocean', 'calm', 'death', 'light', 'blood', 'forest', 'ghost', 'fire', 'rain', 'night', 'love', 'war', 'home', 'dream']
  const tune = (word) => {
    let reg, pal, via = ''
    const hit = LEX[word]
    const V = (typeof window !== 'undefined') ? window.__ccSemantic : null
    if (hit) {
      const [r, c] = hit.split('/'); reg = REG[r]; pal = PAL[c]
    } else if (V && V[word]) {
      // cosine to each anchor, blend the top three
      const wv = V[word]
      const cos = (a, b) => {
        let d = 0, na = 0, nb = 0
        for (let k = 0; k < 50; k++) { d += a[k] * b[k]; na += a[k] * a[k]; nb += b[k] * b[k] }
        return d / Math.sqrt(na * nb + 1e-9)
      }
      const sims = ANCHORS.filter(a => V[a] && LEX[a]).map(a => ({ a, s: cos(wv, V[a]) }))
      sims.sort((x, y) => y.s - x.s)
      const top = sims.slice(0, 3)
      const wts = top.map(t => Math.exp((t.s - top[0].s) / 0.08))
      const wsum = wts.reduce((a, b) => a + b, 0)
      reg = [0, 0]; pal = [0, 0, 0]
      top.forEach((t, j) => {
        const [r, c] = LEX[t.a].split('/')
        const w = wts[j] / wsum
        reg[0] += REG[r][0] * w; reg[1] += REG[r][1] * w
        for (let k2 = 0; k2 < 3; k2++) pal[k2] += PAL[c][k2] * w
      })
      via = top[0].a
      caption(word + ' · feels like ' + via, 'hint')
    } else {
      // unheard words still land somewhere in parameter space, deterministically
      let h = 2166136261
      for (const ch of word) { h ^= ch.charCodeAt(0); h = (h * 16777619) >>> 0 }
      reg = [.014 + (h % 1000) / 1000 * .046, .045 + ((h >>> 10) % 1000) / 1000 * .021]
      const keys = Object.keys(PAL); pal = PAL[keys[(h >>> 20) % keys.length]]
    }
    G.tF = reg[0]; G.tk = reg[1]; G.tA = pal[0]; G.tB = pal[1]; G.tC = pal[2]
    if (typeof window !== 'undefined') window.__sgState = { word, via, F: reg[0], k: reg[1], A: pal[0], B: pal[1], C: pal[2] }
  }

  // typing — every letter is an input to the world
  // pulse counters from the engine — a tap between sim frames still lands
  const edge = (k) => {
    const n = wd['key_' + k + '_n'] || 0
    const was = G.keys[k] || 0
    G.keys[k] = n
    return n > was
  }
  for (let i = 0; i < 26; i++) {
    const ch = String.fromCharCode(97 + i)
    if (edge(ch) && G.word.length < 14) { G.word += ch; caption(G.word, 'typing') }
  }
  if (edge('backspace')) { G.word = G.word.slice(0, -1); caption(G.word, 'typing') }
  if (edge('space')) { G.word = ''; caption('', 'typing') }
  if (edge('enter') && G.word) {
    tune(G.word); G.committed = G.word; G.pulse = 1
    caption(G.word, 'tuned'); G.word = ''
  }
  if (!G.hinted && G.age > 1.6) { G.hinted = true; if (!G.word && !G.committed) caption('type a word · enter tunes reality', 'hint') }

  G.pulse = Math.max(0, G.pulse - dt2 * 0.8)
  const gl = (c, t, r) => c + (t - c) * Math.min(1, dt2 * r)
  G.F = gl(G.F, G.tF, 1.2); G.k = gl(G.k, G.tk, 1.2)
  G.A = gl(G.A, G.tA, 2); G.B = gl(G.B, G.tB, 2); G.C = gl(G.C, G.tC, 2)

  const mx = ((wd.mouse_x ?? 256) - 256) / 256
  const my = ((wd.mouse_y ?? 256) - 256) / 256
  wd.gpuUniforms = [mx, my, wd.mouse_down ? 1 : 0, G.F, G.k, G.A, G.B, G.C, G.pulse, G.age > 0.4 ? 1 : 0]
} catch (e) { /* the set stays on */ }

visualTypes.wgsl:
fn od_ic() -> vec2f { return vec2f(-9.0, 32.0); }

fn od_suncol(el: f32) -> vec3f {
  return mix(vec3f(1.30, 0.45, 0.16), vec3f(1.15, 1.05, 0.90), smoothstep(0.02, 0.55, el));
}

fn od_sky(rd: vec3f, sd: vec3f, md: vec3f, t: f32) -> vec3f {
  let el = uni(1);
  let y = max(rd.y, 0.0);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);

  // dome: night indigo → day blue, horizon warms at low sun
  let zen = mix(vec3f(0.012, 0.018, 0.045), vec3f(0.16, 0.36, 0.65), day);
  let horDay = mix(vec3f(1.00, 0.42, 0.16), vec3f(0.46, 0.58, 0.72), smoothstep(0.10, 0.55, el));
  let hor = mix(vec3f(0.035, 0.035, 0.075), horDay, smoothstep(-0.16, 0.06, el));
  var c = mix(hor, zen, pow(y, 0.6));

  // sun
  let sdot = clamp(dot(rd, sd), 0.0, 1.0);
  let sunUp = smoothstep(-0.14, 0.02, el);
  c += od_suncol(el) * pow(sdot, 5.0) * 0.32 * sunUp;
  c += od_suncol(el) * pow(sdot, 70.0) * 0.60 * sunUp;
  c += vec3f(5.2, 3.6, 2.0) * smoothstep(0.99972, 0.99990, sdot) * sunUp;

  // moon: cool disk + halo, out at night
  let mdot = clamp(dot(rd, md), 0.0, 1.0);
  let moonUp = night * smoothstep(-0.05, 0.10, md.y);
  c += vec3f(0.55, 0.62, 0.75) * pow(mdot, 90.0) * 0.5 * moonUp;
  c += vec3f(2.6, 2.8, 3.1) * smoothstep(0.99985, 0.99995, mdot) * moonUp;

  // stars + a faint galaxy band
  if (night > 0.02 && rd.y > 0.01) {
    let sp = rd.xz / (rd.y + 0.55) * 26.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let tw = 0.55 + 0.45 * sin(t * (0.8 + h) + h * 50.0);
    c += vec3f(0.72, 0.78, 0.95) * step(0.990, h) * smoothstep(0.30, 0.05, length(fract(sp) - 0.5)) * night * tw;
    let band = pow(max(1.0 - abs(rd.x * 0.8 + rd.y * 0.5 - 0.15), 0.0), 3.5);
    c += vec3f(0.07, 0.07, 0.12) * band * night * (0.5 + 0.3 * vnoise(sp * 0.5));
  }

  // clouds: sparse, tinted by the hour
  if (rd.y > 0.015) {
    let cp = rd.xz / (rd.y + 0.14) * 1.4 + vec2f(t * 0.006, t * 0.002);
    var cl = fbm(cp * 0.55, 4);
    cl = smoothstep(0.46, 0.78, cl);
    let cloudLit = mix(vec3f(0.06, 0.06, 0.10), mix(vec3f(1.15, 0.50, 0.28), vec3f(0.85, 0.85, 0.90), smoothstep(0.12, 0.5, el)), max(day, night * 0.12));
    c = mix(c, cloudLit, cl * 0.7 * smoothstep(0.015, 0.10, rd.y));
  }
  return c;
}

fn od_oct(uv0: vec2f, choppy: f32) -> f32 {
  let n = gnoise(uv0);
  let uv = uv0 + vec2f(n, n);
  var wv = 1.0 - abs(sin(uv));
  let swv = abs(cos(uv));
  wv = mix(wv, swv, wv);
  return pow(1.0 - pow(wv.x * wv.y, 0.65), choppy);
}

fn od_surge(pxz: vec2f, st: f32) -> f32 {
  let dr = length(pxz - od_ic());
  return exp(-max(dr - 5.8, 0.0) * 0.35) * (sin(st * 1.4 - dr * 0.9) * 0.5 + 0.62) * 1.05;
}


fn od_wake(pxz: vec2f) -> f32 {
  let d = vec2f(pxz.x - uni(7), pxz.y - 52.0);
  let along = -d.x * uni(8);                 // positive = behind the boat
  if (along < -3.0 || along > 26.0 || abs(d.y) > 12.0) { return 0.0; }
  let a = max(along, 0.0);
  var w = exp(-dot(d, d) * 0.35) * 0.8;      // bow mound at the hull
  let arm = exp(-pow((abs(d.y) - 0.36 * a) * 1.1, 2.0)) * exp(-a * 0.10);  // Kelvin arms (~19.5deg)
  let inside = smoothstep(0.36 * a + 1.0, 0.36 * a - 1.0, abs(d.y));
  let ripple = sin(a * 2.4) * 0.5 * inside * exp(-a * 0.13);               // transverse train
  return w + arm * 0.9 + ripple;
}

fn od_amp() -> f32 { return 0.55 + 0.75 * uni(3); }   // wind raises the sea

fn od_map3(p: vec3f, st: f32) -> f32 {
  var freq = 0.16;
  var amp = 0.6 * od_amp();
  var choppy = 4.0;
  var uv = p.xz;
  uv.x = uv.x * 0.75;
  var h = 0.0;
  for (var i = 0; i < 3; i++) {
    var d = od_oct((uv + vec2f(st)) * freq, choppy);
    d = d + od_oct((uv - vec2f(st)) * freq, choppy);
    h = h + d * amp;
    uv = mat2x2f(1.6, 1.2, -1.2, 1.6) * uv;
    freq = freq * 1.9;
    amp = amp * 0.22;
    choppy = mix(choppy, 1.0, 0.2);
  }
  h = h + od_surge(p.xz, st);
  h = h + od_wake(p.xz) * 0.22;
  return p.y - h;
}

fn od_map5(p: vec3f, st: f32) -> f32 {
  var freq = 0.16;
  var amp = 0.6 * od_amp();
  var choppy = 4.0;
  var uv = p.xz;
  uv.x = uv.x * 0.75;
  var h = 0.0;
  for (var i = 0; i < 5; i++) {
    var d = od_oct((uv + vec2f(st)) * freq, choppy);
    d = d + od_oct((uv - vec2f(st)) * freq, choppy);
    h = h + d * amp;
    uv = mat2x2f(1.6, 1.2, -1.2, 1.6) * uv;
    freq = freq * 1.9;
    amp = amp * 0.22;
    choppy = mix(choppy, 1.0, 0.2);
  }
  h = h + od_surge(p.xz, st);
  h = h + od_wake(p.xz) * 0.22;
  return p.y - h;
}

fn od_nrm(p: vec3f, eps: f32, st: f32) -> vec3f {
  let hy = od_map5(p, st);
  let hx = od_map5(p + vec3f(eps, 0.0, 0.0), st);
  let hz = od_map5(p + vec3f(0.0, 0.0, eps), st);
  return normalize(vec3f(hx - hy, eps, hz - hy));
}

fn od_spec(n: vec3f, l: vec3f, e: vec3f, s: f32) -> f32 {
  let nrm = (s + 8.0) / (3.14159 * 8.0);
  return pow(max(dot(reflect(e, n), l), 0.0), s) * nrm;
}

fn od_seacol(p: vec3f, n: vec3f, sd: vec3f, md: vec3f, eye: vec3f, dist: vec3f, t: f32, st: f32) -> vec3f {
  let el = uni(1);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);

  var fres = clamp(1.0 - dot(n, -eye), 0.0, 1.0);
  fres = pow(fres, 3.0) * 0.5;

  let reflected = od_sky(reflect(eye, n), sd, md, t);
  let base = mix(vec3f(0.004, 0.008, 0.016), vec3f(0.035, 0.06, 0.11), day);
  let waterCol = vec3f(0.17, 0.23, 0.22) * (0.25 + 0.75 * day);
  let refracted = base + pow(dot(n, sd) * 0.4 + 0.6, 80.0) * waterCol * 0.12 * day;

  var col = mix(refracted, reflected, fres);

  let atten = max(1.0 - dot(dist, dist) * 0.001, 0.0);
  col = col + waterCol * (p.y - 0.6) * 0.18 * atten;

  // sun glitter by day, moon glitter by night — same sea, different star
  col = col + od_suncol(el) * vec3f(2.4, 1.5, 0.8) * od_spec(n, sd, eye, 90.0) * smoothstep(-0.08, 0.05, el);
  col = col + vec3f(0.9, 1.05, 1.3) * od_spec(n, md, eye, 140.0) * night * smoothstep(0.0, 0.15, md.y) * 1.6;

  // crest foam
  let foamN = vnoise(p.xz * 2.2 + vec2f(t * 0.5, -t * 0.35));
  let crest = smoothstep(1.05, 1.55, p.y) * smoothstep(0.42, 0.85, foamN);
  col = mix(col, vec3f(0.90, 0.82, 0.72) * (0.25 + 0.75 * day), crest * atten * 0.4);

  // island surf ring
  let drf = length(p.xz - od_ic()) - 6.2;
  let ph = sin(st * 1.4 - (drf + 6.2) * 0.9) * 0.5 + 0.5;
  var rockFoam = smoothstep(3.2, 0.2, drf) * (0.35 + 0.65 * ph);
  rockFoam = rockFoam * (0.45 + 0.55 * vnoise(p.xz * 2.6 + vec2f(st * 0.8, -st * 0.55)));
  col = mix(col, vec3f(0.90, 0.88, 0.84) * (0.3 + 0.7 * day + 0.25 * night), clamp(rockFoam, 0.0, 1.0) * 0.85);

  // boat wake foam — the ocean reads the boat off the whiteboard
  let wk = od_wake(p.xz);
  col = mix(col, vec3f(0.82, 0.85, 0.84) * (0.35 + 0.65 * day + 0.2 * night), clamp(wk * 0.9 - 0.12, 0.0, 1.0) * 0.55);

  return col;
}

fn visual_od_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x, -uv.y);
  let t = time;
  let st = 1.0 + t * 0.8;

  let bob = sin(t * 0.5) * 0.06;
  let ro = vec3f(0.0, 3.4 + bob, 0.0);
  // wide viewports crop the field vertically — widen the vertical FOV to keep
  // the whole lighthouse in frame at any aspect
  let visH = clamp(frame.resolution.y / max(frame.resolution.x, 1.0), 0.45, 1.0);
  var rd = normalize(vec3f(p.x, (p.y * 0.72) / visH - 0.14 * visH, 1.75));
  let rxy = rotate(rd.xy, sin(t * 0.35) * 0.012);
  rd = normalize(vec3f(rxy.x, rxy.y, rd.z));

  // the whiteboard drives the world
  let saz = uni(0);
  let sel = uni(1);
  let sd = normalize(vec3f(cos(saz) * cos(sel), sin(sel), sin(saz) * cos(sel)));
  let mel = uni(5);
  let maz = uni(6);
  let md = normalize(vec3f(cos(maz) * cos(mel), sin(mel), sin(maz) * cos(mel)));

  var col = od_sky(rd, sd, md, t);
  var tScene = 100000.0;

  // ---- ocean ----
  if (rd.y < 0.0) {
    var tm = 0.0;
    var tx = 1000.0;
    var hx = od_map3(ro + rd * tx, st);
    if (hx < 0.0) {
      var hm = od_map3(ro, st);
      var tmid = 0.0;
      for (var i = 0; i < 8; i++) {
        tmid = mix(tm, tx, hm / (hm - hx));
        let pm = ro + rd * tmid;
        let hmid = od_map3(pm, st);
        if (hmid < 0.0) { tx = tmid; hx = hmid; } else { tm = tmid; hm = hmid; }
      }
      let pt = ro + rd * tmid;
      let dist = pt - ro;
      let eps = max(dot(dist, dist) * 0.0002, 0.002);
      let n = od_nrm(pt, eps, st);
      var seaCol = od_seacol(pt, n, sd, md, rd, dist, t, st);
      if (uni(10) > 0.01) {
        let u = uni(10);
        // a patchy ignition front spreads across the water
        let front = smoothstep(u * 1.15, u * 1.15 - 0.22, fbm3(pt.xz * 0.045 + 3.7));
        let burn = u * front;
        if (burn > 0.003) {
          // char: the water darkens as it heats
          seaCol = mix(seaCol, seaCol * vec3f(0.35, 0.22, 0.18), min(burn * 2.2, 1.0));
          // ember cracks glow in the troughs
          let crack = pow(vnoise(pt.xz * 1.6 + vec2f(st * 0.4, -st * 0.3)), 4.0);
          seaCol += vec3f(2.4, 0.5, 0.05) * crack * smoothstep(0.05, 0.45, burn);
          // crests ignite: flames ride the wave tops
          let crest = smoothstep(0.4, 1.4, pt.y);
          let lick = fbm3(vec2f(pt.x * 0.8, pt.z * 0.8 - t * 2.6));
          seaCol += mix(vec3f(1.8, 0.5, 0.02), vec3f(3.0, 1.8, 0.25), lick) * crest * smoothstep(0.3, 0.8, burn) * (0.6 + 0.4 * lick);
          // molten body at full burn
          let fl = fbm3(pt.xz * 0.35 + vec2f(t * 1.8, -t * 1.2));
          let molten = mix(vec3f(1.6, 0.35, 0.05), vec3f(2.8, 1.6, 0.22), fl);
          seaCol = mix(seaCol, molten, smoothstep(0.55, 1.0, burn) * (0.55 + 0.45 * fl));
        }
      }
      let seaBlend = pow(1.0 - smoothstep(-0.02, 0.0, rd.y), 0.2);
      col = mix(col, seaCol, seaBlend);
      tScene = tmid;
    }
  }

  // leaping tongues — the burn climbs off the water into the air
  if (uni(10) > 0.05 && rd.y < 0.16) {
    let hb = smoothstep(0.16, -0.02, rd.y);
    let fx = rd.x / max(rd.z, 0.2);
    let tongue = fbm3(vec2f(fx * 9.0, rd.y * 26.0 - t * 3.2));
    let tongue2 = vnoise(vec2f(fx * 22.0 + 7.0, rd.y * 40.0 - t * 5.0));
    let leap = pow(tongue, 2.0) * (0.5 + 0.5 * tongue2) * hb * uni(10);
    col += mix(vec3f(2.2, 0.6, 0.04), vec3f(3.4, 1.9, 0.3), tongue2) * leap * 0.9;
  }

  // ---- distant sailboat crossing (whiteboard position) ----
  let B = vec3f(uni(7), 0.9 + sin(t * 0.7) * 0.15, 52.0);
  let toB = B - ro;
  let bDist = length(toB);
  let bDir = toB / bDist;
  if (dot(rd, bDir) > 0.995 && tScene > bDist) {
    let right = normalize(cross(bDir, vec3f(0.0, 1.0, 0.0)));
    let upv = cross(right, bDir);
    let par = dot(rd, bDir);
    let lx = dot(rd, right) / par * bDist * uni(8);   // flip with travel direction
    let ly = dot(rd, upv) / par * bDist;
    // hull + mainsail silhouette, warm-rimmed at low sun
    let hull = max(abs(lx) - 1.9 * (1.0 - clamp(ly + 0.4, 0.0, 0.5)), abs(ly + 0.45) - 0.35);
    let sail = max(max(-(lx + 0.1), ly - 2.6), (lx * 0.62 + ly * 0.55) - 1.35);
    let el2 = uni(1);
    let silCol = mix(vec3f(0.015, 0.015, 0.025), vec3f(0.10, 0.05, 0.04), smoothstep(0.3, 0.02, abs(el2)) * 0.8);
    if (hull < 0.0 || sail < 0.0) {
      col = silCol + od_suncol(el2) * 0.25 * smoothstep(0.15, -0.05, lx * uni(8)) * smoothstep(-0.08, 0.05, el2);
    }
  }

  return vec4f(col, 1.0);
}

fn od2_ic() -> vec2f { return vec2f(-9.0, 32.0); }
fn od2_suncol(el: f32) -> vec3f {
  return mix(vec3f(1.30, 0.45, 0.16), vec3f(1.15, 1.05, 0.90), smoothstep(0.02, 0.55, el));
}
fn od2_box(p: vec3f, b: vec3f) -> f32 {
  let d = abs(p) - b;
  return length(max(d, vec3f(0.0))) + min(max(d.x, max(d.y, d.z)), 0.0);
}

// materials: 0 rock · 1 whitewash tower · 2 ironwork · 3 lantern glass
//            4 copper cupola · 5 cottage wall · 6 cottage roof · 7 chimney · 8 door
fn od2_sdf(p: vec3f) -> vec2f {
  let ic = od2_ic();
  let q = p - vec3f(ic.x, 0.0, ic.y);

  // the rock
  var d = length(q * vec3f(1.0, 1.25, 1.08)) - 6.4;
  d = d - (vnoise3(q * 0.55) - 0.5) * 2.6 - (vnoise3(q * 1.9) - 0.5) * 0.9;
  var m = 0.0;

  // tapered masonry tower with a wider plinth — colonial whitewash
  let ty = clamp((p.y - 4.0) / 7.5, 0.0, 1.0);
  let taper = mix(1.42, 0.88, pow(ty, 0.85));
  let plinth = 1.0 + 0.35 * smoothstep(5.2, 4.0, p.y);
  let dTower = max(length(q.xz) - taper * plinth, abs(p.y - 7.75) - 3.75);
  if (dTower < d) { d = dTower; m = 1.0; }

  // gallery deck + railing: handrail ring and a circle of balusters
  let dDeck = max(length(q.xz) - 1.52, abs(p.y - 11.62) - 0.14);
  if (dDeck < d) { d = dDeck; m = 2.0; }
  let dRail = max(abs(length(q.xz) - 1.44) - 0.035, abs(p.y - 12.42) - 0.045);
  if (dRail < d) { d = dRail; m = 2.0; }
  let phi = atan2(q.z, q.x);
  let seg = 6.28318 / 20.0;
  let aphi = (glsl_mod(phi + seg * 0.5, seg) - seg * 0.5) * 1.44;
  let dBal = max(length(vec2f(length(q.xz) - 1.44, aphi)) - 0.035, abs(p.y - 12.02) - 0.42);
  if (dBal < d) { d = dBal; m = 2.0; }

  // octagonal lantern room
  var oct = abs(q.x);
  oct = max(oct, abs(q.z));
  oct = max(oct, abs(q.x * 0.7071 + q.z * 0.7071));
  oct = max(oct, abs(q.x * 0.7071 - q.z * 0.7071));
  let dLan = max(oct - 0.82, abs(p.y - 12.55) - 0.72);
  if (dLan < d) { d = dLan; m = 3.0; }

  // copper cupola with finial
  let ry = clamp((p.y - 13.27) / 1.15, 0.0, 1.0);
  let dRoof = max(length(q.xz) - mix(1.06, 0.06, pow(ry, 0.72)), abs(p.y - 13.84) - 0.58);
  if (dRoof < d) { d = dRoof; m = 4.0; }
  let dFin = length(vec3f(q.x, (p.y - 14.72) * 0.8, q.z)) - 0.14;
  if (dFin < d) { d = dFin; m = 2.0; }

  // the keeper's cottage: clapboard saltbox, gable roof, brick chimney
  let qc = q - vec3f(3.1, 4.45, 0.6);
  let dHouse = od2_box(qc, vec3f(1.55, 0.95, 1.15));
  if (dHouse < d) { d = dHouse; m = 5.0; }
  let dRoofH = max(max(abs(qc.z) * 0.92 + (qc.y - 1.72), -(qc.y - 0.75)), max(abs(qc.x) - 1.72, abs(qc.z) - 1.32));
  if (dRoofH < d) { d = dRoofH; m = 6.0; }
  let dChim = od2_box(qc - vec3f(0.55, 1.85, 0.0), vec3f(0.22, 0.65, 0.22));
  if (dChim < d) { d = dChim; m = 7.0; }

  return vec2f(d, m);
}

fn od2_trace(ro: vec3f, rd: vec3f) -> vec3f {
  let ic = od2_ic();
  let oc = ro - vec3f(ic.x, 6.5, ic.y);
  let b = dot(oc, rd);
  let c = dot(oc, oc) - 182.25;
  let disc = b * b - c;
  if (disc < 0.0) { return vec3f(0.0, 0.0, -1.0); }
  let sq = sqrt(disc);
  let t1 = -b + sq;
  var tt = max(-b - sq, 0.0);
  for (var i = 0; i < 60; i++) {
    let dm = od2_sdf(ro + rd * tt);
    if (dm.x < 0.02) { return vec3f(tt, dm.y, 1.0); }
    tt = tt + dm.x * 0.7;
    if (tt > t1) { break; }
  }
  return vec3f(0.0, 0.0, -1.0);
}

// arched-window mask on the tower shaft, facing the sea (toward the viewer)
fn od2_window(phi: f32, y: f32, yc: f32) -> f32 {
  let PHIC = -1.296;   // bearing from island to the home shore
  var ang = phi - PHIC;
  ang = glsl_mod(ang + 3.14159, 6.28318) - 3.14159;
  let aw = ang * 1.15;
  let wy = y - yc;
  let rect = step(abs(aw), 0.145) * step(-0.26, wy) * step(wy, 0.13);
  let arch = step(length(vec2f(aw, wy - 0.13)), 0.145);
  return max(rect, arch);
}

fn od2_shade(p: vec3f, n: vec3f, rd: vec3f, m: f32, sd: vec3f, t: f32, st: f32) -> vec3f {
  let el = uni(1);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);
  let ic = od2_ic();
  let q = p - vec3f(ic.x, 0.0, ic.y);
  let phi = atan2(q.z, q.x);
  var alb = vec3f(0.0);
  var emis = vec3f(0.0);
  var spec = 0.0;

  if (m < 0.5) {
    // rock: strata, wet dark base, lichen where it faces the sky
    let strat = sin(p.y * 2.1 + (vnoise3(p * 0.4) - 0.5) * 5.0);
    alb = mix(vec3f(0.055, 0.052, 0.058), vec3f(0.125, 0.115, 0.10), 0.5 + 0.5 * strat);
    alb = mix(alb, vec3f(0.14, 0.13, 0.10), vnoise3(p * 1.7) * 0.4);
    let wet = smoothstep(2.6, 0.5, p.y);
    alb = alb * (1.0 - wet * 0.6);
    spec = wet * 0.5;
    let lich = smoothstep(0.45, 0.75, vnoise3(p * 2.3)) * smoothstep(0.35, 0.7, n.y) * smoothstep(3.2, 4.4, p.y);
    alb = mix(alb, vec3f(0.16, 0.17, 0.08), lich * 0.7);
  } else if (m < 1.5) {
    // whitewashed masonry: courses, joints, weather streaks
    alb = vec3f(0.86, 0.85, 0.81);
    let course = smoothstep(0.055, 0.02, abs(fract(p.y / 0.58) - 0.5) * 0.58);
    let joint = smoothstep(0.05, 0.02, abs(fract(phi * 1.15 / 0.85 + floor(p.y / 0.58) * 0.5) - 0.5) * 0.85);
    alb = alb * (1.0 - course * 0.10 - joint * course * 0.05);
    let streak = smoothstep(0.55, 0.9, vnoise(vec2f(phi * 6.0, p.y * 0.22)));
    alb = alb * (1.0 - streak * 0.16 * smoothstep(4.5, 10.5, p.y));
    alb = alb * (1.0 - smoothstep(5.4, 4.2, p.y) * 0.18);   // grime at the plinth
    // three arched windows climbing the shaft + the door
    var win = 0.0;
    win = max(win, od2_window(phi, p.y, 6.3));
    win = max(win, od2_window(phi, p.y, 8.5));
    win = max(win, od2_window(phi, p.y, 10.5));
    let doorM = od2_window(phi, p.y * 0.72, 3.42);
    alb = mix(alb, vec3f(0.05, 0.05, 0.06), win);
    alb = mix(alb, vec3f(0.06, 0.13, 0.09), doorM);        // colonial green door
    let lit = 0.35 + 0.65 * smoothstep(0.4, 0.9, hash11(floor(p.y / 2.0)));
    emis = emis + vec3f(2.0, 1.25, 0.45) * win * night * lit;
  } else if (m < 2.5) {
    alb = vec3f(0.055, 0.058, 0.068);   // wrought iron
    spec = 0.35;
  } else if (m < 3.5) {
    // lantern glazing: mullions read dark, panes catch sky and hold the lamp
    let mseg = 6.28318 / 8.0;
    let mphi = abs(glsl_mod(phi + mseg * 0.5, mseg) - mseg * 0.5);
    let mull = step(mphi, 0.09);
    let bands = step(abs(p.y - 12.55), 0.06) + step(0.60, abs(p.y - 12.55));
    if (mull + bands > 0.5) {
      alb = vec3f(0.055, 0.058, 0.068);
      spec = 0.35;
    } else {
      alb = vec3f(0.02, 0.025, 0.035);
      spec = 1.2;
      let lampP = vec3f(ic.x, 12.55, ic.y);
      let lampD = length(p - lampP);
      emis = vec3f(6.5, 4.9, 2.6) * exp(-lampD * lampD * 0.9) * (0.15 + 0.85 * uni(4)) * (2.2 + uni(11) * 3.5);
      emis = emis + vec3f(1.4, 1.05, 0.55) * (0.10 + 0.90 * uni(4)) * 0.35;
    }
  } else if (m < 4.5) {
    // copper gone to patina
    let pat = vnoise3(p * 3.1);
    alb = mix(vec3f(0.30, 0.20, 0.12), vec3f(0.24, 0.40, 0.33), smoothstep(0.35, 0.7, pat));
    spec = 0.6;
  } else if (m < 5.5) {
    // clapboard: fine horizontal shadow lines
    alb = vec3f(0.82, 0.80, 0.74);
    let lap = smoothstep(0.10, 0.02, abs(fract(p.y / 0.16) - 0.5) * 0.16);
    alb = alb * (1.0 - lap * 0.13);
    // two warm windows on the seaward face
    let qc = q - vec3f(3.1, 4.45, 0.6);
    let front = step(qc.z, -1.05);
    let wmask = front * step(abs(abs(qc.x) - 0.62), 0.26) * step(abs(qc.y + 0.05), 0.30);
    alb = mix(alb, vec3f(0.05, 0.05, 0.06), wmask);
    emis = emis + vec3f(2.2, 1.35, 0.5) * wmask * night;
  } else if (m < 6.5) {
    alb = vec3f(0.16, 0.15, 0.15) * (0.8 + 0.4 * vnoise(vec2f(p.x * 6.0, p.z * 6.0)));  // shingles
  } else if (m < 7.5) {
    let brick = smoothstep(0.06, 0.02, abs(fract(p.y / 0.14) - 0.5) * 0.14);
    alb = vec3f(0.38, 0.16, 0.11) * (1.0 - brick * 0.35);   // brick chimney
  } else {
    alb = vec3f(0.06, 0.13, 0.09);
  }

  let dif = max(dot(n, sd), 0.0) * smoothstep(-0.05, 0.05, el);
  let ambSky = mix(vec3f(0.05, 0.06, 0.10), vec3f(0.30, 0.34, 0.48), day) * (0.35 + 0.25 * max(n.y, 0.0));
  let sunCol = od2_suncol(el) * 1.4;
  var col = alb * (ambSky + sunCol * dif);
  col = col + alb * vec3f(0.10, 0.12, 0.17) * max(dot(n, vec3f(0.3, 0.8, -0.5)), 0.0) * night;
  let rim = pow(clamp(1.0 + dot(rd, n), 0.0, 1.0), 3.0);
  col = col + sunCol * rim * 0.15 * day;
  col = col + sunCol * pow(max(dot(reflect(rd, n), sd), 0.0), 24.0) * spec * day;

  if (m < 0.5) {
    let surgePh = max(sin(st * 1.4), 0.0);
    let sprayN = vnoise(vec2f(p.x * 1.3 + p.z * 1.1, p.y * 1.8) + vec2f(st * 0.9, -st * 0.6));
    let spray = smoothstep(2.1, 0.9, p.y) * smoothstep(0.35, 0.9, sprayN) * (0.4 + 0.6 * surgePh);
    col = mix(col, vec3f(0.88, 0.90, 0.92) * (0.3 + 0.7 * day + 0.3 * night), clamp(spray, 0.0, 1.0) * 0.45);
  }
  return col + emis;
}

fn visual_od_lh(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x, -uv.y);
  let t = time;
  let st = 1.0 + t * 0.8;

  // the same eye as the world field — the two compose pixel-perfectly
  let bob = sin(t * 0.5) * 0.06;
  let ro = vec3f(0.0, 3.4 + bob, 0.0);
  // wide viewports crop the field vertically — widen the vertical FOV to keep
  // the whole lighthouse in frame at any aspect
  let visH = clamp(frame.resolution.y / max(frame.resolution.x, 1.0), 0.45, 1.0);
  var rd = normalize(vec3f(p.x, (p.y * 0.72) / visH - 0.14 * visH, 1.75));
  let rxy = rotate(rd.xy, sin(t * 0.35) * 0.012);
  rd = normalize(vec3f(rxy.x, rxy.y, rd.z));

  let saz = uni(0);
  let sel = uni(1);
  let sd = normalize(vec3f(cos(saz) * cos(sel), sin(sel), sin(saz) * cos(sel)));

  var col = behind.rgb;

  // the sea is not ours, but it still hides our feet: approximate the water
  // plane so rock below a swell yields to the world behind
  var tSea = 100000.0;
  if (rd.y < -0.001) { tSea = (0.85 - ro.y) / rd.y; }

  let lh = od2_trace(ro, rd);
  var tScene = 100000.0;
  if (lh.z > 0.0) {
    let pr = ro + rd * lh.x;
    let e = 0.03;
    let d0 = od2_sdf(pr).x;
    let nr = normalize(vec3f(
      od2_sdf(pr + vec3f(e, 0.0, 0.0)).x - d0,
      od2_sdf(pr + vec3f(0.0, e, 0.0)).x - d0,
      od2_sdf(pr + vec3f(0.0, 0.0, e)).x - d0));
    var sc = od2_shade(pr, nr, rd, lh.y, sd, t, st);
    sc = mix(sc, vec3f(0.45, 0.33, 0.30) * (0.2 + 0.8 * smoothstep(-0.1, 0.3, uni(1))), clamp(lh.x * 0.004, 0.0, 0.4));
    // let the sea's own surf/foam (already in behind) claim the waterline
    let waterVeil = smoothstep(1.15, 0.45, pr.y);
    col = mix(sc, behind.rgb, waterVeil);
    tScene = lh.x;
  }

  // ── the beam as a force field: hard-edged cone, diagonal energy hatch ──
  let beamI = uni(4);
  if (beamI > 0.01) {
    let ic = od2_ic();
    let lamp = vec3f(ic.x, 12.55, ic.y);
    for (var k = 0; k < 2; k++) {
      let ba = uni(9) + f32(k) * 3.14159;
      let Ld = normalize(vec3f(cos(ba), -0.02, sin(ba)));
      let w0 = ro - lamp;
      let a1 = dot(rd, Ld);
      let b1 = dot(rd, w0);
      let c1 = dot(Ld, w0);
      let den = 1.0 - a1 * a1;
      if (den > 0.0001) {
        let sRay = (a1 * c1 - b1) / den;
        let sBeam = (c1 - a1 * b1) / den;
        if (sRay > 0.0 && sRay < min(tScene, tSea) && sBeam > 1.2) {
          let dd = length((ro + rd * sRay) - (lamp + Ld * sBeam));
          let w = (0.32 + sBeam * 0.035) * (1.0 + uni(11) * 0.7);  // the cone opens with distance — and GROWS at the overlap
          let shell = smoothstep(w, w * 0.78, dd); // hard wall, not a gaussian
          let edge = exp(-pow((dd - w * 0.92) * 5.5, 2.0)) * 0.8;   // bright skin
          // one family of diagonal interference — a field, not a net
          let hatch = pow(0.5 + 0.5 * sin(sBeam * 2.2 - dd * 7.0 - t * 6.0), 3.0);
          let breathe = 0.93 + 0.07 * sin(t * 22.0 + sBeam * 0.7);
          let body = shell * (0.34 + 0.66 * hatch);
          let fall = exp(-sBeam * 0.042);
          // when the beam points at the eye its cross-section is half the sky — dim it
          let headOn = 1.0 - pow(abs(a1), 10.0);
          col = col + mix(vec3f(2.5, 1.95, 1.15), vec3f(3.1, 2.95, 2.45), shell * hatch)
                      * (body + edge) * fall * (1.5 + uni(11) * 2.2) * beamI * breathe * headOn;
        }
      }
    }
    // lamp flare when the beam sweeps you
    let toLamp = lamp - ro;
    let lampDist = length(toLamp);
    let ba0 = uni(9);
    let alignK = pow(abs(dot(vec2f(cos(ba0), sin(ba0)), normalize(ro.xz - lamp.xz))), 24.0);
    let flare = pow(max(dot(rd, toLamp / lampDist), 0.0), 700.0);
    col = col + vec3f(4.5, 3.4, 2.0) * flare * (0.5 + 4.5 * alignK) * beamI;
  }

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = behind.rgb; }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

fn visual_od_flies(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  // fireflies over the island after dark — existence itself read off the whiteboard
  let night = smoothstep(0.02, -0.14, uni(1));
  if (night < 0.02) { return vec4f(0.0); }
  let wind = uni(3);
  var c = vec3f(0.0);
  var a = 0.0;
  for (var i = 0; i < 18; i++) {
    let fi = f32(i);
    let h1 = hash11(fi * 13.7);
    let h2 = hash11(fi * 29.3);
    // hover around the island (screen left), drift on the wind
    var pos = vec2f(-0.55 + (h1 - 0.5) * 0.55, -0.10 + (h2 - 0.5) * 0.38);
    pos.x += sin(time * (0.20 + h1 * 0.25) + fi * 2.4) * 0.06 + wind * 0.02;
    pos.y += cos(time * (0.16 + h2 * 0.22) + fi * 1.7) * 0.045;
    let d2 = dot(uv - pos, uv - pos);
    let blink = smoothstep(0.25, 0.9, 0.5 + 0.5 * sin(time * (0.7 + h1 * 1.3) + fi * 5.0));
    let g = exp(-d2 * 26000.0) * blink;
    c += vec3f(2.2, 1.55, 0.45) * g;
    c += vec3f(0.9, 0.6, 0.15) * exp(-d2 * 2600.0) * blink * 0.35;
    a = max(a, clamp(g * 1.6 + exp(-d2 * 2600.0) * 0.3, 0.0, 1.0));
  }
  return vec4f(c * night, a * night * 0.95);
}

fn cf_portal_pos(i: i32) -> vec2f {
  if (i == 0) { return vec2f(0.073, 0.021); }
  if (i == 1) { return vec2f(-0.179, -0.008); }
  if (i == 2) { return vec2f(0.16, -0.15); }
  if (i == 3) { return vec2f(0.001, 0.19); }
  if (i == 4) { return vec2f(-0.219, -0.196); }
  if (i == 5) { return vec2f(0.357, 0.002); }
  if (i == 6) { return vec2f(-0.309, 0.157); }
  if (i == 7) { return vec2f(0.071, -0.326); }
  if (i == 8) { return vec2f(0.242, 0.259); }
  if (i == 9) { return vec2f(-0.458, -0.11); }
  if (i == 10) { return vec2f(0.442, -0.191); }
  if (i == 11) { return vec2f(-0.177, 0.344); }
  return vec2f(0.0, 0.0);
}
fn cf_style(i: i32) -> i32 {
  if (i == 0) { return 8; }
  if (i == 1) { return 2; }
  if (i == 2) { return 8; }
  if (i == 3) { return 8; }
  if (i == 4) { return 8; }
  if (i == 5) { return 6; }
  if (i == 6) { return 7; }
  if (i == 7) { return 8; }
  if (i == 8) { return 8; }
  if (i == 9) { return 8; }
  if (i == 10) { return 1; }
  if (i == 11) { return 0; }
  return 8;
}
fn cf_hue(i: i32) -> f32 {
  if (i == 0) { return 0.420; }
  if (i == 1) { return 0.980; }
  if (i == 2) { return 0.660; }
  if (i == 3) { return 0.990; }
  if (i == 4) { return 0.160; }
  if (i == 5) { return 0.130; }
  if (i == 6) { return 0.400; }
  if (i == 7) { return 0.760; }
  if (i == 8) { return 0.960; }
  if (i == 9) { return 0.250; }
  if (i == 10) { return 0.050; }
  if (i == 11) { return 0.720; }
  return 0.5;
}

fn cf_stars(p: vec2f, t: f32) -> vec3f {
  var c = vec3f(0.008, 0.007, 0.016);
  c += vec3f(0.05, 0.025, 0.09) * smoothstep(0.4, 0.9, fbm(p * 1.5 + vec2f(t * 0.004, 0.0), 4));
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (16.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let fp = fract(sp) - 0.5;
    let tw = 0.5 + 0.5 * sin(t * (0.5 + h * 1.4) + h * 40.0);
    c += vec3f(0.8, 0.75, 0.95) * step(0.985, h) * smoothstep(0.24, 0.03, length(fp)) * tw * (1.1 - fl * 0.4);
  }
  return c;
}

fn visual_cf_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mp = vec2f(uni(0), uni(1));     // cursor in field coords

  // ── the room: stars seen through curved space (your cursor is a lens) ──
  var p = uv;
  let md = uv - mp;
  let mr2 = max(dot(md, md), 0.002);
  p -= md * (0.010 / mr2) * smoothstep(0.9, 0.2, length(md));
  var col = cf_stars(p, t);

  // warm hearth-light from below — this is a cafe, not a void
  col += vec3f(0.10, 0.055, 0.02) * pow(max(0.0, uv.y + 0.2), 2.0) * (0.8 + 0.2 * sin(t * 0.7));

  // ── every cartridge on the shelf, newest nearest the center ──
  for (var i = 0; i < 12; i++) {
    let ctr = cf_portal_pos(i);
    let d = length(uv - ctr);
    let R = 0.088;
    let hov = uni(2 + i);                          // 0..1 hover bloom from the hook
    let rr = R * (1.0 + hov * 0.12);
    if (d < rr) {
      let q = (uv - ctr) / rr;                     // -1..1 inside the disc
      var g = vec3f(0.0);
      let st = cf_style(i);
      if (st == 0) {
        // FABRIC — a lens wandering through stars
        var pp = q * 2.0;
        let lc = vec2f(sin(t * 0.6) * 0.5, cos(t * 0.47) * 0.4);
        let ld = pp - lc;
        pp -= ld * (0.16 / max(dot(ld, ld), 0.02));
        g = cf_stars(pp * 1.6, t) * 2.2;
        g += vec3f(0.5, 0.9, 1.1) * exp(-dot(ld, ld) * 14.0) * 0.4;
      } else if (st == 1) {
        // ORRERY — three worlds around a coal
        g = vec3f(0.02, 0.015, 0.03);
        g += vec3f(3.0, 1.7, 0.5) * exp(-dot(q, q) * 30.0);
        for (var k = 1; k <= 3; k++) {
          let fk = f32(k);
          let a = t * (0.9 - fk * 0.18) + fk * 2.1;
          let pp = q - vec2f(cos(a), sin(a)) * (0.22 + fk * 0.17);
          var pc = vec3f(0.45, 0.5, 0.65);
          if (k == 2) { pc = vec3f(0.2, 0.45, 0.8); }
          if (k == 3) { pc = vec3f(0.8, 0.5, 0.25); }
          g += pc * exp(-dot(pp, pp) * 260.0) * 1.6;
        }
      } else if (st == 2) {
        // GARNET — the crystal
        let qa = rotate(q, t * 0.4);
        let cd = abs(qa.x) * 0.866 + abs(qa.y) * 0.5;
        let inside = smoothstep(0.62, 0.58, max(cd, abs(qa.y)));
        let facet = 0.6 + 0.4 * sin(qa.x * 9.0 + qa.y * 7.0 + t * 0.8);
        g = mix(vec3f(0.02, 0.01, 0.02), vec3f(0.75, 0.18, 0.25) * facet, inside);
        g += vec3f(1.6, 0.9, 0.7) * pow(max(0.0, facet - 0.75) * 4.0, 2.0) * inside;
      } else if (st == 3) {
        // ONE DAY — a sky that keeps its whole day
        let ph = fract(t * 0.05);
        let el = sin(ph * 6.28318) * 0.8;
        let day = smoothstep(-0.2, 0.4, el);
        g = mix(vec3f(0.02, 0.02, 0.06), vec3f(0.25, 0.5, 0.8), day * (0.5 - q.y * 0.5));
        g = mix(g, vec3f(0.9, 0.4, 0.15), smoothstep(0.3, 0.0, abs(el)) * max(0.0, -q.y + 0.2) * 0.9);
        let sun = vec2f(cos(ph * 6.28318 - 1.57) * 0.6, -el * 0.55 + 0.1);
        g += vec3f(3.0, 2.0, 0.9) * exp(-dot(q - sun, q - sun) * 60.0) * max(day, 0.15);
        if (q.y > 0.25) { g = mix(g, g * vec3f(0.5, 0.6, 0.8), 0.6); }   // the sea below
      } else if (st == 4) {
        // SAIL — one boat, one sea
        g = mix(vec3f(0.35, 0.5, 0.65), vec3f(0.05, 0.14, 0.2), smoothstep(-0.1, 0.5, q.y));
        let w = sin(q.x * 9.0 + t * 1.4) * 0.05;
        g = mix(g, vec3f(0.03, 0.10, 0.14), smoothstep(w + 0.02, w - 0.02, -q.y + 0.1) * 0.0 + smoothstep(w - 0.02, w + 0.06, q.y - 0.05));
        let sail = max(max(-(q.x + 0.05) * 3.0, q.y + 0.15), (q.x * 0.9 + q.y * 0.8) - 0.28);
        g = mix(g, vec3f(1.0, 0.96, 0.88), smoothstep(0.02, -0.02, sail));
      } else if (st == 5) {
        // SOLSTICE — a sun you carry over a valley
        g = vec3f(0.03, 0.04, 0.09);
        let sp = vec2f(sin(t * 0.5) * 0.45, -0.3 + cos(t * 0.5) * 0.12);
        g += vec3f(3.2, 2.2, 0.9) * exp(-dot(q - sp, q - sp) * 40.0);
        let hill = q.y - (0.25 + 0.15 * sin(q.x * 3.0 + 1.0));
        let lit = max(0.0, 1.0 - length(q - sp) * 1.4);
        g = mix(g, mix(vec3f(0.03, 0.05, 0.02), vec3f(0.15, 0.3, 0.08), lit), smoothstep(-0.02, 0.02, hill));
      } else if (st == 6) {
        // TIDERUNNER — wind over water
        let band = sin(q.y * 14.0 - t * 1.1 + sin(q.x * 4.0) * 0.7);
        g = mix(vec3f(0.05, 0.13, 0.17), vec3f(0.12, 0.25, 0.3), 0.5 + 0.5 * band);
        g += vec3f(0.8, 0.85, 0.85) * pow(max(0.0, band - 0.8) * 5.0, 2.0) * 0.4;
        let bt = q - vec2f(sin(t * 0.4) * 0.4, 0.0);
        g += vec3f(0.9, 0.85, 0.75) * exp(-dot(bt, bt) * 300.0) * 1.2;
      } else if (st == 7) {
        // SIGNAL — a television waiting for a word
        let sn = hash21(floor(q * 24.0) + floor(t * 9.0));
        g = vec3f(sn * 0.5);
        g += vec3f(0.3, 1.0, 0.45) * exp(-dot(q, q) * 8.0) * (0.28 + 0.14 * sin(t * 2.0));
        g *= 0.82 + 0.18 * sin(q.y * 60.0 - t * 8.0);
      } else {
        // a young world — a banded seed-planet in its own hue
        let hue = cf_hue(i);
        let cA = 0.5 + 0.5 * cos(6.2831 * (hue + vec3f(0.0, 0.33, 0.67)));
        g = cA * (0.22 + 0.5 * fbm3(q * 3.0 + vec2f(t * 0.08, f32(i) * 3.7)));
        g += cA * 0.4 * smoothstep(0.6, 1.0, 1.0 - abs(q.y * 2.2 + 0.3 * sin(q.x * 3.0 + t * 0.4)));
        let mn = q - vec2f(cos(t * 0.5 + f32(i) * 1.9), sin(t * 0.5 + f32(i) * 1.9) * 0.6) * 0.78;
        g += vec3f(0.85) * exp(-dot(mn, mn) * 260.0);
        g *= 0.85 + 0.3 * (1.0 - length(q));
      }
      // glass edge + hover bloom
      let edge = smoothstep(1.0, 0.86, length(q));
      col = mix(col, g, edge);
      col += vec3f(1.2, 0.85, 0.4) * exp(-pow((length(q) - 0.97) * 9.0, 2.0)) * (0.25 + hov * 1.3);
    } else {
      // halo when hovered
      col += vec3f(1.0, 0.7, 0.3) * exp(-pow((d - rr) * 22.0, 2.0)) * hov * 0.8;
    }
  }

  // the cursor itself — a soft ember
  col += vec3f(1.4, 0.9, 0.4) * exp(-dot(uv - mp, uv - mp) * 900.0) * 0.8;

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

const HL_HOR: f32 = 336.0;

fn hl_moonness(ph: f32) -> f32 { return 0.5 - 0.5 * cos(6.2831853 * ph); }

// sky + orb, callable so the lake can mirror it
fn hl_sky(p: vec2f, sun: vec2f, m: f32, t: f32, a: f32) -> vec3f {
  let up = clamp(1.0 - p.y / HL_HOR, 0.0, 1.0);
  // day palette → night palette
  let dayZen = vec3f(0.16, 0.34, 0.62);
  let dayHor = vec3f(0.95, 0.62, 0.32);
  let nightZen = vec3f(0.015, 0.020, 0.055);
  let nightHor = vec3f(0.05, 0.06, 0.13);
  var col = mix(mix(dayHor, dayZen, pow(up, 0.6)), mix(nightHor, nightZen, pow(up, 0.6)), m);

  // light breathes from wherever the orb is (screen-round despite the
  // vertical compression that fits the painting to wide viewports)
  let rel = vec2f(p.x - sun.x, (p.y - sun.y) / a);
  let d = length(rel);
  let warm = mix(vec3f(1.1, 0.7, 0.35), vec3f(0.55, 0.62, 0.80), m);
  col += warm * exp(-d * 0.012) * mix(0.5, 0.28, m);

  // the orb: gold sun ↔ silver moon with craters and a crescent bite
  let r = 26.0;
  if (d < r) {
    var oc = mix(vec3f(3.2, 2.4, 1.1), vec3f(1.6, 1.7, 1.9), m);
    // craters surface only as it becomes moon
    let cr = vnoise(rel * 0.22 + 7.0);
    oc *= 1.0 - m * 0.35 * smoothstep(0.45, 0.8, cr);
    // crescent: a dark disk slides across as moonness grows past half
    let bite = length(rel - vec2f(r * 0.85 * smoothstep(0.35, 1.0, m), -4.0));
    if (m > 0.35 && bite < r * 0.98) { oc *= 0.12; }
    col = oc;
  }
  col += warm * exp(-max(d - r, 0.0) * 0.05) * mix(0.9, 0.55, m);   // corona

  // stars belong to the moon
  if (m > 0.25) {
    let sp2 = p * 0.14;
    let cell = floor(sp2);
    let st = hash21(cell);
    if (st > 0.975 && p.y < HL_HOR - 10.0) {
      let d2 = length(fract(sp2) - 0.5);
      let tw = 0.5 + 0.5 * sin(t * 3.0 + st * 40.0);
      col += vec3f(0.9, 0.92, 1.0) * smoothstep(0.16, 0.02, d2) * tw * smoothstep(0.25, 0.6, m);
    }
  }
  return col;
}

fn hl_ridge(x: f32, seed: f32, amp: f32, base: f32) -> f32 {
  return base - amp * (fbm3(vec2f(x * 0.008 + seed, seed)) - 0.25);
}

fn visual_helios(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let asp = 1.0;   // contain-fit shows the whole painting
  let p = vec2f((uv.x + 1.0) * 256.0, (uv.y * asp + 1.0) * 256.0);
  let t = time;
  var sun = vec2f(uni(0), uni(1));
  if (sun.x < 1.0) { sun = vec2f(150.0, 120.0); }        // pre-hook default: morning
  let m = hl_moonness(uni(2));
  let gold = uni(4);

  var col: vec3f;
  let LAKE = 424.0;

  if (p.y < LAKE) {
    col = hl_sky(p, sun, m, t, asp);

    // three ridgelines, lit from wherever the orb hangs
    let warm = mix(vec3f(1.0, 0.75, 0.45), vec3f(0.5, 0.58, 0.75), m);
    let sunSide = clamp(1.0 - abs(p.x - sun.x) / 360.0, 0.0, 1.0);
    let r1 = hl_ridge(p.x, 3.0, 90.0, HL_HOR - 40.0);
    let r2 = hl_ridge(p.x, 11.0, 60.0, HL_HOR - 6.0);
    let r3 = hl_ridge(p.x, 27.0, 34.0, HL_HOR + 26.0);
    if (p.y > r3 && p.y < LAKE) {
      col = mix(vec3f(0.10, 0.16, 0.08), vec3f(0.012, 0.02, 0.03), m);
      col += warm * 0.35 * sunSide * smoothstep(r3 + 14.0, r3, p.y);  // lit brow
      col *= 0.9 + 0.2 * vnoise(p * 0.12);
    } else if (p.y > r2) {
      col = mix(vec3f(0.13, 0.20, 0.11), vec3f(0.02, 0.03, 0.05), m);
      col += warm * 0.30 * sunSide * smoothstep(r2 + 12.0, r2, p.y);
      col *= 0.9 + 0.2 * vnoise(p * 0.1 + 5.0);
    } else if (p.y > r1) {
      col = mix(vec3f(0.17, 0.25, 0.15), vec3f(0.03, 0.045, 0.07), m);
      col += warm * 0.28 * sunSide * smoothstep(r1 + 10.0, r1, p.y);
      col *= 0.9 + 0.2 * vnoise(p * 0.08 + 9.0);
    }

    // fireflies rise at night over the near meadow
    if (m > 0.5 && p.y > HL_HOR) {
      let fp2 = p * 0.06 + vec2f(0.0, t * 0.06);
      let fc = floor(fp2);
      let fh = hash21(fc + 31.0);
      if (fh > 0.955) {
        let fd = length(fract(fp2) - 0.5);
        let blink = pow(0.5 + 0.5 * sin(t * 2.5 + fh * 60.0), 3.0);
        col += vec3f(0.9, 1.4, 0.3) * smoothstep(0.10, 0.02, fd) * blink * (m - 0.5) * 2.4;
      }
    }
  } else {
    // the lake: the whole sky again, upside down and breathing
    let ry = LAKE - (p.y - LAKE) * 1.9;
    let wob = vnoise(vec2f(p.x * 0.05, p.y * 0.3 - t * 0.8)) - 0.5;
    var rp = vec2f(p.x + wob * 9.0, ry + wob * 5.0);
    col = hl_sky(rp, sun, m, t, asp) * mix(0.62, 0.5, m);
    col += vec3f(0.04, 0.05, 0.06) * (0.5 + wob);

    // moon-glitter: when the moon is out and its face lies on the lake,
    // the water sparkles along the reflection path
    let refY = LAKE + (LAKE - sun.y) / 1.9;
    let mglow = smoothstep(0.35, 0.75, m) * smoothstep(620.0, 500.0, refY);
    if (mglow > 0.01) {
      let depth = clamp((p.y - LAKE) / (512.0 - LAKE), 0.0, 1.0);
      let spread = 16.0 + 100.0 * depth;                 // the glade widens toward you
      let path = smoothstep(spread, spread * 0.2, abs(p.x - sun.x + wob * 14.0));
      // glint cells — little horizontal flecks, twinkling out of phase
      let gp = vec2f(p.x * 0.12, p.y * 0.3 - t * 0.55);
      let gh = hash21(floor(gp));
      let gd = length((fract(gp) - 0.5) * vec2f(0.9, 2.2));
      let flash = pow(0.5 + 0.5 * sin(t * (2.0 + gh * 6.0) + gh * 47.0), 6.0);
      let glint = smoothstep(0.45, 0.05, gd) * step(0.80, gh) * flash;
      col += vec3f(1.05, 1.12, 1.30) * glint * path * mglow * 2.8;   // the sparkle
      col += vec3f(0.35, 0.40, 0.55) * path * mglow * 0.20 * (0.6 + wob);  // silver sheen
      col += vec3f(1.30, 0.95, 0.40) * path * gold * 0.55 * (0.7 + wob);   // the invitation
    }
  }

  // hold feedback: a slow pulse ring while the orb is aging
  if (uni(3) > 0.01) {
    let ring = abs(length(vec2f(p.x - sun.x, (p.y - sun.y) / asp)) - (30.0 + fract(t * 0.8) * 26.0));
    col += vec3f(0.8, 0.8, 0.7) * uni(3) * smoothstep(3.0, 0.0, ring) * 0.5;
  }

  // the moon's reflection noticed you: the whole valley breathes gold
  if (gold > 0.01) {
    let breath = 0.5 + 0.5 * sin(t * 3.2);
    col += vec3f(1.05, 0.78, 0.28) * gold * (0.10 + 0.11 * breath) * (1.25 - 0.5 * length(uv));
  }

  col *= 1.0 - 0.35 * pow(length(uv), 3.0);
  return vec4f(col, 1.0);
}

// a moon whose bite orbits with phase — six unique crescents, one per stone
fn se_seg(p: vec2f, a: vec2f, b: vec2f) -> f32 {
  let pa = p - a;
  let ba = b - a;
  let h = clamp(dot(pa, ba) / max(dot(ba, ba), 1e-6), 0.0, 1.0);
  return length(pa - ba * h);
}

fn se_moon(rel: vec2f, r: f32, ph: f32) -> f32 {
  let d = length(rel);
  let disc = smoothstep(r, r * 0.9, d);
  let bc = vec2f(cos(6.2831853 * ph), sin(6.2831853 * ph)) * r * 0.72;
  let bite = smoothstep(r * 0.98, r * 0.84, length(rel - bc));
  return disc * (1.0 - bite * 0.93);
}

fn visual_selene(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let asp = 1.0;   // contain-fit shows the whole deep
  let t = time;
  let mc = vec2f(uni(0), uni(1));
  let ph = uni(2);
  let win = uni(10);
  let nvy = clamp(uv.y * asp, -1.3, 1.3);

  // ── the drowned sky ──
  var col = mix(vec3f(0.010, 0.018, 0.038), vec3f(0.030, 0.055, 0.095), 0.5 - 0.5 * nvy);
  // caustic light from the lake's surface far above
  let ca = sin(uv.x * 9.0 + sin(nvy * 5.0 + t * 0.4) * 1.5 + t * 0.5);
  col += vec3f(0.028, 0.05, 0.07) * (0.5 + 0.5 * ca) * 0.5;
  // drowned stars, dim and wavering
  let sp = uv * 14.0 + vec2f(sin(t * 0.2 + nvy * 2.0) * 0.05, 0.0);
  let sh = hash21(floor(sp));
  if (sh > 0.972) {
    col += vec3f(0.35, 0.45, 0.65) * smoothstep(0.2, 0.03, length(fract(sp) - 0.5)) * (0.4 + 0.4 * sin(t * 1.5 + sh * 40.0));
  }
  // motes rising toward the surface
  let bp = vec2f(uv.x * 10.0, nvy * 6.0 - t * 0.35);
  let bh = hash21(floor(bp));
  if (bh > 0.955) {
    col += vec3f(0.08, 0.13, 0.17) * smoothstep(0.16, 0.02, length(fract(bp) - 0.5));
  }

  // ── six phase-stones ringing the deep ──
  let R = 0.68 / asp;
  for (var i = 0; i < 6; i++) {
    let fi = f32(i);
    let a = 6.2831853 * fi / 6.0 - 1.5707963;
    let c = vec2f(cos(a), sin(a)) * R;
    let rel = uv - c;
    if (abs(rel.x) < 0.22 && abs(rel.y) < 0.22) {
      let lit = clamp(uni(4 + i), 0.0, 1.0);
      let stone = se_moon(rel, 0.075, fi / 6.0);
      let scol = mix(vec3f(0.15, 0.17, 0.23), vec3f(1.35, 1.30, 1.05), lit);
      col = mix(col, scol, stone * (0.4 + 0.6 * lit));
      // faint carved seat under each stone
      col += vec3f(0.05, 0.06, 0.09) * exp(-dot(rel, rel) * 90.0) * (1.0 - lit);
      // when your moon's phase matches this stone, its rim wakes amber
      let dp = abs(fract(ph - fi / 6.0 + 0.5) - 0.5);
      let phMatch = smoothstep(0.085, 0.03, dp) * (1.0 - lit);
      col += vec3f(1.0, 0.72, 0.28) * exp(-pow((length(rel) - 0.085) * 26.0, 2.0)) * phMatch * (0.6 + 0.4 * sin(t * 5.0));
      // lit stones hold a silver halo
      col += vec3f(0.85, 0.85, 0.6) * exp(-dot(rel, rel) * 150.0) * lit * 0.9;
    }
  }

  // ── the way home: when the ring is lit, the MOON-TREE grows ──
  let wt = clamp(uni(11), 0.0, 1.0);
  if (wt > 0.005) {
    let g1 = clamp(wt * 3.0, 0.0, 1.0);
    let g2 = clamp(wt * 3.0 - 1.0, 0.0, 1.0);
    let g3 = clamp(wt * 3.0 - 2.0, 0.0, 1.0);
    let p0 = vec2f(0.0, 0.42);
    let p1 = p0 + vec2f(-0.03, -0.20) * g1;
    let p2 = p1 + vec2f(0.05, -0.19) * g2;
    let p3 = p2 + vec2f(-0.02, -0.16) * g3;
    var td = se_seg(uv, p0, p1) - 0.022 * (0.6 + 0.4 * g1);
    td = min(td, se_seg(uv, p1, p2) - 0.016);
    td = min(td, se_seg(uv, p2, p3) - 0.011);
    for (var bi = 0; bi < 5; bi++) {
      let fb = f32(bi);
      let gb = clamp(wt * 4.0 - 2.2 - fb * 0.25, 0.0, 1.0);
      if (gb > 0.01) {
        let root = mix(p2, p3, 0.2 + fb * 0.2);
        let ang = -1.5707963 + (fb - 2.0) * 0.55 + sin(t * 0.4 + fb) * 0.04;
        let tip = root + vec2f(cos(ang), sin(ang)) * (0.14 + fb * 0.014) * gb;
        td = min(td, se_seg(uv, root, tip) - 0.006);
        col += vec3f(1.15, 1.10, 0.75) * exp(-dot(uv - tip, uv - tip) * 900.0) * gb * (0.8 + 0.3 * sin(t * 2.0 + fb * 2.1));
        col += vec3f(0.55, 0.60, 0.45) * exp(-dot(uv - tip, uv - tip) * 120.0) * gb * 0.35;
      }
    }
    if (td < 0.0) { col = mix(vec3f(0.72, 0.68, 0.58), vec3f(0.35, 0.30, 0.24), clamp((uv.y - p2.y) * 2.0, 0.0, 1.0)); }
    col += vec3f(1.0, 0.85, 0.45) * exp(-dot(uv - p3, uv - p3) * 9.0) * wt * 0.30;
    col += vec3f(0.9, 0.75, 0.35) * wt * (0.035 + 0.03 * sin(t * 2.1));
  }

  // ── the drowned moon you carry ──
  let mr = uv - mc;
  let held = se_moon(mr, 0.055, ph);
  col = mix(col, vec3f(1.55, 1.55, 1.35), held);
  col += vec3f(0.45, 0.5, 0.68) * exp(-dot(mr, mr) * 55.0) * (0.45 + 0.4 * uni(3));

  col *= 1.0 - 0.4 * pow(length(vec2f(uv.x, nvy)) * 0.72, 3.0);
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
}

// state encoding: r = (1-u)*A*0.35, g = v*B, b = art (display only, never decoded)
// A,B are palette amplitudes (>= 0.35 so state stays decodable)
fn sg_dec(c: vec4f, A: f32, B: f32) -> vec2f {
  return vec2f(clamp(c.x, 0.0, 1.0) / (0.35 * max(A, 0.35)), clamp(c.y, 0.0, 1.0) / max(B, 0.35));
}
// one thermostat's published feed bias, read from the frame
fn sg_bias(n: vec2f, p: vec2f) -> f32 {
  let c = prevAt(n * 64.0 + vec2f(32.0, 32.0) - p);
  return (clamp(c.y, 0.0, 1.0) / 0.12 - 0.5) / 20.0;
}
fn sg_isCtrl(p: vec2i) -> bool {
  let m = p % vec2i(64, 64);
  return m.x == 32 && m.y == 32;
}
// neighbor state; controller pixels are not chemistry — substitute self
fn sg_nb(o: vec2f, cSelf: vec2f, A: f32, B: f32) -> vec2f {
  let np = vec2i(pix() + o);
  if (sg_isCtrl(np)) { return cSelf; }
  return sg_dec(prevAt(o), A, B);
}

fn visual_sg_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let A = clamp(uni(5), 0.35, 1.0);
  let B = clamp(uni(6), 0.35, 1.0);
  let Cc = clamp(uni(7), 0.0, 1.2);
  let booted = uni(9) > 0.5;
  let p = pix();

  // ── CONTROLLER pixels: measure, integrate, publish. 1px each, one per 64px cell ──
  if (sg_isCtrl(vec2i(p))) {
    if (!booted) { return vec4f(0.10 * 0.25, 0.5 * 0.12, 0.0, 1.0); }
    var OFS = array<vec2f, 8>(
      vec2f(0.0, 16.0), vec2f(0.0, -16.0), vec2f(16.0, 0.0), vec2f(-16.0, 0.0),
      vec2f(20.0, 20.0), vec2f(-20.0, 20.0), vec2f(20.0, -20.0), vec2f(-20.0, -20.0));
    var act = 0.0;
    for (var j = 0; j < 8; j++) { act += sg_dec(prevAt(OFS[j]), A, B).y; }
    act /= 8.0;
    let s = prevHere();
    let prevAct = clamp(s.x, 0.0, 1.0) / 0.25;
    let prevBias = (clamp(s.y, 0.0, 1.0) / 0.12 - 0.5) / 20.0;
    let prevLock = clamp(s.z, 0.0, 1.0) / 0.2;
    let sm = mix(prevAct, act, 0.04);
    let TARGET = 0.10;
    let bias = clamp(prevBias + (TARGET - sm) * 0.00045, -0.024, 0.024);
    let err = abs(TARGET - sm) / TARGET;
    let lock = mix(prevLock, clamp(1.0 - err, 0.0, 1.0), 0.006);
    return vec4f(sm * 0.25, (0.5 + bias * 20.0) * 0.12, lock * 0.2, 1.0);
  }

  let ax = max(abs(uv.x), abs(uv.y));

  // ── BEZEL: the set itself. Inner dead frame is the reaction's boundary ──
  if (ax > 0.94) {
    if (ax < 0.955) { return vec4f(0.0, 0.0, 0.0, 1.0); }
    var c = vec3f(0.055, 0.038, 0.028) * (0.85 + 0.3 * hash21(floor(p / 3.0)));
    // LED rail: one thermostat's verdict per column — amber hunts, green holds
    if (uv.y < -0.955) {
      let cl = floor((p - vec2f(0.0, 130.0)) / 64.0) * 64.0 + vec2f(32.0, 32.0);
      let cc = prevAt(cl - p);
      let lock = clamp(cc.z, 0.0, 1.0) / 0.2;
      let act = clamp(cc.x, 0.0, 1.0) / 0.25;
      let lx = p.x - cl.x;
      let led = exp(-lx * lx / 40.0);
      let hunting = 0.6 + 0.4 * sin(time * 6.0 + cl.x * 0.13);
      let lcol = mix(vec3f(1.0, 0.55, 0.15) * hunting, vec3f(0.25, 1.0, 0.4), clamp(lock * 1.15, 0.0, 1.0));
      c += lcol * led * (0.5 + 0.5 * clamp(act * 3.0, 0.0, 1.0)) * 2.2;
    }
    c += vec3f(0.4, 0.9, 0.5) * uni(8) * 0.12;   // retune flash
    if (c.x != c.x || c.y != c.y || c.z != c.z) { c = vec3f(0.02); }
    return vec4f(clamp(c, vec3f(0.0), vec3f(8.0)), 1.0);
  }

  // ── SUBSTRATE: Gray-Scott on the previous frame ──
  if (!booted) {
    // first light: sparse seeds in an empty universe
    let h = hash21(floor(p / 9.0));
    let v0 = select(0.0, 0.85, h > 0.978);
    return vec4f(0.0, v0 * B, 0.0, 1.0);
  }
  let cs = sg_dec(prevHere(), A, B);
  var la = 0.0;
  var lv = 0.0;
  var NO = array<vec2f, 4>(vec2f(2.0, 0.0), vec2f(-2.0, 0.0), vec2f(0.0, 2.0), vec2f(0.0, -2.0));
  var ND = array<vec2f, 4>(vec2f(2.0, 2.0), vec2f(2.0, -2.0), vec2f(-2.0, 2.0), vec2f(-2.0, -2.0));
  for (var j = 0; j < 4; j++) {
    let n1 = sg_nb(NO[j], cs, A, B);
    la += 0.2 * (n1.x - cs.x); lv += 0.2 * (n1.y - cs.y);
    let n2 = sg_nb(ND[j], cs, A, B);
    la += 0.05 * (n2.x - cs.x); lv += 0.05 * (n2.y - cs.y);
  }
  // the control layer, read through the frame — blended between the four
  // nearest thermostats so control varies smoothly across the picture
  let pc = (p - vec2f(32.0, 32.0)) / 64.0;
  let b0 = floor(pc);
  let bf = pc - b0;
  let bias = mix(
    mix(sg_bias(b0, p), sg_bias(b0 + vec2f(1.0, 0.0), p), bf.x),
    mix(sg_bias(b0 + vec2f(0.0, 1.0), p), sg_bias(b0 + vec2f(1.0, 1.0), p), bf.x), bf.y);

  let F = clamp(uni(3) + bias, 0.004, 0.095);
  let k = clamp(uni(4), 0.03, 0.08);
  let u = 1.0 - cs.x;
  let v = cs.y;
  let uvv = u * v * v;
  var un = clamp(u + (1.0 * (-la) - uvv + F * (1.0 - u)), 0.0, 1.0);
  var vn = clamp(v + (0.5 * lv + uvv - (F + k) * v), 0.0, 1.0);

  // touch pours reagent — you can seed reality by hand
  if (uni(2) > 0.5) {
    let dm = uv - vec2f(uni(0), uni(1));
    vn = max(vn, 0.9 * exp(-dot(dm, dm) * 2200.0));
  }

  // art channel: glow from concentration + the retune ripple
  let pl = uni(8);
  var art = pow(vn, 1.5) * 3.0 * Cc;
  if (pl > 0.001) {
    let dc = abs(length(uv) - (1.0 - pl) * 1.6);
    art += pl * 1.2 * exp(-dc * dc * 160.0);
  }
  var outc = vec3f((1.0 - un) * A * 0.35, vn * B, art);
  if (outc.x != outc.x || outc.y != outc.y || outc.z != outc.z) { outc = vec3f(0.0); }
  return vec4f(clamp(outc, vec3f(0.0), vec3f(4.0)), 1.0);
}

stepHooks.code:
try {
  const wd = sim.worldData
  if (!wd.__tr) wd.__tr = {
    t: 0, score: 0, best: 0, hull: 3, cargo: 0, inv: 2,
    head: -1.57, trim: 0.5, vx: 0, vy: 0,
    windA: 0.6, windV: 6.0, over: 0, boom: 0.4, heel: 0,
    raftT: 3, deliverGlow: 0
  }
  const G = wd.__tr
  G.t += dt
  let boat = null, sea = null, hud = null, light = null, whirl = null
  const rocks = [], squalls = [], rafts = []
  for (const f of sim.fields.values()) {
    const n = f.name || ''
    if (n.startsWith('Sloop')) boat = f
    else if (n.startsWith('Sea')) sea = f
    else if (n.startsWith('Rock')) rocks.push(f)
    else if (n.startsWith('Squall')) squalls.push(f)
    else if (n.startsWith('Raft')) rafts.push(f)
    else if (n.startsWith('Beacon')) light = f
    else if (n.startsWith('Maelstrom')) whirl = f
    else if (n.startsWith('TIDERUNNER')) hud = f
  }
  if (boat && sea) {
    const T = f => f.transform
    G.inv = Math.max(0, G.inv - dt)
    G.deliverGlow = Math.max(0, G.deliverGlow - dt * 0.8)

    // ── living wind: slow veer + strength swell ──
    G.windA += (Math.sin(G.t * 0.043 + 1.3) * 0.0016 + Math.sin(G.t * 0.011) * 0.0022) * 60 * dt
    G.windV = 5.6 + Math.sin(G.t * 0.031) * 1.6 + Math.min(G.score * 0.04, 2.0)
    const wdx = Math.cos(G.windA), wdy = Math.sin(G.windA)

    // squalls drift downwind and wrap; gust if the boat is inside
    let gust = 1.0
    for (const s of squalls) {
      T(s).x += wdx * 9 * dt; T(s).y += wdy * 9 * dt
      if (T(s).x < -80) T(s).x += 672; if (T(s).x > 592) T(s).x -= 672
      if (T(s).y < -80) T(s).y += 672; if (T(s).y > 592) T(s).y -= 672
      T(s).vx = 0; T(s).vy = 0
      const d = Math.hypot(T(boat).x - T(s).x, T(boat).y - T(s).y)
      if (d < 78) gust = Math.max(gust, 1.55 + 0.35 * Math.sin(G.t * 1.9))
      s.visualParams = [wdx, wdy, 1, 0]
    }

    // ── helm & trim ──
    const fwd = [Math.cos(G.head), Math.sin(G.head)]
    const fwdSpd = G.vx * fwd[0] + G.vy * fwd[1]
    const turnRate = (1.55 - G.cargo * 0.10) * (0.35 + Math.min(Math.abs(fwdSpd) / 55, 1.0))
    if (wd.key_a) G.head -= turnRate * dt
    if (wd.key_d) G.head += turnRate * dt
    if (wd.key_w) G.trim = Math.min(1, G.trim + 0.9 * dt)
    if (wd.key_s) G.trim = Math.max(0.05, G.trim - 0.9 * dt)
    if (wd.key_space) G.trim = Math.max(0.05, G.trim - 3.5 * dt)   // let fly

    // ── sail physics: no-go zone, trim matching, heel ──
    const windFrom = G.windA + Math.PI
    let off = G.head - windFrom
    while (off > Math.PI) off -= 2 * Math.PI
    while (off < -Math.PI) off += 2 * Math.PI
    const offA = Math.abs(off)                       // 0 = in irons, PI = dead run
    const smoothstep = (a, b, x) => { const u = Math.min(1, Math.max(0, (x - a) / (b - a))); return u * u * (3 - 2 * u) }
    const eff = smoothstep(0.42, 0.85, offA) * (0.55 + 0.45 * Math.sin(Math.min(offA, 2.1)))
    const idealTrim = Math.min(1, Math.max(0.15, offA / Math.PI))
    const trimPen = 1 - Math.min(Math.abs(G.trim - idealTrim) * 2.0, 0.85)
    const wPow = G.windV * gust
    const drive = wPow * 13.5 * eff * trimPen
    G.heel = Math.min(1.45, (wPow / 6) * G.trim * Math.sin(Math.min(offA, 2.4)) * 1.05) * (off > 0 ? 1 : -1)

    // broach: over-canvassed too long → rounded up, cargo overboard
    if (Math.abs(G.heel) > 1.0) G.over += dt; else G.over = Math.max(0, G.over - dt * 2)
    if (G.over > 0.9) {
      G.over = 0; G.trim = 0.25
      G.head = windFrom + (off > 0 ? 0.5 : -0.5)
      G.vx *= 0.35; G.vy *= 0.35
      if (G.cargo > 0) {
        G.cargo--
        const r = rafts.find(q => q.visualParams && q.visualParams[3] > 0.5)
        if (r) { T(r).x = T(boat).x - fwd[0] * 30; T(r).y = T(boat).y - fwd[1] * 30; r.visualParams = [Math.random(), 0, 0, 0]; r.properties.set('ttl', 60) }
      }
    }

    // ── integrate ──
    G.vx += fwd[0] * drive * dt; G.vy += fwd[1] * drive * dt
    const dragK = 0.62 + G.cargo * 0.05
    G.vx -= G.vx * dragK * dt; G.vy -= G.vy * dragK * dt
    // leeway + wave push
    G.vx += -fwd[1] * G.heel * 6.5 * dt; G.vy += fwd[0] * G.heel * 6.5 * dt
    G.vx += wdx * 2.2 * dt; G.vy += wdy * 2.2 * dt
    // maelstrom pull
    if (whirl) {
      const mx = T(whirl).x - T(boat).x, my = T(whirl).y - T(boat).y
      const md = Math.hypot(mx, my) || 1
      if (md < 165) {
        const pull = 5200 / (md * md)
        G.vx += (mx / md) * pull; G.vy += (my / md) * pull
        G.vx += (-my / md) * pull * 0.55; G.vy += (mx / md) * pull * 0.55
        if (md < 26 && G.inv <= 0) { hullHit(mx, my, md, 1) }
      }
      whirl.visualParams = [1, 0, 0, 0]
    }
    const spd = Math.hypot(G.vx, G.vy)
    const cap2 = 95 + 20 * (gust - 1)
    if (spd > cap2) { G.vx *= cap2 / spd; G.vy *= cap2 / spd }
    T(boat).x += G.vx * dt; T(boat).y += G.vy * dt
    T(boat).x = Math.max(14, Math.min(498, T(boat).x))
    T(boat).y = Math.max(14, Math.min(498, T(boat).y))
    T(boat).vx = 0; T(boat).vy = 0

    // ── rocks: hard contact ──
    function hullHit(nx, ny, nd, soft) {
      G.hull--; G.inv = 2.2
      G.vx -= (nx / nd) * (soft ? 60 : 85); G.vy -= (ny / nd) * (soft ? 60 : 85)
      if (G.hull <= 0) {
        G.hull = 3; G.cargo = 0; G.score = Math.max(0, G.score - 5)
        T(boat).x = 412; T(boat).y = 205; G.vx = 0; G.vy = 0; G.head = 1.9; G.trim = 0.3; G.inv = 3
      }
    }
    for (const rk of rocks) {
      const rr = (rk.properties.get('rr') || 26)
      const rx = T(boat).x - T(rk).x, ry = T(boat).y - T(rk).y
      const rd2 = Math.hypot(rx, ry) || 1
      if (rd2 < rr && G.inv <= 0) {
        hullHit(-rx, -ry, rd2, 0)
        const vn = (G.vx * rx + G.vy * ry) / rd2
        if (vn < 0) { G.vx -= 1.6 * vn * rx / rd2; G.vy -= 1.6 * vn * ry / rd2 }
      }
      T(rk).vx = 0; T(rk).vy = 0
    }
    // beacon islet is rock too
    if (light) {
      const lx = T(boat).x - T(light).x, ly = T(boat).y - T(light).y
      const ld = Math.hypot(lx, ly) || 1
      if (ld < 34 && G.inv <= 0) hullHit(-lx, -ly, ld, 0)
      light.visualParams = [G.t * 0.55, G.deliverGlow, 0, 0]
      T(light).vx = 0; T(light).vy = 0
    }

    // ── lantern rafts: spawn, drift, collect, deliver ──
    G.raftT -= dt
    const active = rafts.filter(r => r.visualParams && r.visualParams[3] < 0.5).length
    if (G.raftT <= 0 && active < 4) {
      const r = rafts.find(q => q.visualParams && q.visualParams[3] > 0.5)
      if (r) {
        let ok = false, x = 0, y = 0, tries = 0
        while (!ok && tries < 12) {
          tries++
          x = 60 + Math.random() * 392; y = 60 + Math.random() * 392
          ok = true
          for (const rk of rocks) if (Math.hypot(x - T(rk).x, y - T(rk).y) < 70) ok = false
          if (light && Math.hypot(x - T(light).x, y - T(light).y) < 90) ok = false
          if (whirl && Math.hypot(x - T(whirl).x, y - T(whirl).y) < 100) ok = false
        }
        T(r).x = x; T(r).y = y; T(r).vx = 0; T(r).vy = 0
        r.visualParams = [Math.random(), 0, 0, 0]
        r.properties.set('ttl', 45)
      }
      G.raftT = 8
    }
    for (const r of rafts) {
      if (!r.visualParams || r.visualParams[3] > 0.5) continue
      const ttl = (r.properties.get('ttl') || 0) - dt
      r.properties.set('ttl', ttl)
      T(r).x += wdx * 3.5 * dt; T(r).y += wdy * 3.5 * dt
      T(r).vx = 0; T(r).vy = 0
      if (ttl <= 0) { r.visualParams = [0, 0, 0, 1]; T(r).x = 8; T(r).y = 8; continue }
      if (G.cargo < 4 && Math.hypot(T(boat).x - T(r).x, T(boat).y - T(r).y) < 24) {
        G.cargo++; r.visualParams = [0, 0, 0, 1]; T(r).x = 8; T(r).y = 8
      }
    }
    // deliver at the dock (south of the beacon)
    if (light && G.cargo > 0) {
      const dkx = T(light).x + 4, dky = T(light).y + 54
      if (Math.hypot(T(boat).x - dkx, T(boat).y - dky) < 30 && spd < 45) {
        G.score += G.cargo * (G.cargo + 1) / 2
        if (G.score > G.best) G.best = G.score
        G.cargo = 0; G.deliverGlow = 1
      }
    }

    // ── boom geometry & visuals ──
    const side = off > 0 ? 1 : -1
    const boomTarget = side * (0.25 + (1 - G.trim) * 0.5 + (offA / Math.PI) * 0.55)
    G.boom += (boomTarget - G.boom) * Math.min(1, dt * 5)
    boat.visualParams = [G.head, Math.min(1, spd / 80), G.boom, G.heel]
    sea.visualParams = [wdx, wdy, Math.min(1, (G.windV * gust - 4) / 6), 0]
    if (hud) {
      hud.visualParams = [G.hull, G.cargo, G.windA, Math.min(1, (G.windV - 4) / 5)]
      hud.name = 'TIDERUNNER \u00b7 ' + G.score + ' \u00b7 best ' + G.best + (G.inv > 0 ? ' \u00b7 hull!' : '')
    }
  }
} catch (e) { /* keep the sim alive */ }

visualTypes.wgsl:
fn cf_stars(p: vec2f, t: f32) -> vec3f {
  var c = vec3f(0.008, 0.007, 0.016);
  c += vec3f(0.05, 0.025, 0.09) * smoothstep(0.4, 0.9, fbm(p * 1.5 + vec2f(t * 0.004, 0.0), 4));
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (16.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let fp = fract(sp) - 0.5;
    let tw = 0.5 + 0.5 * sin(t * (0.5 + h * 1.4) + h * 40.0);
    c += vec3f(0.8, 0.75, 0.95) * step(0.985, h) * smoothstep(0.24, 0.03, length(fp)) * tw * (1.1 - fl * 0.4);
  }
  return c;
}

fn visual_cf_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mp = vec2f(uni(4), uni(5));     // cursor (uv coords)
  let cam = vec2f(uni(0), uni(1));
  let zm = uni(2);

  // ── the room: stars seen through curved space (your cursor is a lens) ──
  var p = uv;
  let md = uv - mp;
  let mr2 = max(dot(md, md), 0.002);
  p -= md * (0.010 / mr2) * smoothstep(0.9, 0.2, length(md));
  var col = cf_stars(p, t);

  // warm hearth-light from below — this is a cafe, not a void
  col += vec3f(0.10, 0.055, 0.02) * pow(max(0.0, uv.y + 0.2), 2.0) * (0.8 + 0.2 * sin(t * 0.7));

  // ── the bubble universe: live positions, pressure-ranked, explorable ──
  for (var i = 0; i < i32(uni(3) + 0.5); i++) {
    let sv = uni(8 + i * 3);
    let st = i32(floor(sv));
    let hue = fract(sv);
    let ctr = vec2f((uni(6 + i * 3) - cam.x) * zm / 256.0, (uni(7 + i * 3) - cam.y) * zm / 256.0);
    let d = length(uv - ctr);
    let R = 0.098 * zm;
    let hov = smoothstep(R * 1.9, R * 1.1, length(mp - ctr));
    let rr = R * (1.0 + hov * 0.12);
    if (d < rr) {
      let q = (uv - ctr) / rr;                     // -1..1 inside the disc
      var g = vec3f(0.0);
      if (st == 0) {
        // FABRIC — a lens wandering through stars
        var pp = q * 2.0;
        let lc = vec2f(sin(t * 0.6) * 0.5, cos(t * 0.47) * 0.4);
        let ld = pp - lc;
        pp -= ld * (0.16 / max(dot(ld, ld), 0.02));
        g = cf_stars(pp * 1.6, t) * 2.2;
        g += vec3f(0.5, 0.9, 1.1) * exp(-dot(ld, ld) * 14.0) * 0.4;
      } else if (st == 1) {
        // ORRERY — three worlds around a coal
        g = vec3f(0.02, 0.015, 0.03);
        g += vec3f(3.0, 1.7, 0.5) * exp(-dot(q, q) * 30.0);
        for (var k = 1; k <= 3; k++) {
          let fk = f32(k);
          let a = t * (0.9 - fk * 0.18) + fk * 2.1;
          let pp = q - vec2f(cos(a), sin(a)) * (0.22 + fk * 0.17);
          var pc = vec3f(0.45, 0.5, 0.65);
          if (k == 2) { pc = vec3f(0.2, 0.45, 0.8); }
          if (k == 3) { pc = vec3f(0.8, 0.5, 0.25); }
          g += pc * exp(-dot(pp, pp) * 260.0) * 1.6;
        }
      } else if (st == 2) {
        // GARNET — the crystal
        let qa = rotate(q, t * 0.4);
        let cd = abs(qa.x) * 0.866 + abs(qa.y) * 0.5;
        let inside = smoothstep(0.62, 0.58, max(cd, abs(qa.y)));
        let facet = 0.6 + 0.4 * sin(qa.x * 9.0 + qa.y * 7.0 + t * 0.8);
        g = mix(vec3f(0.02, 0.01, 0.02), vec3f(0.75, 0.18, 0.25) * facet, inside);
        g += vec3f(1.6, 0.9, 0.7) * pow(max(0.0, facet - 0.75) * 4.0, 2.0) * inside;
      } else if (st == 3) {
        // ONE DAY — a sky that keeps its whole day
        let ph = fract(t * 0.05);
        let el = sin(ph * 6.28318) * 0.8;
        let day = smoothstep(-0.2, 0.4, el);
        g = mix(vec3f(0.02, 0.02, 0.06), vec3f(0.25, 0.5, 0.8), day * (0.5 - q.y * 0.5));
        g = mix(g, vec3f(0.9, 0.4, 0.15), smoothstep(0.3, 0.0, abs(el)) * max(0.0, -q.y + 0.2) * 0.9);
        let sun = vec2f(cos(ph * 6.28318 - 1.57) * 0.6, -el * 0.55 + 0.1);
        g += vec3f(3.0, 2.0, 0.9) * exp(-dot(q - sun, q - sun) * 60.0) * max(day, 0.15);
        if (q.y > 0.25) { g = mix(g, g * vec3f(0.5, 0.6, 0.8), 0.6); }   // the sea below
      } else if (st == 4) {
        // SAIL — one boat, one sea
        g = mix(vec3f(0.35, 0.5, 0.65), vec3f(0.05, 0.14, 0.2), smoothstep(-0.1, 0.5, q.y));
        let w = sin(q.x * 9.0 + t * 1.4) * 0.05;
        g = mix(g, vec3f(0.03, 0.10, 0.14), smoothstep(w + 0.02, w - 0.02, -q.y + 0.1) * 0.0 + smoothstep(w - 0.02, w + 0.06, q.y - 0.05));
        let sail = max(max(-(q.x + 0.05) * 3.0, q.y + 0.15), (q.x * 0.9 + q.y * 0.8) - 0.28);
        g = mix(g, vec3f(1.0, 0.96, 0.88), smoothstep(0.02, -0.02, sail));
      } else if (st == 5) {
        // SOLSTICE — a sun you carry over a valley
        g = vec3f(0.03, 0.04, 0.09);
        let sp = vec2f(sin(t * 0.5) * 0.45, -0.3 + cos(t * 0.5) * 0.12);
        g += vec3f(3.2, 2.2, 0.9) * exp(-dot(q - sp, q - sp) * 40.0);
        let hill = q.y - (0.25 + 0.15 * sin(q.x * 3.0 + 1.0));
        let lit = max(0.0, 1.0 - length(q - sp) * 1.4);
        g = mix(g, mix(vec3f(0.03, 0.05, 0.02), vec3f(0.15, 0.3, 0.08), lit), smoothstep(-0.02, 0.02, hill));
      } else if (st == 6) {
        // TIDERUNNER — wind over water
        let band = sin(q.y * 14.0 - t * 1.1 + sin(q.x * 4.0) * 0.7);
        g = mix(vec3f(0.05, 0.13, 0.17), vec3f(0.12, 0.25, 0.3), 0.5 + 0.5 * band);
        g += vec3f(0.8, 0.85, 0.85) * pow(max(0.0, band - 0.8) * 5.0, 2.0) * 0.4;
        let bt = q - vec2f(sin(t * 0.4) * 0.4, 0.0);
        g += vec3f(0.9, 0.85, 0.75) * exp(-dot(bt, bt) * 300.0) * 1.2;
      } else if (st == 7) {
        // SIGNAL — a television waiting for a word
        let sn = hash21(floor(q * 24.0) + floor(t * 9.0));
        g = vec3f(sn * 0.5);
        g += vec3f(0.3, 1.0, 0.45) * exp(-dot(q, q) * 8.0) * (0.28 + 0.14 * sin(t * 2.0));
        g *= 0.82 + 0.18 * sin(q.y * 60.0 - t * 8.0);
      } else {
        // a young world — a banded seed-planet in its own hue
        let cA = 0.5 + 0.5 * cos(6.2831 * (hue + vec3f(0.0, 0.33, 0.67)));
        g = cA * (0.22 + 0.5 * fbm3(q * 3.0 + vec2f(t * 0.08, f32(i) * 3.7)));
        g += cA * 0.4 * smoothstep(0.6, 1.0, 1.0 - abs(q.y * 2.2 + 0.3 * sin(q.x * 3.0 + t * 0.4)));
        let mn = q - vec2f(cos(t * 0.5 + f32(i) * 1.9), sin(t * 0.5 + f32(i) * 1.9) * 0.6) * 0.78;
        g += vec3f(0.85) * exp(-dot(mn, mn) * 260.0);
        g *= 0.85 + 0.3 * (1.0 - length(q));
      }
      // glass edge + hover bloom
      let edge = smoothstep(1.0, 0.86, length(q));
      col = mix(col, g, edge);
      col += vec3f(1.2, 0.85, 0.4) * exp(-pow((length(q) - 0.97) * 9.0, 2.0)) * (0.25 + hov * 1.3);
    } else {
      // halo when hovered
      col += vec3f(1.0, 0.7, 0.3) * exp(-pow((d - rr) * 22.0, 2.0)) * hov * 0.8;
    }
  }

  // the cursor itself — a soft ember
  col += vec3f(1.4, 0.9, 0.4) * exp(-dot(uv - mp, uv - mp) * 900.0) * 0.8;

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

fn od_ic() -> vec2f { return vec2f(-9.0, 32.0); }

fn od_suncol(el: f32) -> vec3f {
  return mix(vec3f(1.30, 0.45, 0.16), vec3f(1.15, 1.05, 0.90), smoothstep(0.02, 0.55, el));
}

fn od_sky(rd: vec3f, sd: vec3f, md: vec3f, t: f32) -> vec3f {
  let el = uni(1);
  let y = max(rd.y, 0.0);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);

  // dome: night indigo → day blue, horizon warms at low sun
  let zen = mix(vec3f(0.012, 0.018, 0.045), vec3f(0.16, 0.36, 0.65), day);
  let horDay = mix(vec3f(1.00, 0.42, 0.16), vec3f(0.46, 0.58, 0.72), smoothstep(0.10, 0.55, el));
  let hor = mix(vec3f(0.035, 0.035, 0.075), horDay, smoothstep(-0.16, 0.06, el));
  var c = mix(hor, zen, pow(y, 0.6));

  // sun
  let sdot = clamp(dot(rd, sd), 0.0, 1.0);
  let sunUp = smoothstep(-0.14, 0.02, el);
  c += od_suncol(el) * pow(sdot, 5.0) * 0.32 * sunUp;
  c += od_suncol(el) * pow(sdot, 70.0) * 0.60 * sunUp;
  c += vec3f(5.2, 3.6, 2.0) * smoothstep(0.99972, 0.99990, sdot) * sunUp;

  // moon: cool disk + halo, out at night
  let mdot = clamp(dot(rd, md), 0.0, 1.0);
  let moonUp = night * smoothstep(-0.05, 0.10, md.y);
  c += vec3f(0.55, 0.62, 0.75) * pow(mdot, 90.0) * 0.5 * moonUp;
  c += vec3f(2.6, 2.8, 3.1) * smoothstep(0.99985, 0.99995, mdot) * moonUp;

  // stars + a faint galaxy band
  if (night > 0.02 && rd.y > 0.01) {
    let sp = rd.xz / (rd.y + 0.55) * 26.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let tw = 0.55 + 0.45 * sin(t * (0.8 + h) + h * 50.0);
    c += vec3f(0.72, 0.78, 0.95) * step(0.990, h) * smoothstep(0.30, 0.05, length(fract(sp) - 0.5)) * night * tw;
    let band = pow(max(1.0 - abs(rd.x * 0.8 + rd.y * 0.5 - 0.15), 0.0), 3.5);
    c += vec3f(0.07, 0.07, 0.12) * band * night * (0.5 + 0.3 * vnoise(sp * 0.5));
  }

  // clouds: sparse, tinted by the hour
  if (rd.y > 0.015) {
    let cp = rd.xz / (rd.y + 0.14) * 1.4 + vec2f(t * 0.006, t * 0.002);
    var cl = fbm(cp * 0.55, 4);
    cl = smoothstep(0.46, 0.78, cl);
    let cloudLit = mix(vec3f(0.06, 0.06, 0.10), mix(vec3f(1.15, 0.50, 0.28), vec3f(0.85, 0.85, 0.90), smoothstep(0.12, 0.5, el)), max(day, night * 0.12));
    c = mix(c, cloudLit, cl * 0.7 * smoothstep(0.015, 0.10, rd.y));
  }
  return c;
}

fn od_oct(uv0: vec2f, choppy: f32) -> f32 {
  let n = gnoise(uv0);
  let uv = uv0 + vec2f(n, n);
  var wv = 1.0 - abs(sin(uv));
  let swv = abs(cos(uv));
  wv = mix(wv, swv, wv);
  return pow(1.0 - pow(wv.x * wv.y, 0.65), choppy);
}

fn od_surge(pxz: vec2f, st: f32) -> f32 {
  let dr = length(pxz - od_ic());
  return exp(-max(dr - 5.8, 0.0) * 0.35) * (sin(st * 1.4 - dr * 0.9) * 0.5 + 0.62) * 1.05;
}


fn od_wake(pxz: vec2f) -> f32 {
  let d = vec2f(pxz.x - uni(7), pxz.y - 52.0);
  let along = -d.x * uni(8);                 // positive = behind the boat
  if (along < -3.0 || along > 26.0 || abs(d.y) > 12.0) { return 0.0; }
  let a = max(along, 0.0);
  var w = exp(-dot(d, d) * 0.35) * 0.8;      // bow mound at the hull
  let arm = exp(-pow((abs(d.y) - 0.36 * a) * 1.1, 2.0)) * exp(-a * 0.10);  // Kelvin arms (~19.5deg)
  let inside = smoothstep(0.36 * a + 1.0, 0.36 * a - 1.0, abs(d.y));
  let ripple = sin(a * 2.4) * 0.5 * inside * exp(-a * 0.13);               // transverse train
  return w + arm * 0.9 + ripple;
}

fn od_amp() -> f32 { return 0.55 + 0.75 * uni(3); }   // wind raises the sea


fn od_fireH(p: vec3f, st: f32, h0: f32) -> f32 {
  // TRANSITION MATH: the wave field morphs into a flame field. Keyed to the
  // SAME ignition front as the color pass, so shape and char advance together.
  let u = uni(10);
  if (u <= 0.01) { return h0; }
  let front = smoothstep(u * 1.15, u * 1.15 - 0.22, fbm3(p.xz * 0.045 + vec2f(3.7, 0.0)));
  let burn = u * front;
  if (burn <= 0.003) { return h0; }
  // cusped ridges racing upward — fire runs at 2.6x wave time and flickers
  var q = p.xz * 0.55;
  var f = 0.0;
  var amp2 = 1.0;
  for (var i = 0; i < 3; i++) {
    let n = vnoise(q + vec2f(f32(i) * 7.3, -st * 2.6));
    f += (1.0 - abs(n * 2.0 - 1.0)) * amp2;
    q = q * 2.1;
    amp2 *= 0.45;
  }
  let flick = 0.8 + 0.35 * sin(st * 9.0 + p.x * 0.9 + f * 4.0);
  let flameH = (f - 0.65) * flick * 1.9;
  // waves damp as tongues take over; troughs keep a quarter of their swell
  return mix(h0, max(flameH, h0 * 0.25), burn);
}

fn od_map3(p: vec3f, st: f32) -> f32 {
  var freq = 0.16;
  var amp = 0.6 * od_amp();
  var choppy = 4.0;
  var uv = p.xz;
  uv.x = uv.x * 0.75;
  var h = 0.0;
  for (var i = 0; i < 3; i++) {
    var d = od_oct((uv + vec2f(st)) * freq, choppy);
    d = d + od_oct((uv - vec2f(st)) * freq, choppy);
    h = h + d * amp;
    uv = mat2x2f(1.6, 1.2, -1.2, 1.6) * uv;
    freq = freq * 1.9;
    amp = amp * 0.22;
    choppy = mix(choppy, 1.0, 0.2);
  }
  h = h + od_surge(p.xz, st);
  h = h + od_wake(p.xz) * 0.22;
  h = od_fireH(p, st, h);
  return p.y - h;
}

fn od_map5(p: vec3f, st: f32) -> f32 {
  var freq = 0.16;
  var amp = 0.6 * od_amp();
  var choppy = 4.0;
  var uv = p.xz;
  uv.x = uv.x * 0.75;
  var h = 0.0;
  for (var i = 0; i < 5; i++) {
    var d = od_oct((uv + vec2f(st)) * freq, choppy);
    d = d + od_oct((uv - vec2f(st)) * freq, choppy);
    h = h + d * amp;
    uv = mat2x2f(1.6, 1.2, -1.2, 1.6) * uv;
    freq = freq * 1.9;
    amp = amp * 0.22;
    choppy = mix(choppy, 1.0, 0.2);
  }
  h = h + od_surge(p.xz, st);
  h = h + od_wake(p.xz) * 0.22;
  h = od_fireH(p, st, h);
  return p.y - h;
}

fn od_nrm(p: vec3f, eps: f32, st: f32) -> vec3f {
  let hy = od_map5(p, st);
  let hx = od_map5(p + vec3f(eps, 0.0, 0.0), st);
  let hz = od_map5(p + vec3f(0.0, 0.0, eps), st);
  return normalize(vec3f(hx - hy, eps, hz - hy));
}

fn od_spec(n: vec3f, l: vec3f, e: vec3f, s: f32) -> f32 {
  let nrm = (s + 8.0) / (3.14159 * 8.0);
  return pow(max(dot(reflect(e, n), l), 0.0), s) * nrm;
}

fn od_seacol(p: vec3f, n: vec3f, sd: vec3f, md: vec3f, eye: vec3f, dist: vec3f, t: f32, st: f32) -> vec3f {
  let el = uni(1);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);

  var fres = clamp(1.0 - dot(n, -eye), 0.0, 1.0);
  fres = pow(fres, 3.0) * 0.5;

  let reflected = od_sky(reflect(eye, n), sd, md, t);
  let base = mix(vec3f(0.004, 0.008, 0.016), vec3f(0.035, 0.06, 0.11), day);
  let waterCol = vec3f(0.17, 0.23, 0.22) * (0.25 + 0.75 * day);
  let refracted = base + pow(dot(n, sd) * 0.4 + 0.6, 80.0) * waterCol * 0.12 * day;

  var col = mix(refracted, reflected, fres);

  let atten = max(1.0 - dot(dist, dist) * 0.001, 0.0);
  col = col + waterCol * (p.y - 0.6) * 0.18 * atten;

  // sun glitter by day, moon glitter by night — same sea, different star
  col = col + od_suncol(el) * vec3f(2.4, 1.5, 0.8) * od_spec(n, sd, eye, 90.0) * smoothstep(-0.08, 0.05, el);
  col = col + vec3f(0.9, 1.05, 1.3) * od_spec(n, md, eye, 140.0) * night * smoothstep(0.0, 0.15, md.y) * 1.6;

  // crest foam
  let foamN = vnoise(p.xz * 2.2 + vec2f(t * 0.5, -t * 0.35));
  let crest = smoothstep(1.05, 1.55, p.y) * smoothstep(0.42, 0.85, foamN);
  col = mix(col, vec3f(0.90, 0.82, 0.72) * (0.25 + 0.75 * day), crest * atten * 0.4);

  // island surf ring
  let drf = length(p.xz - od_ic()) - 6.2;
  let ph = sin(st * 1.4 - (drf + 6.2) * 0.9) * 0.5 + 0.5;
  var rockFoam = smoothstep(3.2, 0.2, drf) * (0.35 + 0.65 * ph);
  rockFoam = rockFoam * (0.45 + 0.55 * vnoise(p.xz * 2.6 + vec2f(st * 0.8, -st * 0.55)));
  col = mix(col, vec3f(0.90, 0.88, 0.84) * (0.3 + 0.7 * day + 0.25 * night), clamp(rockFoam, 0.0, 1.0) * 0.85);

  // boat wake foam — the ocean reads the boat off the whiteboard
  let wk = od_wake(p.xz);
  col = mix(col, vec3f(0.82, 0.85, 0.84) * (0.35 + 0.65 * day + 0.2 * night), clamp(wk * 0.9 - 0.12, 0.0, 1.0) * 0.55);

  return col;
}

fn visual_od_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x, -uv.y);
  let t = time;
  let st = 1.0 + t * 0.8;

  let bob = sin(t * 0.5) * 0.06;
  let ro = vec3f(0.0, 3.4 + bob, 0.0);
  // wide viewports crop the field vertically — widen the vertical FOV to keep
  // the whole lighthouse in frame at any aspect
  let visH = clamp(frame.resolution.y / max(frame.resolution.x, 1.0), 0.45, 1.0);
  var rd = normalize(vec3f(p.x, (p.y * 0.72) / visH - 0.14 * visH, 1.75));
  let rxy = rotate(rd.xy, sin(t * 0.35) * 0.012);
  rd = normalize(vec3f(rxy.x, rxy.y, rd.z));

  // the whiteboard drives the world
  let saz = uni(0);
  let sel = uni(1);
  let sd = normalize(vec3f(cos(saz) * cos(sel), sin(sel), sin(saz) * cos(sel)));
  let mel = uni(5);
  let maz = uni(6);
  let md = normalize(vec3f(cos(maz) * cos(mel), sin(mel), sin(maz) * cos(mel)));

  var col = od_sky(rd, sd, md, t);
  var tScene = 100000.0;

  // ---- ocean ----
  if (rd.y < 0.0) {
    var tm = 0.0;
    var tx = 1000.0;
    var hx = od_map3(ro + rd * tx, st);
    if (hx < 0.0) {
      var hm = od_map3(ro, st);
      var tmid = 0.0;
      for (var i = 0; i < 8; i++) {
        tmid = mix(tm, tx, hm / (hm - hx));
        let pm = ro + rd * tmid;
        let hmid = od_map3(pm, st);
        if (hmid < 0.0) { tx = tmid; hx = hmid; } else { tm = tmid; hm = hmid; }
      }
      let pt = ro + rd * tmid;
      let dist = pt - ro;
      let eps = max(dot(dist, dist) * 0.0002, 0.002);
      let n = od_nrm(pt, eps, st);
      var seaCol = od_seacol(pt, n, sd, md, rd, dist, t, st);
      if (uni(10) > 0.01) {
        let u = uni(10);
        // a patchy ignition front spreads across the water
        let front = smoothstep(u * 1.15, u * 1.15 - 0.22, fbm3(pt.xz * 0.045 + 3.7));
        let burn = u * front;
        if (burn > 0.003) {
          // char: the water darkens as it heats
          seaCol = mix(seaCol, seaCol * vec3f(0.35, 0.22, 0.18), min(burn * 2.2, 1.0));
          // ember cracks glow in the troughs
          let crack = pow(vnoise(pt.xz * 1.6 + vec2f(st * 0.4, -st * 0.3)), 4.0);
          seaCol += vec3f(2.4, 0.5, 0.05) * crack * smoothstep(0.05, 0.45, burn);
          // crests ignite: flames ride the wave tops
          let crest = smoothstep(0.4, 1.4, pt.y);
          let lick = fbm3(vec2f(pt.x * 0.8, pt.z * 0.8 - t * 2.6));
          seaCol += mix(vec3f(1.8, 0.5, 0.02), vec3f(3.0, 1.8, 0.25), lick) * crest * smoothstep(0.3, 0.8, burn) * (0.6 + 0.4 * lick);
          // molten body at full burn
          let fl = fbm3(pt.xz * 0.35 + vec2f(t * 1.8, -t * 1.2));
          let molten = mix(vec3f(1.6, 0.35, 0.05), vec3f(2.8, 1.6, 0.22), fl);
          seaCol = mix(seaCol, molten, smoothstep(0.55, 1.0, burn) * (0.55 + 0.45 * fl));
        }
      }
      let seaBlend = pow(1.0 - smoothstep(-0.02, 0.0, rd.y), 0.2);
      col = mix(col, seaCol, seaBlend);
      tScene = tmid;
    }
  }

  // leaping tongues — the burn climbs off the water into the air
  if (uni(10) > 0.05 && rd.y < 0.16) {
    let hb = smoothstep(0.16, -0.02, rd.y);
    let fx = rd.x / max(rd.z, 0.2);
    let tongue = fbm3(vec2f(fx * 9.0, rd.y * 26.0 - t * 3.2));
    let tongue2 = vnoise(vec2f(fx * 22.0 + 7.0, rd.y * 40.0 - t * 5.0));
    let leap = pow(tongue, 2.0) * (0.5 + 0.5 * tongue2) * hb * uni(10);
    col += mix(vec3f(2.2, 0.6, 0.04), vec3f(3.4, 1.9, 0.3), tongue2) * leap * 0.9;
  }

  // ---- distant sailboat crossing (whiteboard position) ----
  let B = vec3f(uni(7), 0.9 + sin(t * 0.7) * 0.15, 52.0);
  let toB = B - ro;
  let bDist = length(toB);
  let bDir = toB / bDist;
  if (dot(rd, bDir) > 0.995 && tScene > bDist) {
    let right = normalize(cross(bDir, vec3f(0.0, 1.0, 0.0)));
    let upv = cross(right, bDir);
    let par = dot(rd, bDir);
    let lx = dot(rd, right) / par * bDist * uni(8);   // flip with travel direction
    let ly = dot(rd, upv) / par * bDist;
    // hull + mainsail silhouette, warm-rimmed at low sun
    let hull = max(abs(lx) - 1.9 * (1.0 - clamp(ly + 0.4, 0.0, 0.5)), abs(ly + 0.45) - 0.35);
    let sail = max(max(-(lx + 0.1), ly - 2.6), (lx * 0.62 + ly * 0.55) - 1.35);
    let el2 = uni(1);
    let silCol = mix(vec3f(0.015, 0.015, 0.025), vec3f(0.10, 0.05, 0.04), smoothstep(0.3, 0.02, abs(el2)) * 0.8);
    if (hull < 0.0 || sail < 0.0) {
      col = silCol + od_suncol(el2) * 0.25 * smoothstep(0.15, -0.05, lx * uni(8)) * smoothstep(-0.08, 0.05, el2);
    }
  }

  // selection outline: the lighthouse is a thing you can pick up
  if (uni(13) > 0.05) {
    let od = abs(sdRoundedBox(p - vec2f(uni(14), uni(15)), vec2f(uni(16) * 0.5, uni(16)), 0.03));
    col += vec3f(1.1, 0.95, 0.5) * smoothstep(0.012, 0.0, od) * uni(13) * (0.65 + 0.35 * sin(t * 4.0));
  }

  return vec4f(col, 1.0);
}

fn od2_ic() -> vec2f { return vec2f(uni(11), uni(12)); }
fn od2_suncol(el: f32) -> vec3f {
  return mix(vec3f(1.30, 0.45, 0.16), vec3f(1.15, 1.05, 0.90), smoothstep(0.02, 0.55, el));
}
fn od2_box(p: vec3f, b: vec3f) -> f32 {
  let d = abs(p) - b;
  return length(max(d, vec3f(0.0))) + min(max(d.x, max(d.y, d.z)), 0.0);
}

// materials: 0 rock · 1 whitewash tower · 2 ironwork · 3 lantern glass
//            4 copper cupola · 5 cottage wall · 6 cottage roof · 7 chimney · 8 door
fn od2_sdf(p: vec3f) -> vec2f {
  let ic = od2_ic();
  let q = p - vec3f(ic.x, 0.0, ic.y);

  // the rock
  var d = length(q * vec3f(1.0, 1.25, 1.08)) - 6.4;
  d = d - (vnoise3(q * 0.55) - 0.5) * 2.6 - (vnoise3(q * 1.9) - 0.5) * 0.9;
  var m = 0.0;

  // tapered masonry tower with a wider plinth — colonial whitewash
  let ty = clamp((p.y - 4.0) / 7.5, 0.0, 1.0);
  let taper = mix(1.42, 0.88, pow(ty, 0.85));
  let plinth = 1.0 + 0.35 * smoothstep(5.2, 4.0, p.y);
  let dTower = max(length(q.xz) - taper * plinth, abs(p.y - 7.75) - 3.75);
  if (dTower < d) { d = dTower; m = 1.0; }

  // gallery deck + railing: handrail ring and a circle of balusters
  let dDeck = max(length(q.xz) - 1.52, abs(p.y - 11.62) - 0.14);
  if (dDeck < d) { d = dDeck; m = 2.0; }
  let dRail = max(abs(length(q.xz) - 1.44) - 0.035, abs(p.y - 12.42) - 0.045);
  if (dRail < d) { d = dRail; m = 2.0; }
  let phi = atan2(q.z, q.x);
  let seg = 6.28318 / 20.0;
  let aphi = (glsl_mod(phi + seg * 0.5, seg) - seg * 0.5) * 1.44;
  let dBal = max(length(vec2f(length(q.xz) - 1.44, aphi)) - 0.035, abs(p.y - 12.02) - 0.42);
  if (dBal < d) { d = dBal; m = 2.0; }

  // octagonal lantern room
  var oct = abs(q.x);
  oct = max(oct, abs(q.z));
  oct = max(oct, abs(q.x * 0.7071 + q.z * 0.7071));
  oct = max(oct, abs(q.x * 0.7071 - q.z * 0.7071));
  let dLan = max(oct - 0.82, abs(p.y - 12.55) - 0.72);
  if (dLan < d) { d = dLan; m = 3.0; }

  // copper cupola with finial
  let ry = clamp((p.y - 13.27) / 1.15, 0.0, 1.0);
  let dRoof = max(length(q.xz) - mix(1.06, 0.06, pow(ry, 0.72)), abs(p.y - 13.84) - 0.58);
  if (dRoof < d) { d = dRoof; m = 4.0; }
  let dFin = length(vec3f(q.x, (p.y - 14.72) * 0.8, q.z)) - 0.14;
  if (dFin < d) { d = dFin; m = 2.0; }

  // the keeper's cottage: clapboard saltbox, gable roof, brick chimney
  let qc = q - vec3f(3.1, 4.45, 0.6);
  let dHouse = od2_box(qc, vec3f(1.55, 0.95, 1.15));
  if (dHouse < d) { d = dHouse; m = 5.0; }
  let dRoofH = max(max(abs(qc.z) * 0.92 + (qc.y - 1.72), -(qc.y - 0.75)), max(abs(qc.x) - 1.72, abs(qc.z) - 1.32));
  if (dRoofH < d) { d = dRoofH; m = 6.0; }
  let dChim = od2_box(qc - vec3f(0.55, 1.85, 0.0), vec3f(0.22, 0.65, 0.22));
  if (dChim < d) { d = dChim; m = 7.0; }

  return vec2f(d, m);
}

fn od2_trace(ro: vec3f, rd: vec3f) -> vec3f {
  let ic = od2_ic();
  let oc = ro - vec3f(ic.x, 6.5, ic.y);
  let b = dot(oc, rd);
  let c = dot(oc, oc) - 182.25;
  let disc = b * b - c;
  if (disc < 0.0) { return vec3f(0.0, 0.0, -1.0); }
  let sq = sqrt(disc);
  let t1 = -b + sq;
  var tt = max(-b - sq, 0.0);
  for (var i = 0; i < 60; i++) {
    let dm = od2_sdf(ro + rd * tt);
    if (dm.x < 0.02) { return vec3f(tt, dm.y, 1.0); }
    tt = tt + dm.x * 0.7;
    if (tt > t1) { break; }
  }
  return vec3f(0.0, 0.0, -1.0);
}

// arched-window mask on the tower shaft, facing the sea (toward the viewer)
fn od2_window(phi: f32, y: f32, yc: f32) -> f32 {
  let PHIC = -1.296;   // bearing from island to the home shore
  var ang = phi - PHIC;
  ang = glsl_mod(ang + 3.14159, 6.28318) - 3.14159;
  let aw = ang * 1.15;
  let wy = y - yc;
  let rect = step(abs(aw), 0.145) * step(-0.26, wy) * step(wy, 0.13);
  let arch = step(length(vec2f(aw, wy - 0.13)), 0.145);
  return max(rect, arch);
}

fn od2_shade(p: vec3f, n: vec3f, rd: vec3f, m: f32, sd: vec3f, t: f32, st: f32) -> vec3f {
  let el = uni(1);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);
  let ic = od2_ic();
  let q = p - vec3f(ic.x, 0.0, ic.y);
  let phi = atan2(q.z, q.x);
  var alb = vec3f(0.0);
  var emis = vec3f(0.0);
  var spec = 0.0;

  if (m < 0.5) {
    // rock: strata, wet dark base, lichen where it faces the sky
    let strat = sin(p.y * 2.1 + (vnoise3(p * 0.4) - 0.5) * 5.0);
    alb = mix(vec3f(0.055, 0.052, 0.058), vec3f(0.125, 0.115, 0.10), 0.5 + 0.5 * strat);
    alb = mix(alb, vec3f(0.14, 0.13, 0.10), vnoise3(p * 1.7) * 0.4);
    let wet = smoothstep(2.6, 0.5, p.y);
    alb = alb * (1.0 - wet * 0.6);
    spec = wet * 0.5;
    let lich = smoothstep(0.45, 0.75, vnoise3(p * 2.3)) * smoothstep(0.35, 0.7, n.y) * smoothstep(3.2, 4.4, p.y);
    alb = mix(alb, vec3f(0.16, 0.17, 0.08), lich * 0.7);
  } else if (m < 1.5) {
    // whitewashed masonry: courses, joints, weather streaks
    alb = vec3f(0.86, 0.85, 0.81);
    let course = smoothstep(0.055, 0.02, abs(fract(p.y / 0.58) - 0.5) * 0.58);
    let joint = smoothstep(0.05, 0.02, abs(fract(phi * 1.15 / 0.85 + floor(p.y / 0.58) * 0.5) - 0.5) * 0.85);
    alb = alb * (1.0 - course * 0.10 - joint * course * 0.05);
    let streak = smoothstep(0.55, 0.9, vnoise(vec2f(phi * 6.0, p.y * 0.22)));
    alb = alb * (1.0 - streak * 0.16 * smoothstep(4.5, 10.5, p.y));
    alb = alb * (1.0 - smoothstep(5.4, 4.2, p.y) * 0.18);   // grime at the plinth
    // three arched windows climbing the shaft + the door
    var win = 0.0;
    win = max(win, od2_window(phi, p.y, 6.3));
    win = max(win, od2_window(phi, p.y, 8.5));
    win = max(win, od2_window(phi, p.y, 10.5));
    let doorM = od2_window(phi, p.y * 0.72, 3.42);
    alb = mix(alb, vec3f(0.05, 0.05, 0.06), win);
    alb = mix(alb, vec3f(0.06, 0.13, 0.09), doorM);        // colonial green door
    let lit = 0.35 + 0.65 * smoothstep(0.4, 0.9, hash11(floor(p.y / 2.0)));
    emis = emis + vec3f(2.0, 1.25, 0.45) * win * night * lit;
  } else if (m < 2.5) {
    alb = vec3f(0.055, 0.058, 0.068);   // wrought iron
    spec = 0.35;
  } else if (m < 3.5) {
    // lantern glazing: mullions read dark, panes catch sky and hold the lamp
    let mseg = 6.28318 / 8.0;
    let mphi = abs(glsl_mod(phi + mseg * 0.5, mseg) - mseg * 0.5);
    let mull = step(mphi, 0.09);
    let bands = step(abs(p.y - 12.55), 0.06) + step(0.60, abs(p.y - 12.55));
    if (mull + bands > 0.5) {
      alb = vec3f(0.055, 0.058, 0.068);
      spec = 0.35;
    } else {
      alb = vec3f(0.02, 0.025, 0.035);
      spec = 1.2;
      let lampP = vec3f(ic.x, 12.55, ic.y);
      let lampD = length(p - lampP);
      emis = vec3f(6.5, 4.9, 2.6) * exp(-lampD * lampD * 0.9) * (0.15 + 0.85 * uni(4)) * 2.2;
      emis = emis + vec3f(1.4, 1.05, 0.55) * (0.10 + 0.90 * uni(4)) * 0.35;
    }
  } else if (m < 4.5) {
    // copper gone to patina
    let pat = vnoise3(p * 3.1);
    alb = mix(vec3f(0.30, 0.20, 0.12), vec3f(0.24, 0.40, 0.33), smoothstep(0.35, 0.7, pat));
    spec = 0.6;
  } else if (m < 5.5) {
    // clapboard: fine horizontal shadow lines
    alb = vec3f(0.82, 0.80, 0.74);
    let lap = smoothstep(0.10, 0.02, abs(fract(p.y / 0.16) - 0.5) * 0.16);
    alb = alb * (1.0 - lap * 0.13);
    // two warm windows on the seaward face
    let qc = q - vec3f(3.1, 4.45, 0.6);
    let front = step(qc.z, -1.05);
    let wmask = front * step(abs(abs(qc.x) - 0.62), 0.26) * step(abs(qc.y + 0.05), 0.30);
    alb = mix(alb, vec3f(0.05, 0.05, 0.06), wmask);
    emis = emis + vec3f(2.2, 1.35, 0.5) * wmask * night;
  } else if (m < 6.5) {
    alb = vec3f(0.16, 0.15, 0.15) * (0.8 + 0.4 * vnoise(vec2f(p.x * 6.0, p.z * 6.0)));  // shingles
  } else if (m < 7.5) {
    let brick = smoothstep(0.06, 0.02, abs(fract(p.y / 0.14) - 0.5) * 0.14);
    alb = vec3f(0.38, 0.16, 0.11) * (1.0 - brick * 0.35);   // brick chimney
  } else {
    alb = vec3f(0.06, 0.13, 0.09);
  }

  let dif = max(dot(n, sd), 0.0) * smoothstep(-0.05, 0.05, el);
  let ambSky = mix(vec3f(0.05, 0.06, 0.10), vec3f(0.30, 0.34, 0.48), day) * (0.35 + 0.25 * max(n.y, 0.0));
  let sunCol = od2_suncol(el) * 1.4;
  var col = alb * (ambSky + sunCol * dif);
  col = col + alb * vec3f(0.10, 0.12, 0.17) * max(dot(n, vec3f(0.3, 0.8, -0.5)), 0.0) * night;
  let rim = pow(clamp(1.0 + dot(rd, n), 0.0, 1.0), 3.0);
  col = col + sunCol * rim * 0.15 * day;
  col = col + sunCol * pow(max(dot(reflect(rd, n), sd), 0.0), 24.0) * spec * day;

  if (m < 0.5) {
    let surgePh = max(sin(st * 1.4), 0.0);
    let sprayN = vnoise(vec2f(p.x * 1.3 + p.z * 1.1, p.y * 1.8) + vec2f(st * 0.9, -st * 0.6));
    let spray = smoothstep(2.1, 0.9, p.y) * smoothstep(0.35, 0.9, sprayN) * (0.4 + 0.6 * surgePh);
    col = mix(col, vec3f(0.88, 0.90, 0.92) * (0.3 + 0.7 * day + 0.3 * night), clamp(spray, 0.0, 1.0) * 0.45);
  }
  return col + emis;
}

fn visual_od_lh(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x, -uv.y);
  let t = time;
  let st = 1.0 + t * 0.8;

  // the same eye as the world field — the two compose pixel-perfectly
  let bob = sin(t * 0.5) * 0.06;
  let ro = vec3f(0.0, 3.4 + bob, 0.0);
  // wide viewports crop the field vertically — widen the vertical FOV to keep
  // the whole lighthouse in frame at any aspect
  let visH = clamp(frame.resolution.y / max(frame.resolution.x, 1.0), 0.45, 1.0);
  var rd = normalize(vec3f(p.x, (p.y * 0.72) / visH - 0.14 * visH, 1.75));
  let rxy = rotate(rd.xy, sin(t * 0.35) * 0.012);
  rd = normalize(vec3f(rxy.x, rxy.y, rd.z));

  let saz = uni(0);
  let sel = uni(1);
  let sd = normalize(vec3f(cos(saz) * cos(sel), sin(sel), sin(saz) * cos(sel)));

  var col = behind.rgb;

  // the sea is not ours, but it still hides our feet: approximate the water
  // plane so rock below a swell yields to the world behind
  var tSea = 100000.0;
  if (rd.y < -0.001) { tSea = (0.85 - ro.y) / rd.y; }

  let lh = od2_trace(ro, rd);
  var tScene = 100000.0;
  if (lh.z > 0.0) {
    let pr = ro + rd * lh.x;
    let e = 0.03;
    let d0 = od2_sdf(pr).x;
    let nr = normalize(vec3f(
      od2_sdf(pr + vec3f(e, 0.0, 0.0)).x - d0,
      od2_sdf(pr + vec3f(0.0, e, 0.0)).x - d0,
      od2_sdf(pr + vec3f(0.0, 0.0, e)).x - d0));
    var sc = od2_shade(pr, nr, rd, lh.y, sd, t, st);
    sc = mix(sc, vec3f(0.45, 0.33, 0.30) * (0.2 + 0.8 * smoothstep(-0.1, 0.3, uni(1))), clamp(lh.x * 0.004, 0.0, 0.4));
    // let the sea's own surf/foam (already in behind) claim the waterline
    let waterVeil = smoothstep(1.15, 0.45, pr.y);
    col = mix(sc, behind.rgb, waterVeil);
    tScene = lh.x;
  }

  // ── the beam as a force field: hard-edged cone, diagonal energy hatch ──
  let beamI = uni(4);
  if (beamI > 0.01) {
    let ic = od2_ic();
    let lamp = vec3f(ic.x, 12.55, ic.y);
    for (var k = 0; k < 2; k++) {
      let ba = uni(9) + f32(k) * 3.14159;
      let Ld = normalize(vec3f(cos(ba), -0.02, sin(ba)));
      let w0 = ro - lamp;
      let a1 = dot(rd, Ld);
      let b1 = dot(rd, w0);
      let c1 = dot(Ld, w0);
      let den = 1.0 - a1 * a1;
      if (den > 0.0001) {
        let sRay = (a1 * c1 - b1) / den;
        let sBeam = (c1 - a1 * b1) / den;
        if (sRay > 0.0 && sRay < min(tScene, tSea) && sBeam > 1.2) {
          let dd = length((ro + rd * sRay) - (lamp + Ld * sBeam));
          let w = 0.32 + sBeam * 0.035;            // the cone opens with distance
          let shell = smoothstep(w, w * 0.78, dd); // hard wall, not a gaussian
          let edge = exp(-pow((dd - w * 0.92) * 5.5, 2.0)) * 0.8;   // bright skin
          // one family of diagonal interference — a field, not a net
          let hatch = pow(0.5 + 0.5 * sin(sBeam * 2.2 - dd * 7.0 - t * 6.0), 3.0);
          let breathe = 0.93 + 0.07 * sin(t * 22.0 + sBeam * 0.7);
          let body = shell * (0.34 + 0.66 * hatch);
          let fall = exp(-sBeam * 0.042);
          // when the beam points at the eye its cross-section is half the sky — dim it
          let headOn = 1.0 - pow(abs(a1), 10.0);
          col = col + mix(vec3f(2.5, 1.95, 1.15), vec3f(3.1, 2.95, 2.45), shell * hatch)
                      * (body + edge) * fall * 1.5 * beamI * breathe * headOn;
        }
      }
    }
    // lamp flare when the beam sweeps you
    let toLamp = lamp - ro;
    let lampDist = length(toLamp);
    let ba0 = uni(9);
    let alignK = pow(abs(dot(vec2f(cos(ba0), sin(ba0)), normalize(ro.xz - lamp.xz))), 24.0);
    let flare = pow(max(dot(rd, toLamp / lampDist), 0.0), 700.0);
    col = col + vec3f(4.5, 3.4, 2.0) * flare * (0.5 + 4.5 * alignK) * beamI;
  }

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = behind.rgb; }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

fn visual_od_flies(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  // fireflies over the island after dark — existence itself read off the whiteboard
  let night = smoothstep(0.02, -0.14, uni(1));
  if (night < 0.02) { return vec4f(0.0); }
  let wind = uni(3);
  var c = vec3f(0.0);
  var a = 0.0;
  for (var i = 0; i < 18; i++) {
    let fi = f32(i);
    let h1 = hash11(fi * 13.7);
    let h2 = hash11(fi * 29.3);
    // hover around the island (screen left), drift on the wind
    var pos = vec2f(-0.55 + (h1 - 0.5) * 0.55, -0.10 + (h2 - 0.5) * 0.38);
    pos.x += sin(time * (0.20 + h1 * 0.25) + fi * 2.4) * 0.06 + wind * 0.02;
    pos.y += cos(time * (0.16 + h2 * 0.22) + fi * 1.7) * 0.045;
    let d2 = dot(uv - pos, uv - pos);
    let blink = smoothstep(0.25, 0.9, 0.5 + 0.5 * sin(time * (0.7 + h1 * 1.3) + fi * 5.0));
    let g = exp(-d2 * 26000.0) * blink;
    c += vec3f(2.2, 1.55, 0.45) * g;
    c += vec3f(0.9, 0.6, 0.15) * exp(-d2 * 2600.0) * blink * 0.35;
    a = max(a, clamp(g * 1.6 + exp(-d2 * 2600.0) * 0.3, 0.0, 1.0));
  }
  return vec4f(c * night, a * night * 0.95);
}

fn tr_h(pw: vec2f, t: f32, wdir: vec2f) -> f32 {
  let d2 = normalize(wdir + vec2f(-wdir.y, wdir.x) * 0.55);
  var h = sin(dot(pw, wdir) * 0.09 - t * 1.05) * 0.55;
  h += sin(dot(pw, d2) * 0.157 - t * 1.45 + 1.7) * 0.28;
  h += (vnoise(pw * 0.045 + vec2f(t * 0.05, t * 0.03)) - 0.5) * 0.9;
  h += (vnoise(pw * 0.11 - vec2f(t * 0.07, t * 0.02)) - 0.5) * 0.45;
  return h;
}
fn visual_tr_sea(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [windX, windY, wind01, 0]
  var wdir = vec2f(p.x, p.y);
  if (length(wdir) < 0.1) { wdir = vec2f(1.0, 0.0); }
  wdir = normalize(wdir);
  let w01 = clamp(p.z, 0.0, 1.0);
  let pw = uv * 256.0;
  let t = time;

  let h0 = tr_h(pw, t, wdir);
  let hx = tr_h(pw + vec2f(1.6, 0.0), t, wdir);
  let hy = tr_h(pw + vec2f(0.0, 1.6), t, wdir);
  let n = normalize(vec3f(h0 - hx, h0 - hy, 0.85));

  // dusk water: deep slate-teal, warmer toward the sun side
  var c = mix(vec3f(0.050, 0.130, 0.175), vec3f(0.085, 0.170, 0.200), h0 * 0.5 + 0.5);
  let sun2 = normalize(vec2f(-0.66, -0.30));
  c = mix(c, vec3f(0.165, 0.125, 0.115), clamp(dot(uv, sun2) * 0.5 + 0.2, 0.0, 0.45));

  // sky reflection modulated by slope (fresnel-ish from above)
  let skyRef = mix(vec3f(0.22, 0.26, 0.34), vec3f(0.62, 0.36, 0.24), clamp(dot(uv, sun2) + 0.45, 0.0, 1.0));
  c = mix(c, skyRef, clamp(0.22 + 0.35 * (1.0 - n.z), 0.0, 0.6));

  // low-sun glitter — anisotropic, stretched along the sun azimuth
  let L = normalize(vec3f(sun2 * 1.0, 0.24));
  let H = normalize(L + vec3f(0.0, 0.0, 1.0));
  var spec = pow(max(dot(n, H), 0.0), 160.0);
  spec *= 0.55 + 0.65 * vnoise(pw * 0.9 + vec2f(t * 0.8, -t * 0.5));
  c += vec3f(2.6, 1.5, 0.7) * spec * (0.35 + 0.65 * clamp(dot(uv, sun2) + 0.55, 0.0, 1.0));

  // whitecaps grow with wind
  let cap = smoothstep(0.9 - w01 * 0.35, 1.15, h0) * (0.4 + 0.6 * vnoise(pw * 0.5 + vec2f(t * 0.6, 0.0)));
  c = mix(c, vec3f(0.62, 0.66, 0.68), cap * (0.25 + 0.55 * w01));

  // wind streaks — elongated noise aligned with the wind
  let perp = vec2f(-wdir.y, wdir.x);
  let streak = vnoise(vec2f(dot(pw, perp) * 0.55, dot(pw, wdir) * 0.045 - t * 0.5));
  c *= 0.94 + 0.12 * streak * (0.3 + 0.7 * w01);

  // drifting cloud shadows
  let cs = fbm(pw * 0.006 + wdir * t * 0.012, 3);
  c *= 0.82 + 0.28 * cs;

  return vec4f(c, 1.0);
}

fn visual_tr_whirl(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv);
  if (r > 0.97) { return vec4f(0.0); }
  let ang = atan2(uv.y, uv.x);
  let sang = ang + 4.2 * log(r + 0.13) + time * 0.9;
  let streak = pow(0.5 + 0.5 * sin(sang * 3.0), 2.0);
  // bowl darkening toward the drain
  var c = mix(vec3f(0.050, 0.115, 0.150), vec3f(0.008, 0.022, 0.032), smoothstep(0.75, 0.05, r));
  c *= 0.75 + 0.4 * streak;
  // sheared foam collar and inner filaments
  let foamN = vnoise(vec2f(sang * 2.0, r * 14.0 - time * 0.8));
  var foam = exp(-pow((r - 0.72) * 7.0, 2.0)) * (0.4 + 0.6 * foamN);
  foam += smoothstep(0.28, 0.05, r) * streak * 0.5 * foamN;
  c += vec3f(0.55, 0.60, 0.62) * foam;
  let a = smoothstep(0.95, 0.6, r) * 0.92;
  return vec4f(c, a);
}

fn visual_tr_rock(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [seed, 0, surgePhaseOffset, 0]
  let r = length(uv);
  if (r > 0.98) { return vec4f(0.0); }
  let ca = uv / max(r, 0.001);
  let seed = p.x;
  var rockR = 0.46 + 0.16 * (vnoise(ca * 2.1 + vec2f(seed * 9.0, seed * 4.0)) - 0.5) * 2.0;
  rockR += 0.07 * (vnoise(ca * 5.0 + vec2f(seed * 3.0, seed * 7.0)) - 0.5) * 2.0;

  var c = vec3f(0.0);
  var a = 0.0;
  let surge = sin(time * 1.25 + p.z * 6.28);

  if (r < rockR) {
    // craggy top-lit basalt; height falls toward the waterline
    let hgt = clamp((rockR - r) / rockR, 0.0, 1.0);
    let tex = fbm(uv * 9.0 + vec2f(seed * 20.0, 0.0), 4);
    c = mix(vec3f(0.055, 0.052, 0.050), vec3f(0.16, 0.145, 0.125), hgt * (0.5 + 0.5 * tex));
    // warm dusk grazing light from the west
    let sun2 = normalize(vec2f(-0.66, -0.30));
    let grad = vnoise(uv * 7.0 + vec2f(seed * 11.0, 3.0)) - vnoise(uv * 7.0 + sun2 * 0.25 + vec2f(seed * 11.0, 3.0));
    c += vec3f(0.55, 0.30, 0.16) * clamp(grad * 3.0, 0.0, 0.35) * hgt;
    // wet dark band at the waterline
    c *= mix(0.35, 1.0, smoothstep(0.02, 0.14, rockR - r));
    a = 1.0;
  } else {
    // breaking surf collar — swells on a slow pulse, textured foam
    let d = r - rockR;
    let foamN = vnoise(uv * 11.0 + vec2f(time * 0.7, seed * 8.0));
    var foam = exp(-d * d * 160.0) * (0.55 + 0.35 * surge) * (0.45 + 0.55 * foamN);
    foam += exp(-pow((d - 0.10 - 0.03 * surge) * 16.0, 2.0)) * 0.4 * foamN;
    c = vec3f(0.72, 0.75, 0.76) * foam * 1.25;
    a = clamp(foam * 1.15, 0.0, 1.0);
  }
  return vec4f(c, a);
}

fn visual_tr_squall(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [windX, windY, intensity, 0]
  let r = length(uv);
  if (r > 0.98) { return vec4f(0.0); }
  var wdir = vec2f(p.x, p.y);
  if (length(wdir) < 0.1) { wdir = vec2f(1.0, 0.0); }
  wdir = normalize(wdir);
  let perp = vec2f(-wdir.y, wdir.x);
  let edge = smoothstep(0.95, 0.45, r);
  // grey rain veil
  var c = vec3f(0.115, 0.130, 0.145);
  var a = 0.38 * edge * p.z;
  // rain streaks driven along the wind
  let streak = vnoise(vec2f(dot(uv, perp) * 26.0, dot(uv, wdir) * 2.2 - time * 2.2));
  c += vec3f(0.10, 0.11, 0.12) * pow(streak, 3.0) * 2.0;
  // agitated water sheen beneath
  let churn = vnoise(uv * 14.0 + vec2f(time * 1.3, 0.0));
  c += vec3f(0.16, 0.18, 0.19) * churn * 0.35;
  a = clamp(a + pow(streak, 3.0) * 0.25 * edge, 0.0, 0.75);
  return vec4f(c, a);
}

fn visual_tr_light(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [beamAngle, deliverGlow, 0, 0] — islet with tower, rotating beam, and a plank dock (south)
  let r = length(uv);
  var c = vec3f(0.0);
  var a = 0.0;

  // rotating beam wedge over the water (HDR, soft)
  let ang = atan2(uv.y, uv.x);
  var dAng = ang - p.x;
  dAng = atan2(sin(dAng), cos(dAng));
  let wedge = pow(max(cos(dAng), 0.0), 48.0);
  let reach = smoothstep(0.10, 0.30, r) * exp(-r * 1.6);
  c += vec3f(2.0, 1.5, 0.85) * wedge * reach * (1.1 + p.y * 1.4);
  a = max(a, clamp(wedge * reach * 2.0, 0.0, 0.55));

  // islet
  let rockR = 0.40 + 0.10 * (vnoise(uv / max(r, 0.001) * 2.4 + vec2f(4.0, 8.0)) - 0.5) * 2.0;
  if (r < rockR * 0.42) {
    let hgt = clamp((rockR * 0.42 - r) / (rockR * 0.42), 0.0, 1.0);
    let tex = fbm(uv * 8.0 + vec2f(13.0, 5.0), 4);
    c = mix(vec3f(0.06, 0.055, 0.05), vec3f(0.17, 0.15, 0.13), hgt * (0.5 + 0.5 * tex));
    c *= mix(0.4, 1.0, smoothstep(0.01, 0.08, rockR * 0.42 - r));
    a = 1.0;
  } else if (r < rockR * 0.42 + 0.10) {
    let d = r - rockR * 0.42;
    let foamN = vnoise(uv * 12.0 + vec2f(time * 0.7, 2.0));
    let foam = exp(-d * d * 220.0) * (0.6 + 0.3 * sin(time * 1.25)) * (0.5 + 0.5 * foamN);
    c = max(c, vec3f(0.72, 0.75, 0.76) * foam * 1.2);
    a = max(a, clamp(foam, 0.0, 1.0));
  }
  // dock: weathered planks running south
  let dq = uv - vec2f(0.02, 0.30);
  let dockD = sdBox(dq, vec2f(0.055, 0.22));
  if (dockD < 0.0) {
    let plank = 0.8 + 0.2 * sin(dq.y * 90.0);
    c = vec3f(0.30, 0.21, 0.13) * plank * (0.8 + 0.2 * vnoise(dq * 40.0));
    a = 1.0;
  }
  // tower: white drum, red lantern, warm halo
  if (r < 0.085) {
    let ring = smoothstep(0.085, 0.055, r);
    c = mix(vec3f(0.75, 0.72, 0.68), vec3f(0.9, 0.88, 0.84), ring);
    a = 1.0;
  }
  c += vec3f(3.0, 1.6, 0.6) * exp(-r * r * 300.0) * (1.0 + p.y * 2.0);
  return vec4f(c, a);
}

fn visual_tr_raft(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [seed, 0, 0, hidden] — a lantern lashed to a small raft
  if (p.w > 0.5) { return vec4f(0.0); }
  let r = length(uv);
  var c = vec3f(0.0);
  var a = 0.0;
  // expanding ripple rings (slow)
  let rip = sin(r * 22.0 - time * 2.2 + p.x * 9.0) * exp(-r * 2.6);
  c += vec3f(0.10, 0.12, 0.13) * max(rip, 0.0) * 0.8;
  a = max(a, max(rip, 0.0) * 0.35);
  // raft planks
  let rq = rotate(uv, p.x * 6.0);
  if (sdBox(rq, vec2f(0.16, 0.11)) < 0.0) {
    c = vec3f(0.24, 0.17, 0.11) * (0.8 + 0.2 * sin(rq.y * 70.0));
    a = 1.0;
  }
  // warm lantern — gentle breathing, HDR for bloom
  let breathe = 0.85 + 0.15 * sin(time * 1.6 + p.x * 12.0);
  c += vec3f(2.6, 1.5, 0.55) * exp(-r * r * 60.0) * breathe;
  c += vec3f(1.2, 0.6, 0.2) * exp(-r * r * 9.0) * 0.5 * breathe;
  a = max(a, clamp(exp(-r * r * 20.0) * 1.3, 0.0, 1.0));
  return vec4f(c, a);
}

fn visual_tr_boat(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [heading, speed01, boomAngle, heel(-1..1)] — +x forward in boat frame
  let q = rotate(uv, -p.x);
  let spd = clamp(p.y, 0.0, 1.0);
  let sun2n = normalize(vec2f(-0.66, -0.30));
  let shD = rotate(-sun2n, -p.x) * 0.045;      // shadow cast away from the sun, in boat frame
  var c = vec3f(0.0);
  var a = 0.0;

  // ---- Kelvin wake ----
  if (q.x < 0.02 && spd > 0.04) {
    let wx = 0.02 - q.x;
    let wy = q.y;
    let slope = abs(wy) / max(wx, 0.002);
    let armD = abs(slope - 0.354) * wx;
    let arm = exp(-armD * armD * 800.0) * exp(-wx * 2.3);
    var trans = 0.0;
    if (slope < 0.354) {
      trans = (0.5 + 0.5 * sin(wx * (34.0 + 26.0 * (1.0 - spd)))) * exp(-wx * 2.8) * smoothstep(0.354, 0.12, slope);
    }
    let turb = exp(-wy * wy * 260.0) * exp(-wx * 3.0) * (0.55 + 0.45 * vnoise(vec2f(wx * 26.0 - time * 4.0 * spd, wy * 36.0)));
    let foam = (arm + turb * 0.95) * spd;
    c += vec3f(0.70, 0.76, 0.78) * foam * 1.25;
    c += vec3f(0.16, 0.22, 0.26) * trans * spd * 0.8;
    a = max(a, clamp(foam * 1.25 + trans * spd * 0.35, 0.0, 1.0) * 0.9);
  }

  // hull profile: pointed bow (+x), squared transom
  let hL = 0.34;
  let hW = 0.10;
  // ---- shadow on the water (hull + sail silhouette, offset from the sun) ----
  let sq = q - shD;
  let sxn = sq.x / hL;
  if (abs(sxn) < 1.0) {
    let wp = hW * sqrt(max(0.0, 1.0 - sxn * sxn)) * (1.0 - 0.45 * smoothstep(0.1, 1.0, sxn));
    if (abs(sq.y) < wp && sq.x > -hL * 0.94) {
      c = mix(c, vec3f(0.005, 0.012, 0.016), 0.55);
      a = max(a, 0.5);
    }
  }

  // ---- hull ----
  let hq = vec2f(q.x, q.y + p.w * 0.010);     // heel shifts the deck line
  let xn = hq.x / hL;
  if (abs(xn) < 1.0 && hq.x > -hL * 0.94) {
    let wProf = hW * sqrt(max(0.0, 1.0 - xn * xn)) * (1.0 - 0.45 * smoothstep(0.1, 1.0, xn));
    let dy = abs(hq.y);
    if (dy < wProf) {
      // teak deck, planked; brighter on the sunward rail (heel-aware)
      let plank = 0.85 + 0.15 * sin(hq.y * 260.0);
      var deck = vec3f(0.36, 0.26, 0.17) * plank * (0.85 + 0.15 * vnoise(hq * 80.0));
      let railLight = clamp(-hq.y * sign(p.w) * 10.0, -0.2, 0.35);
      deck *= 0.9 + railLight;
      // white gunwale
      let rail = smoothstep(wProf - 0.011, wProf - 0.004, dy);
      deck = mix(deck, vec3f(0.82, 0.80, 0.76), rail);
      // cabin house aft of the mast
      let cd = sdRoundedBox(hq - vec2f(-0.075, 0.0), vec2f(0.055, 0.032), 0.015);
      if (cd < 0.0) { deck = mix(vec3f(0.46, 0.35, 0.24), vec3f(0.55, 0.44, 0.30), 0.5 + 0.5 * sin(hq.x * 200.0)); }
      c = deck * (0.9 + 0.35 * clamp(dot(rotate(vec2f(1.0, 0.0), p.x), -sun2n), 0.0, 1.0));
      a = 1.0;
    }
    // bow spray
    if (xn > 0.55 && spd > 0.35) {
      let bq = hq - vec2f(hL, 0.0);
      let spray = exp(-dot(bq, bq) * 320.0) * spd * (0.5 + 0.5 * vnoise(hq * 60.0 + vec2f(time * 3.0, 0.0)));
      c += vec3f(0.75, 0.8, 0.82) * spray;
      a = max(a, clamp(spray, 0.0, 0.8));
    }
  }

  // ---- rig: mast, boom, canvas ----
  let mast = vec2f(0.075, 0.0);
  let boomAng = p.z;
  let tip = mast + vec2f(cos(3.14159 + boomAng), sin(3.14159 + boomAng)) * 0.27;  // boom sweeps aft
  // sail: curved panel from mast to boom tip, cambered to leeward
  let mid = (mast + tip) * 0.5 + vec2f(-(tip - mast).y, (tip - mast).x) * 0.16;
  let d1 = sdSegment(q, mast, mid);
  let d2 = sdSegment(q, mid, tip);
  let sailD = min(d1, d2);
  if (sailD < 0.020) {
    // cream dacron lit by the low sun
    let lit = 0.65 + 0.4 * clamp(dot(normalize(tip - mast), sun2n), -0.4, 1.0);
    c = vec3f(0.88, 0.84, 0.74) * lit;
    a = 1.0;
  }
  // boom shadow line on deck
  let bD = sdSegment(q, mast, tip);
  if (bD < 0.006) { c = mix(c, vec3f(0.06, 0.05, 0.04), 0.7); a = max(a, 0.9); }
  // mast head
  c += vec3f(0.9, 0.85, 0.75) * exp(-dot(q - mast, q - mast) * 2600.0);
  a = max(a, clamp(exp(-dot(q - mast, q - mast) * 2000.0), 0.0, 1.0));

  a *= smoothstep(1.0, 0.92, length(uv));
  return vec4f(c, a);
}

fn visual_tr_hud(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [hull, cargo, windAngle, wind01] — quiet glass instruments, no chrome
  var c = vec3f(0.0);
  var a = 0.0;
  // wind rose: arrow rotated to where the wind blows
  let wq = rotate((uv - vec2f(-0.86, 0.0)) * vec2f(8.0, 3.6), -p.z);
  let tri = sdEquilateralTriangle(rotate(wq, 1.5708), 0.30);
  let ring = abs(length(wq) - 0.42);
  c += vec3f(0.75, 0.82, 0.88) * smoothstep(0.05, -0.02, tri) * (0.55 + 0.45 * p.w);
  c += vec3f(0.45, 0.55, 0.62) * smoothstep(0.03, 0.0, ring) * 0.5;
  a = max(a, smoothstep(0.05, -0.02, tri) * 0.85);
  a = max(a, smoothstep(0.03, 0.0, ring) * 0.4);
  // hull integrity: three small planks
  for (var i = 0; i < 3; i++) {
    let q = (uv - vec2f(-0.55 + f32(i) * 0.09, 0.0)) * vec2f(12.0, 5.0);
    let on = select(0.12, 1.0, f32(i) < p.x);
    let g = exp(-dot(q, q) * 2.0);
    c += vec3f(0.85, 0.55, 0.35) * g * on;
    a = max(a, g * 0.7);
  }
  // cargo lanterns aboard
  for (var i = 0; i < 4; i++) {
    let q = (uv - vec2f(0.30 + f32(i) * 0.09, 0.0)) * vec2f(12.0, 5.0);
    let on = select(0.10, 1.0, f32(i) < p.y);
    let g = exp(-dot(q, q) * 2.0);
    c += vec3f(1.6, 0.95, 0.35) * g * on;
    a = max(a, g * 0.75 * max(on, 0.25));
  }
  return vec4f(c, clamp(a, 0.0, 1.0) * 0.8);
}

