try {
  const wd = sim.worldData
  if (!wd.__lh3) wd.__lh3 = { t: 38, icx: -9, icz: 32, hold: 0, ba: 0, fire: 0, mh: 0, bt: 0, fireLock: 0 }
  const H = wd.__lh3
  const CYC = 150
  const mx = wd.mouse_x, my = wd.mouse_y, md = wd.mouse_down
  const hasM = typeof mx === 'number'

  // ── camera math (matches the shader: ro=(0,3.4,0), f=1.75, y=(py*0.72-0.14)) ──
  const proj = (x, y, z, isDir) => {
    const vy = isDir ? y : y - 3.4
    if (z < 0.12) return null
    const px = x / z * 1.75, py = (vy / z * 1.75 + 0.14) / 0.72
    return { px, py, gx: (px + 1) * 256, gy: (1 - py) * 256 }
  }
  const ray = (gx, gy) => {
    const px = (gx / 256) - 1, py = 1 - (gy / 256)
    return [px, py * 0.72 - 0.14, 1.75]
  }

  // ── hover + drag: the lighthouse is a thing you can pick up ──
  const bS = proj(H.icx, 0.8, H.icz)
  const tS = proj(H.icx, 13.8, H.icz)
  const fTower = sim.fields.get('lh_tower')
  let hover = false
  if (hasM && fTower) {
    const TT = fTower.transform
    hover = TT.x > 0 && Math.abs(mx - TT.x) < (fTower.w || 64) / 2 && Math.abs(my - TT.y) < (fTower.h || 120) / 2
  }
  if (md && (hover || H.hold)) H.hold = 1
  if (!md) H.hold = 0
  if (H.hold && hasM) {
    // drag on the sea plane — and while held, TIME DOES NOT MOVE
    const d = ray(mx, my)
    if (d[1] < -0.02) {
      const tp = (0.5 - 3.4) / d[1]
      H.icx = Math.max(-38, Math.min(38, d[0] * tp))
      H.icz = Math.max(16, Math.min(70, d[2] * tp))
    }
  }
  // ── the SLIDER is the clock: click & drag the bottom bar to move the sun ──
  if (!md) H.sliderDrag = 0
  else if (hasM && (H.sliderDrag || (!H.mh && my > 470))) {
    H.sliderDrag = 1
    const target = (Math.max(8, Math.min(504, mx)) - 8) / 496 * CYC
    H.t += (target - H.t) * Math.min(1, dt * 12)
  }

  const ph = ((H.t % CYC) + CYC) % CYC / CYC
  const az = 1.35 + ph * 6.28318
  const el = Math.sin(ph * 6.28318) * 0.72
  const wind = Math.max(0, Math.min(1, 0.35 + 0.30 * Math.sin(ph * 6.28318 - 1.2)))
  const beam = Math.max(0, Math.min(1, (0.06 - el) * 9))
  const mel = -el * 0.85
  const maz = az + Math.PI
  H.bt += dt
  const leg = Math.floor(H.bt / 55)
  const dirB = (leg % 2 === 0) ? 1 : -1
  const u2 = ((H.bt % 55) + 55) % 55 / 55
  const bx = dirB > 0 ? (-70 + u2 * 140) : (70 - u2 * 140)

  // ── the beam sweeps; geometry alone decides the fire ──
  H.ba += dt * 0.55
  const sd = [Math.cos(az) * Math.cos(el), Math.sin(el), Math.sin(az) * Math.cos(el)]
  const sunS = sd[2] > 0.05 ? proj(sd[0], sd[1], sd[2], true) : null
  const lampS = proj(H.icx, 12.55, H.icz)
  let crossD = 1e9, crX = -80, crY = -120
  if (sunS && lampS) {
    for (const sgn of [1, -1]) {
      const T = proj(H.icx + Math.cos(H.ba) * 45 * sgn, 12.55, H.icz + Math.sin(H.ba) * 45 * sgn)
      if (!T) continue
      const vx = T.gx - lampS.gx, vy = T.gy - lampS.gy
      const tt = Math.max(0, Math.min(1, ((sunS.gx - lampS.gx) * vx + (sunS.gy - lampS.gy) * vy) / Math.max(vx * vx + vy * vy, 1e-6)))
      const cx2 = lampS.gx + vx * tt, cy2 = lampS.gy + vy * tt
      const dd3 = Math.hypot(sunS.gx - cx2, sunS.gy - cy2)
      if (dd3 < crossD) { crossD = dd3; crX = cx2; crY = cy2 }
    }
  }
  const sunVisible = !!sunS && el > -0.15 && sunS.gx > 10 && sunS.gx < 502 && sunS.gy > 0 && sunS.gy < 350
  // ── citizens: The Sun, The Beam, The Tower are FIELDS — their bodies are
  //    the hit truth (rule 'ir_lightgrow' watches the same bodies) ──
  const fSun = sim.fields.get('lh_sun'), fBeam = sim.fields.get('lh_beam')
  if (fSun) { const T2 = fSun.transform; if (sunVisible && sunS) { T2.x = sunS.gx; T2.y = sunS.gy } else { T2.x = -80; T2.y = -80 } T2.vx = 0; T2.vy = 0 }
  if (fBeam) { const T3 = fBeam.transform; if (beam > 0.2 && crossD < 1e8) { T3.x = crX; T3.y = crY } else { T3.x = -80; T3.y = -120 } T3.vx = 0; T3.vy = 0 }
  if (fTower && bS && tS) {
    const T4 = fTower.transform
    T4.x = (bS.gx + tS.gx) / 2; T4.y = (bS.gy + tS.gy) / 2; T4.vx = 0; T4.vy = 0
    fTower.w = 64; fTower.h = Math.abs(bS.gy - tS.gy) + 32
  }
  // water → fire TRIGGERS when the fields overlap: the light grows into the burn
  // ── overlap in WORLD space: the beam's angle meets the sun's azimuth —
  //    projection-proof. The fields then physically meet for the flare. ──
  const wrapA = x => { let v = x % 6.28318; if (v > 3.14159) v -= 6.28318; if (v < -3.14159) v += 6.28318; return v }
  const dA = Math.min(Math.abs(wrapA(az - H.ba)), Math.abs(wrapA(az - H.ba - 3.14159)))
  const overlapped = beam > 0.2 && el > -0.12 && el < 0.30 && dA < 0.12
  H.dbgA = Math.round(dA * 57.3)
  // during the meeting, The Beam stands where The Sun stands — the engine's
  // interaction rule and the flare fire on real field overlap
  if (overlapped && fBeam && sunS) { fBeam.transform.x = sunS.gx; fBeam.transform.y = sunS.gy }
  // TEST SWITCH: a fresh click (not on the tower) toggles water <-> fire
  // directly, so the burn can be verified independent of hit detection
  if (md && !H.mh && !hover && !H.hold && my <= 470) H.fireLock = H.fireLock ? 0 : 1
  H.fire = (overlapped || H.fireLock) ? Math.min(1, H.fire + dt * 1.5) : Math.max(0, H.fire - dt * 0.6)

  // (the blaze-door to TIDERUNNER was removed with that world)
  H.mh = md ? 1 : 0

  // outline rect in the shader's p-space
  let ocx = 0, ocy = 0, ohh = 0
  if (bS && tS) { ocx = (bS.px + tS.px) / 2; ocy = (bS.py + tS.py) / 2; ohh = Math.abs(tS.py - bS.py) / 2 + 0.045 }

  wd.gpuUniforms = [az, el, ph, wind, beam, mel, maz, bx, dirB, H.ba % 6.28318, H.fire, H.icx, H.icz, (hover || H.hold) ? 1 : 0, ocx, ocy, ohh]
  wd.hud = [{ id: 'lh_t', type: 'text', x: '14px', y: '12px', color: '#c9b370', fontSize: '13px',
    text: 'LIGHTHOUSE v9 — ' + (H.fire > 0.5 ? 'THE WATER BURNS' : H.hold ? 'carrying the lighthouse' : (beam > 0.5 ? 'the lamp is lit' : (el > 0.3 ? 'high day' : 'low light'))) + (beam > 0.2 ? ' · beam∠sun ' + H.dbgA + '°' + (overlapped ? ' · OVERLAP' : '') : '') + (H.fireLock ? ' · TEST FIRE' : '') }]
} catch (e) { /* keep the sim alive */ }

